	 ('ab731c9e-f4b1-4818-8924-af4c3adeea9f'::uuid,'4-FOOT TUNNEL AT QUEEN MARY COLLEGE LONDON','DEVICE','{}','A photograph from 1909 depicts a four foot wide tunnel at Queen Mary College based on NPL tunnel specifications. It is mentioned that the 0.61 m tunnel at QMC might have been the first of its kind, followed by the construction of the 1.2m square tunnel in 1919.','{}','{}','{"frequency": 2, "text_unit_ids": ["75e55aae79fa4fef8afa00e4bf79f6f1f694d27b10f227c1f393bd8cf61700080ce3c057271ae7311d2d3cd09b4445ff1281543e67c2ce7840a138c9f1467077", "75e55aae79fa4fef8afa00e4bf79f6f1f694d27b10f227c1f393bd8cf61700080ce3c057271ae7311d2d3cd09b4445ff1281543e67c2ce7840a138c9f1467077"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');

