	 ('8c40106f-676c-4d26-b2bc-c77a03895a51'::uuid,'LANGLEY','ORGANIZATION','{}','Langley''s advancements in aeronautical engineering and research are important in the context of evolving into more efficient forms of aircraft and powered controlled human flight','{}','{}','{"frequency": 2, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
