	 ('299842e7-a482-47ae-8be9-b246cc427f35'::uuid,'LANDING FLIGHT SYSTEM','SYSTEM','{}','The landing process for aircraft includes a series of systems required to ensure safe operation and evacuation, such as those involved with "Hindenburg".','{}','{}','{"frequency": 2, "text_unit_ids": ["3ea69086c604fb251a4059f678ec83b99d67d511efb1c29354f7c0b54808defd6170d2ee03e45660f508dc039db22634dfa65c013414a6a31a8795a58d791441", "3ea69086c604fb251a4059f678ec83b99d67d511efb1c29354f7c0b54808defd6170d2ee03e45660f508dc039db22634dfa65c013414a6a31a8795a58d791441"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
