	 ('50a39101-562b-4380-bad5-bcaa78aa0067'::uuid,'PRESSURE_DISTRIBUTION','FORMATION','{}','The actual pressure spread over body surfaces is crucial for understanding and controlling motion properties','{}','{}','{"frequency": 1, "text_unit_ids": ["a9ae9046c84bd485f66f44763948025a4066f10073bee095a4c15c4665d9db3e9ee4c83182db236d7659a96a72f09b4262666709a85154db90a6633d796a8eab"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
