INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('668893b2-6a90-401c-959d-c497d322cc94'::uuid,'FREE FLIGHT','METHOD','{}','An initial approach used to study aerodynamics by observing how objects naturally move through air','{}','{}','{"frequency": 2, "text_unit_ids": ["29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6", "29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('af9ffb3f-97b8-4381-8840-145ec9c1970a'::uuid,'DROP TESTS','METHOD','{}','A method involving dropping objects into the air to observe their behavior and measure characteristics such as drag and lift','{}','{}','{"frequency": 2, "text_unit_ids": ["29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6", "29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('1622eb13-622b-439e-ad08-9f1256a6d762'::uuid,'WRIGHT BROTHERS','PERSON','{}','Wright Brothers, consisting of Orville and Wilbur Wright, were American pioneers instrumental in the development and successful flight of the world’s first self-propelled, fully controllable airplane. They devoted significant effort to early aircraft design and succeeded in achieving sustained and controlled flight, marking a pivotal moment in aviation history. Their achievements surpassed those of other contemporary researchers such as Langley, who had also been conducting related experiments. The Wright brothers’ innovation and determination solidified their place as key figures in the origins of powered air travel.','{}','{}','{"frequency": 3, "text_unit_ids": ["29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6", "29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6", "baaa62fd839985ce0a3d03b2d98ddcadb6f3444480414cdd20d36ee69e47687c9474cf34e27996edfbc0ef5e505f086b7089d7dffa034ef135e1881d1386aee9"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('7994247d-35f6-4576-b719-084f1c4514b4'::uuid,'BICYCLE','DEVICE','{}','A comparison to bicycles helped the Wright Brothers understand their need for active control inputs during flight','{}','{}','{"frequency": 2, "text_unit_ids": ["29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6", "29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('994d2fcc-96c1-41b2-a999-6057a49a0408'::uuid,'AIRCRAFT','SYSTEM','{}','The complex mechanism and components that work together to enable flight, including wings, motors, and control surfaces','{}','{}','{"frequency": 2, "text_unit_ids": ["29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6", "29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('1b23fc1b-8480-4084-908b-28e3c782a5fc'::uuid,'WING','COMPONENT','{}','WING is an essential component in aviation design, primarily used to generate lift and balance the weight of the aircraft. In early aviation development, wings played a fundamental role as one of the core elements enabling flight. Typically, wing models for testing purposes are constructed at specific dimensions, such as 1 meter by 200 millimeters, ensuring precise aerodynamic analysis in wind tunnels. These tests often adhere to a standard aspect ratio of 5, which helps in optimizing lift and reducing drag, contributing significantly to the overall performance and efficiency of aircraft designs.','{}','{}','{"frequency": 3, "text_unit_ids": ["29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6", "29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6", "1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a9d65168-5636-4c7d-a8a7-04ad990374ba'::uuid,'MOTOR','COMPONENT','{}','An essential part for overcoming air resistance and providing propulsion necessary for powered flight','{}','{}','{"frequency": 2, "text_unit_ids": ["29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6", "29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b0956b40-cb38-4b12-a3cc-fb8aa26bfd2c'::uuid,'CONTROL SURFACES','COMPONENT','{}','Devices used to alter the flight path, crucial for controlling the aircraft''s stability during flight; Wright Brothers pioneered effective control techniques','{}','{}','{"frequency": 2, "text_unit_ids": ["29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6", "29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5e827a4f-a7a7-4b08-ad96-6cc3ae3be7e9'::uuid,'STABILITY_SYSTEMS','SYSTEM','{"обеспечивает баланс в полёте"}','Mechanisms aimed at maintaining stability in an aircraft, contributing to pilot comfort and predictability during controlled flight operations','{}','{}','{"frequency": 1, "text_unit_ids": ["3afa04cc7530a641a3fd45906a688d4d426fc2e94b2b585d2d5b048682c638b5d8cd601b89ec4e804b881be405f7431c8a546e371ae8a5e5f7c753897b8c882b"]}','2026-07-17 10:37:07.080969','2026-07-17 10:37:07.080969','history_development_aeronautics'),
	 ('5309b098-2ec4-482e-8abb-0fdbfd133545'::uuid,'LIFT','PROPERTY','{}','The force that keeps an airplane in the air by counteracting gravity and allowing it to ascend or maintain altitude','{}','{}','{"frequency": 2, "text_unit_ids": ["29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6", "29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('0138ba43-d69f-4f7f-ae7b-a011fc608287'::uuid,'DRAG','PROPERTY','{}','Air resistance resisting movement, a critical aspect of aerodynamic design and performance optimization','{}','{}','{"frequency": 2, "text_unit_ids": ["29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6", "29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f92aacdd-f325-43cf-9177-67809d48f911'::uuid,'AERIAL CARRIER','SYSTEM','{}','A term that covers the components required for flight; it includes lift generation mechanisms and drag mitigation strategies','{}','{}','{"frequency": 2, "text_unit_ids": ["29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6", "29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a5f55e9c-4e66-43eb-904a-cf558d91be49'::uuid,'STABILITY','PROPERTY','{}','The characteristic of an aircraft maintaining a steady orientation during flight, influenced by control surfaces and overall design','{}','{}','{"frequency": 1, "text_unit_ids": ["29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('68791d09-eede-47e0-bef0-1ce68aff7bcd'::uuid,'PITCH','PROPERTY','{}','An aspect of control that relates to the rotation around a wing''s longitudinal axis, affecting lift and control stability','{}','{}','{"frequency": 1, "text_unit_ids": ["29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('8e392988-6fd5-4c0b-9c0b-7fad23fbfe67'::uuid,'ROLL','PROPERTY','{}','The rotation around an aircraft''s lateral axis, crucial for maintaining balance and stability in flight','{}','{}','{"frequency": 1, "text_unit_ids": ["29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('fd8504e3-0e83-488b-af2e-86505a0030be'::uuid,'YAW','PROPERTY','{}','The rotation around an aircraft''s vertical axis, essential for heading control during flight','{}','{}','{"frequency": 1, "text_unit_ids": ["29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('45dc21c2-b3bb-49cb-a73c-ea0ab9e66785'::uuid,'PARACHUTE','DEVICE','{}','The parachute is adevice primarily designed to slow the descent of an object through the air by generating aerodynamic drag force. This device has been utilized for various purposes, including ensuring safe landings from heights when jumping or falling.
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('85627fd9-a7ab-4ed4-8dd2-0ec1c1f77676'::uuid,'LEVER SYSTEM','MECHANISM','{}','A machine that uses one or several levers for mechanical advantage or to change direction of applied effort, potentially tested on bat-like wings','{}','{}','{"frequency": 2, "text_unit_ids": ["e9e299fdd315262c60dc335f6516a7d09106b9d9354cb34f01b7599af64f2d9273530938403a9f1b91129f2a67f0cccb25885ad1cf8e1ad0f9c71aea12340520", "e9e299fdd315262c60dc335f6516a7d09106b9d9354cb34f01b7599af64f2d9273530938403a9f1b91129f2a67f0cccb25885ad1cf8e1ad0f9c71aea12340520"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ac090309-675b-4a19-b7dc-2e73b5afa9eb'::uuid,'BRIDGE PIER VORTEX','MATERIAL','{}','The swirling flow in the air around a pier of a bridge, observed by Leonardo and possibly misinterpreted due to secrecy','{}','{}','{"frequency": 2, "text_unit_ids": ["e9e299fdd315262c60dc335f6516a7d09106b9d9354cb34f01b7599af64f2d9273530938403a9f1b91129f2a67f0cccb25885ad1cf8e1ad0f9c71aea12340520", "e9e299fdd315262c60dc335f6516a7d09106b9d9354cb34f01b7599af64f2d9273530938403a9f1b91129f2a67f0cccb25885ad1cf8e1ad0f9c71aea12340520"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('973072e1-62ea-4635-990c-bba307714a47'::uuid,'WRIGHT BROTHERS GLIDERS','DEVICE','{}','Early flying machines designed and tested by the Wright brothers before their eventual powered flight, likely involving wing warping for control','{}','{}','{"frequency": 2, "text_unit_ids": ["e9e299fdd315262c60dc335f6516a7d09106b9d9354cb34f01b7599af64f2d9273530938403a9f1b91129f2a67f0cccb25885ad1cf8e1ad0f9c71aea12340520", "e9e299fdd315262c60dc335f6516a7d09106b9d9354cb34f01b7599af64f2d9273530938403a9f1b91129f2a67f0cccb25885ad1cf8e1ad0f9c71aea12340520"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3fe7fb27-3970-4b69-96dc-7b4a707233c0'::uuid,'GEARBOX WING WARPING CONTROL','MECHANISM','{}','Mechanical linkage connecting the steering controls to the wing surfaces in Wright brothers'' aircraft, which allowed adjustments in flight for stable maneuvering and control','{}','{}','{"frequency": 2, "text_unit_ids": ["e9e299fdd315262c60dc335f6516a7d09106b9d9354cb34f01b7599af64f2d9273530938403a9f1b91129f2a67f0cccb25885ad1cf8e1ad0f9c71aea12340520", "e9e299fdd315262c60dc335f6516a7d09106b9d9354cb34f01b7599af64f2d9273530938403a9f1b91129f2a67f0cccb25885ad1cf8e1ad0f9c71aea12340520"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b4fafee7-4f73-4003-8693-4f651a4bcd0b'::uuid,'FLIGHT MEASUREMENT SCALES','MODEL','{}','Methods or apparatus used by pioneers like Leonardo and perhaps later investigators to quantify and measure aerodynamic properties of objects flying through the air','{}','{}','{"frequency": 1, "text_unit_ids": ["e9e299fdd315262c60dc335f6516a7d09106b9d9354cb34f01b7599af64f2d9273530938403a9f1b91129f2a67f0cccb25885ad1cf8e1ad0f9c71aea12340520"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c3a8df2c-a3ac-440c-a972-1e29603077f1'::uuid,'SELF-EVALUATION AND SCEPTICISM OF WRIGHT BROTHERS','MODEL','{}','The approach of carefully evaluating data and experiments by the Wright brothers, contributing to their innovations and success in powered flight)<|COMPLETE|>','{}','{}','{"frequency": 1, "text_unit_ids": ["e9e299fdd315262c60dc335f6516a7d09106b9d9354cb34f01b7599af64f2d9273530938403a9f1b91129f2a67f0cccb25885ad1cf8e1ad0f9c71aea12340520"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('8b5e612c-fc66-4a29-9a0e-ebe2d88a7680'::uuid,'CIRCULATION THEORY OF LIFT','MODEL','{}','Theoretical explanation by Montgomery regarding the mechanism behind lift, but not widely recognized for its importance initially','{}','{}','{"frequency": 1, "text_unit_ids": ["fbfbe3eab64670ade81f0f5bb091f801c41f6144a0b8e541a66dad3c1f397496968ec6594738a46e5d6eca8ef00ae4a984c6e2a885277c5555498e6becc7e9c6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('afc5aaeb-46f7-4505-843a-6388feaf8859'::uuid,'DA VINCI''S WRITINGS ON FLOW AROUND BODIES','MATERIAL','{}','Written works of Da Vinci that describe fluid dynamics and were not known during his lifetime or shortly after, only discovered much later','{}','{}','{"frequency": 1, "text_unit_ids": ["fbfbe3eab64670ade81f0f5bb091f801c41f6144a0b8e541a66dad3c1f397496968ec6594738a46e5d6eca8ef00ae4a984c6e2a885277c5555498e6becc7e9c6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('adade9ee-6d39-4a40-8f9f-b2ab245a7608'::uuid,'6 DEGREES OF FREEDOM','MECHANISM','{}','Concept in aerodynamics describing the six possible types of motion and rotations an object can undergo when flying; key for understanding aircraft stability','{}','{}','{"frequency": 1, "text_unit_ids": ["fbfbe3eab64670ade81f0f5bb091f801c41f6144a0b8e541a66dad3c1f397496968ec6594738a46e5d6eca8ef00ae4a984c6e2a885277c5555498e6becc7e9c6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('69957acf-b7c8-4730-a943-10ada76ddd81'::uuid,'BRYAN AND WILLIAMS'' ANALYSIS (1903/4)','MODEL','{}','Research conducted by Bryan and Williams that significantly advanced the understanding of 6 degrees of freedom in aerodynamics, published between 1903 and 1904','{}','{}','{"frequency": 1, "text_unit_ids": ["fbfbe3eab64670ade81f0f5bb091f801c41f6144a0b8e541a66dad3c1f397496968ec6594738a46e5d6eca8ef00ae4a984c6e2a885277c5555498e6becc7e9c6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
