	 ('9e077664-0860-4ace-851f-be3eec64a45e'::uuid,'BAIRSTOW''S THEORY (1913)','MODEL','{}','Work expressed by Bairstow which clarified the analysis of dynamic stability, published in 1913','{}','{}','{"frequency": 1, "text_unit_ids": ["fbfbe3eab64670ade81f0f5bb091f801c41f6144a0b8e541a66dad3c1f397496968ec6594738a46e5d6eca8ef00ae4a984c6e2a885277c5555498e6becc7e9c6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6b817ce2-06d2-4bb8-acea-5f666880c9f7'::uuid,'CAYLEY CONFIGURATION','DEVICE','{}','A balanced equilibrium aeroplane layout designed by Cayley in early 19th century, a precursor to modern aircraft design','{}','{}','{"frequency": 1, "text_unit_ids": ["fbfbe3eab64670ade81f0f5bb091f801c41f6144a0b8e541a66dad3c1f397496968ec6594738a46e5d6eca8ef00ae4a984c6e2a885277c5555498e6becc7e9c6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b6adbf3b-0f2f-4c99-a64a-0a4a0f4d4918'::uuid,'STATIC STABILITY ANALYSIS','SYSTEM','{}','Method used to determine if an aircraft can return to its initial condition after a disturbance, important for flight safety and control','{}','{}','{"frequency": 1, "text_unit_ids": ["fbfbe3eab64670ade81f0f5bb091f801c41f6144a0b8e541a66dad3c1f397496968ec6594738a46e5d6eca8ef00ae4a984c6e2a885277c5555498e6becc7e9c6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a38a7f6a-5836-4593-bad8-b4a978e79de7'::uuid,'DYNAMIC STABILITY ANALYSIS','SYSTEM','{}','Analysis that looks at the natural tendency of disturbances in an aircraft’s motion to decrease over time due to inertial and aerodynamic damping forces','{}','{}','{"frequency": 1, "text_unit_ids": ["fbfbe3eab64670ade81f0f5bb091f801c41f6144a0b8e541a66dad3c1f397496968ec6594738a46e5d6eca8ef00ae4a984c6e2a885277c5555498e6becc7e9c6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c8825871-d7c6-4735-8d58-32324e2b8170'::uuid,'WRIGHT BROTHERS'' GLIDER (1902)','DEVICE','{}','Pioneering control technique implemented in a glider by Wright brothers for precise rotational direction control using wing warping','{}','{}','{"frequency": 1, "text_unit_ids": ["fbfbe3eab64670ade81f0f5bb091f801c41f6144a0b8e541a66dad3c1f397496968ec6594738a46e5d6eca8ef00ae4a984c6e2a885277c5555498e6becc7e9c6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d6c1af7f-a346-4fe3-9bb5-4f527f118f22'::uuid,'LILIENTHAL, PILCHER, CHANUTE''S GLIDERS','COMPONENT','{}','Early hang gliders or similar devices designed by these pioneers that used shifting weight to provide limited control','{}','{}','{"frequency": 1, "text_unit_ids": ["fbfbe3eab64670ade81f0f5bb091f801c41f6144a0b8e541a66dad3c1f397496968ec6594738a46e5d6eca8ef00ae4a984c6e2a885277c5555498e6becc7e9c6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b75405f2-0356-4863-8538-29d189c8f466'::uuid,'LILIENTHAL, PILCHER''S HANG GLIDERS','DEVICE','{}','(H)ang (G)liders designed by Lil(i)enth(al) and (P)i(l)cher that used shifting weight for limited control; precursors to more sophisticated designs like the Wright brothers'' implementation of wing warping for improved control','{}','{}','{"frequency": 1, "text_unit_ids": ["fbfbe3eab64670ade81f0f5bb091f801c41f6144a0b8e541a66dad3c1f397496968ec6594738a46e5d6eca8ef00ae4a984c6e2a885277c5555498e6becc7e9c6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('90caaf08-b1a3-478d-ae64-590f1beea33e'::uuid,'CHANDUTE''S GLIDERS','DEVICE','{}','(G)lider designs by Chan(u)te, another pioneer who contributed basic principles before advancements in precise control mechanisms as seen in later devices like those from (W)righ(t) brothers','{}','{}','{"frequency": 1, "text_unit_ids": ["fbfbe3eab64670ade81f0f5bb091f801c41f6144a0b8e541a66dad3c1f397496968ec6594738a46e5d6eca8ef00ae4a984c6e2a885277c5555498e6becc7e9c6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5d9f3437-2027-48c3-b121-065ed42eb8e3'::uuid,'RELAXED STATIC STABILITY (RSS)','MODEL','{}','(R)elax(ed) (S)tatic (S)tability is an advanced design introduced later in the 1970s that built upon foundational concepts explored by earlier pioneers, including the work of Cayley on balanced configurations.','{}','{}','{"frequency": 1, "text_unit_ids": ["fbfbe3eab64670ade81f0f5bb091f801c41f6144a0b8e541a66dad3c1f397496968ec6594738a46e5d6eca8ef00ae4a984c6e2a885277c5555498e6becc7e9c6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9c3eb2e0-1b2a-40cd-ab9a-a4eea4b34e7d'::uuid,'BRYAN AND WILLIAMS'' ANALYSIS','SYSTEM','{}','(B)ryan and (W)illiam’s research is a critical examination system used to understand 6 degrees of freedom, an important milestone in advancing aerodynamic and stability analyses beyond what was understood by earlier pioneers.','{}','{}','{"frequency": 1, "text_unit_ids": ["fbfbe3eab64670ade81f0f5bb091f801c41f6144a0b8e541a66dad3c1f397496968ec6594738a46e5d6eca8ef00ae4a984c6e2a885277c5555498e6becc7e9c6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('b70f71c7-59e1-4509-8cf5-1178d72559d5'::uuid,'CONTINUUM_HYPOTHESIS','MODEL','{}','The hypothesis that real media can be substituted by continuous models, proven effective in aerodynamics and other physicsfields','{}','{}','{"frequency": 1, "text_unit_ids": ["a9ae9046c84bd485f66f44763948025a4066f10073bee095a4c15c4665d9db3e9ee4c83182db236d7659a96a72f09b4262666709a85154db90a6633d796a8eab"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('1f04c2a9-141c-43e6-b84c-de73d180461f'::uuid,'RIGID_BODY','DEVICE','{}','Most streamlined objects considered as non-deformable to simplify force analysis; exceptions include noticeable phenomena like flag fluttering','{}','{}','{"frequency": 1, "text_unit_ids": ["a9ae9046c84bd485f66f44763948025a4066f10073bee095a4c15c4665d9db3e9ee4c83182db236d7659a96a72f09b4262666709a85154db90a6633d796a8eab"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('2ed33438-5d75-4e10-b62d-eb7a601e81fd'::uuid,'FORCES_AND_MOMENTS','SYSTEM','{}','Formed by forces such as thrust, drag, lift, and moments about the center of mass','{}','{}','{"frequency": 1, "text_unit_ids": ["a9ae9046c84bd485f66f44763948025a4066f10073bee095a4c15c4665d9db3e9ee4c83182db236d7659a96a72f09b4262666709a85154db90a6633d796a8eab"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('95560b27-6c40-45ce-90e6-f0607d664259'::uuid,'FLOW_PATTERN','MECHANISM','{}','The spatial distribution and temporal changes in velocities, pressure, density, and temperature that shape body flow','{}','{}','{"frequency": 1, "text_unit_ids": ["a9ae9046c84bd485f66f44763948025a4066f10073bee095a4c15c4665d9db3e9ee4c83182db236d7659a96a72f09b4262666709a85154db90a6633d796a8eab"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('47b29ddd-af0d-4062-8d92-825dba53d413'::uuid,'EXPERIMENTAL_TECHNIQUE','MODEL','{}','Used by Wright brothers to compensate for lack of deep understanding of aerodynamics','{}','{}','{"frequency": 1, "text_unit_ids": ["a9ae9046c84bd485f66f44763948025a4066f10073bee095a4c15c4665d9db3e9ee4c83182db236d7659a96a72f09b4262666709a85154db90a6633d796a8eab"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('b959c003-5f9a-460b-9e0e-5f938290e69a'::uuid,'WIND_TUNNEL EXPERIMENTATION','MECHANISM','{}','Experimental methods used to study aerodynamics through wind tunnel tests, first developed but not fully accepted until the 1920s. This was crucial for validating theories about air resistance and drag in motion.','{}','{}','{"frequency": 1, "text_unit_ids": ["71513cc51ffa1e8b185f20e95d505c81a39cad56f6db7e0192988badc6a212324cd2dca2a6e0b895668f6133ccf33ae88b3164f544f6ed7f319db021e5f84305"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3773947e-5a7e-45fd-af90-196fdcc0090f'::uuid,'FINITE_WING<TERM>','DEVICE','{}','A wing with finite length, as opposed to an infinite flat plate, which required more sophisticated mathematical analysis by mathematicians like Lanchester and Prandtl in the early 20th century.','{}','{}','{"frequency": 1, "text_unit_ids": ["71513cc51ffa1e8b185f20e95d505c81a39cad56f6db7e0192988badc6a212324cd2dca2a6e0b895668f6133ccf33ae88b3164f544f6ed7f319db021e5f84305"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('627d1f63-55cc-430c-999d-243facaccc12'::uuid,'LANCHETER','PERSON','{}','Frank P. W. Tompkins Lanchester was a key figure who empirically resolved some of the problems related to finite wings, contributing significantly to aerodynamic theory.','{}','{}','{"frequency": 1, "text_unit_ids": ["71513cc51ffa1e8b185f20e95d505c81a39cad56f6db7e0192988badc6a212324cd2dca2a6e0b895668f6133ccf33ae88b3164f544f6ed7f319db021e5f84305"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6b5460e7-f5be-40b7-89c8-d3af570d185e'::uuid,'PRANDTL<TERM>','MODEL','{}','The work of Ludwig Prandtl in the early 20th century mathematically analyzed the behavior and performance of finite wings, leading to a deeper understanding of drag and lift ratios. His theories were foundational in modern aerodynamics.','{}','{}','{"frequency": 1, "text_unit_ids": ["71513cc51ffa1e8b185f20e95d505c81a39cad56f6db7e0192988badc6a212324cd2dca2a6e0b895668f6133ccf33ae88b3164f544f6ed7f319db021e5f84305"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('114eee9e-89de-4aed-b211-77dbe303edb5'::uuid,'FINITE_WING_THEORY<TERM>','SYSTEM','{}','The comprehensive theory explaining the aerodynamic properties of finite wings, which was not fully accepted until the 1920s despite earlier observations by Wenham et al. It involves calculations and models to predict lift-to-drag ratios accurately.','{}','{}','{"frequency": 1, "text_unit_ids": ["71513cc51ffa1e8b185f20e95d505c81a39cad56f6db7e0192988badc6a212324cd2dca2a6e0b895668f6133ccf33ae88b3164f544f6ed7f319db021e5f84305"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('cb1c8e3e-6e0d-4d44-a90d-4d1e9d341b6d'::uuid,'DRAIN<TERM>','MECHANISM','{}','The measure of air resistance in motion, now called drag, which was also historically referred to as drift before the establishment of more precise definitions and equations. Early research focused on understanding this fundamental force in atmospheric flow over surfaces like aircraft wings.','{}','{}','{"frequency": 1, "text_unit_ids": ["71513cc51ffa1e8b185f20e95d505c81a39cad56f6db7e0192988badc6a212324cd2dca2a6e0b895668f6133ccf33ae88b3164f544f6ed7f319db021e5f84305"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('51ba3600-1ce5-4001-bae4-77b65fd2fa7e'::uuid,'SIMON_STEVINS<TERM>','PERSON','{}','(Historical figure) Simon Stevin, an early contributor to scientific methods and mechanics, although not directly mentioned as a researcher in fluid dynamics or aerodynamics. His work on the acceleration of bodies laid foundational principles for the science.','{}','{}','{"frequency": 1, "text_unit_ids": ["71513cc51ffa1e8b185f20e95d505c81a39cad56f6db7e0192988badc6a212324cd2dca2a6e0b895668f6133ccf33ae88b3164f544f6ed7f319db021e5f84305"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6b4f583b-2b79-4bc6-beb3-dabf9231d7cd'::uuid,'WENHAM<TERM>','PERSON','{}','(Historical figure) John Henry Dumbleton Wenham, an experimenter who contributed to understanding lift and drag ratios through his bird flight observations and wind tunnel measurements. His work was important in validating theories but was not fully accepted by the scientific community at first.','{}','{}','{"frequency": 1, "text_unit_ids": ["71513cc51ffa1e8b185f20e95d505c81a39cad56f6db7e0192988badc6a212324cd2dca2a6e0b895668f6133ccf33ae88b3164f544f6ed7f319db021e5f84305"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('30cbeec8-6659-478a-9d2d-55ef35a9831a'::uuid,'LORD_LANCASTER<TERM>','PERSON','{}','(Historical figure) Frederick William Lanchester, who empirically resolved some of the issues with finite wings and contributed crucial insights to later mathematical models in aerodynamics. His work was foundational for modern airfoil design and analysis.','{}','{}','{"frequency": 1, "text_unit_ids": ["71513cc51ffa1e8b185f20e95d505c81a39cad56f6db7e0192988badc6a212324cd2dca2a6e0b895668f6133ccf33ae88b3164f544f6ed7f319db021e5f84305"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('82d0539e-3462-4f73-92f1-e784e4f146bb'::uuid,'LIFT_TO_DRAG_RATIO<TERM>','SYSTEM','{}','(Dimensionless quantity) A measure used to compare the efficiency of wings in generating lift versus producing drag, essential for understanding and designing flying devices like hang gliders.','{}','{}','{"frequency": 1, "text_unit_ids": ["71513cc51ffa1e8b185f20e95d505c81a39cad56f6db7e0192988badc6a212324cd2dca2a6e0b895668f6133ccf33ae88b3164f544f6ed7f319db021e5f84305"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('34835b35-6620-482c-856f-1c0aeebe6fc6'::uuid,'WIND_TUNNEL_EXPERIMENTATION<TERM>','MECHANISM','{}','Experimental methods using wind tunnels to study aerodynamic properties. It was crucial for validating theories about air resistance and wing performance but not fully accepted until the 1920s.','{}','{}','{"frequency": 1, "text_unit_ids": ["71513cc51ffa1e8b185f20e95d505c81a39cad56f6db7e0192988badc6a212324cd2dca2a6e0b895668f6133ccf33ae88b3164f544f6ed7f319db021e5f84305"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('66cae1ae-7f93-448d-9bd7-4ea7abde1e1e'::uuid,'FLAT_PLATE<TERM>','DEVICE','{}','A simple model or test object used in early experiments to understand basic principles of fluid dynamics, with Otto Smeaton''s measurements being especially significant for determining drag coefficients.','{}','{}','{"frequency": 1, "text_unit_ids": ["71513cc51ffa1e8b185f20e95d505c81a39cad56f6db7e0192988badc6a212324cd2dca2a6e0b895668f6133ccf33ae88b3164f544f6ed7f319db021e5f84305"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3560621d-a9f8-4987-8149-68cd94ee606d'::uuid,'LUDWIG_PRANDTL<TERM>','PERSON','{}','(Academic and engineer) Ludwig Prandtl contributed significantly through his mathematical analysis of wing airflow. His work was foundational in understanding finite wing behavior but not widely accepted until further experimental validation.','{}','{}','{"frequency": 1, "text_unit_ids": ["71513cc51ffa1e8b185f20e95d505c81a39cad56f6db7e0192988badc6a212324cd2dca2a6e0b895668f6133ccf33ae88b3164f544f6ed7f319db021e5f84305"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5062b109-c1a6-40a2-a2b7-10e6ed75cdd4'::uuid,'FLOW AROUND BODIES','MECHANISM','{}','The pattern and dynamics of fluid (air) movement around solid bodies at an angle to their motion, crucial for lift and drag analysis','{}','{}','{"frequency": 2, "text_unit_ids": ["da2c68ea72d6096891cf006fbb7859eb6086b57f5f126736a57dd65bf1b0e2133cdc19753df3049b79ab1e71a91e46e9d3764b949686b623843529cf5f38774b", "da2c68ea72d6096891cf006fbb7859eb6086b57f5f126736a57dd65bf1b0e2133cdc19753df3049b79ab1e71a91e46e9d3764b949686b623843529cf5f38774b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d96d2d78-2163-4253-99e8-2f50ce793466'::uuid,'REYNOLDS NUMBER','MECHANISM','{}','A dimensionless number used in fluid mechanics to predict flow patterns based on the ratio of inertial forces to viscous forces in the system; fundamental for understanding lift and drag characteristics','{}','{}','{"frequency": 2, "text_unit_ids": ["da2c68ea72d6096891cf006fbb7859eb6086b57f5f126736a57dd65bf1b0e2133cdc19753df3049b79ab1e71a91e46e9d3764b949686b623843529cf5f38774b", "da2c68ea72d6096891cf006fbb7859eb6086b57f5f126736a57dd65bf1b0e2133cdc19753df3049b79ab1e71a91e46e9d3764b949686b623843529cf5f38774b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('ede64bd3-c680-4f14-be3f-25c87a24a8cc'::uuid,'SMEATON COEFFICIENT','MODEL','{}','A model for lift coefficient in older aviation that was challenged by later researchers due to its misinterpretation of data from others; misnamed as Smeaton''s based on historical mistake','{}','{}','{"frequency": 2, "text_unit_ids": ["da2c68ea72d6096891cf006fbb7859eb6086b57f5f126736a57dd65bf1b0e2133cdc19753df3049b79ab1e71a91e46e9d3764b949686b623843529cf5f38774b", "da2c68ea72d6096891cf006fbb7859eb6086b57f5f126736a57dd65bf1b0e2133cdc19753df3049b79ab1e71a91e46e9d3764b949686b623843529cf5f38774b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a2b2f63d-128f-4c31-8a0a-5b5548c1dae8'::uuid,'LUDWIG PRANDTL','RESEARCHER','{}','Ludwig Prandtl''s 1904 work provided the first comprehensive solution to fluid flow mechanics and improved understanding of lift and drag, particularly through his study of boundary layers','{}','{}','{"frequency": 2, "text_unit_ids": ["da2c68ea72d6096891cf006fbb7859eb6086b57f5f126736a57dd65bf1b0e2133cdc19753df3049b79ab1e71a91e46e9d3764b949686b623843529cf5f38774b", "da2c68ea72d6096891cf006fbb7859eb6086b57f5f126736a57dd65bf1b0e2133cdc19753df3049b79ab1e71a91e46e9d3764b949686b623843529cf5f38774b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9e610edc-273a-4950-ad57-11bcadb7e2cd'::uuid,'TOWED TRIALS','TEST','{}','TOWED TRIALS is a test technique involving the towing of bodies through the air to conduct drag and lift testing. This method was commonly employed prior to the widespread adoption and advancement of wind tunnel testing techniques. Towed trials served as a crucial means for evaluating aerodynamic properties and performance characteristics of various objects, including aircraft components or models, under controlled conditions before more sophisticated wind tunnel facilities became prevalent in the aerospace industry.','{}','{}','{"frequency": 2, "text_unit_ids": ["da2c68ea72d6096891cf006fbb7859eb6086b57f5f126736a57dd65bf1b0e2133cdc19753df3049b79ab1e71a91e46e9d3764b949686b623843529cf5f38774b", "da2c68ea72d6096891cf006fbb7859eb6086b57f5f126736a57dd65bf1b0e2133cdc19753df3049b79ab1e71a91e46e9d3764b949686b623843529cf5f38774b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('0c807528-cf1d-4a7b-871a-9e6adacf1270'::uuid,'FREE AND SEMI-FREE FLIGHT','SYSTEM','{}','This system consists of Free and Semi-free flight techniques including Drop tests, Free wind and towed trials','{}','{}','{"frequency": 1, "text_unit_ids": ["98f5af20b50979a6ceae00e0e262a4696f43fcd93e841c5eef7dcf55961a4513c7b0217df7f06d0572fe3bf238235fca6779737f60a3dedb4741275610b14f03"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('75299792-aa1a-4f2e-9988-592cb71f7197'::uuid,'MATHEMATICAL_MODEL','MODEL','{}','Used effectively in forming necessary knowledge in aerodynamics, based on continuum hypothesis','{}','{}','{"frequency": 1, "text_unit_ids": ["a9ae9046c84bd485f66f44763948025a4066f10073bee095a4c15c4665d9db3e9ee4c83182db236d7659a96a72f09b4262666709a85154db90a6633d796a8eab"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('22fa7a50-c13b-4d10-ac91-151eba8886eb'::uuid,'AIR_MEDIUM','SYSTEM','{}','The medium (air) through which objects flow and exert forces on each other','{}','{}','{"frequency": 1, "text_unit_ids": ["a9ae9046c84bd485f66f44763948025a4066f10073bee095a4c15c4665d9db3e9ee4c83182db236d7659a96a72f09b4262666709a85154db90a6633d796a8eab"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('7d0e84a0-b032-43ca-a9ce-77179f468188'::uuid,'AERODYNAMIC FORCES','MECHANISM','{}','Forces that cause deformation in aerodynamic bodies','{}','{}','{"frequency": 1, "text_unit_ids": ["16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('08a3a2e7-3046-4724-8c3f-00ba84cb205e'::uuid,'NEWTON''S SECOND LAW','MODEL','{}','Fundamental relation used to study the motion of a fluid or gas particle by considering deformability and changes in relative distances between particles','{}','{}','{"frequency": 1, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('083ec8c3-c65e-4f84-bf87-ecc588dc5f16'::uuid,'BASIC FLUID MECHANICS','MECHANISM','{}','Fundamental principles and concepts related to the flow of fluids which are less understood in early aero research','{}','{}','{"frequency": 2, "text_unit_ids": ["98f5af20b50979a6ceae00e0e262a4696f43fcd93e841c5eef7dcf55961a4513c7b0217df7f06d0572fe3bf238235fca6779737f60a3dedb4741275610b14f03", "98f5af20b50979a6ceae00e0e262a4696f43fcd93e841c5eef7dcf55961a4513c7b0217df7f06d0572fe3bf238235fca6779737f60a3dedb4741275610b14f03"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('7f92cf11-7177-483d-9d22-992c92341d14'::uuid,'FREE WIND TRIALS','PART','{}','A part of Free and Semi-free flight techniques involving the observation of object movement in natural airflow without additional forces such as towed air','{}','{}','{"frequency": 2, "text_unit_ids": ["98f5af20b50979a6ceae00e0e262a4696f43fcd93e841c5eef7dcf55961a4513c7b0217df7f06d0572fe3bf238235fca6779737f60a3dedb4741275610b14f03", "98f5af20b50979a6ceae00e0e262a4696f43fcd93e841c5eef7dcf55961a4513c7b0217df7f06d0572fe3bf238235fca6779737f60a3dedb4741275610b14f03"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('2de62c36-a98e-4663-a10f-2d415199eeb3'::uuid,'ARISTOTLE','MODEL','{}','ARISTOTLE was a prominent philosopher whose work significantly impacted the understanding of physical phenomena in ancient times. According to historical accounts, he theorized the behavior of motion through air and fluid resistance based on his beliefs about the natural order. His ideas, while influential in shaping early scientific thought, were often misunderstood or misinterpreted by subsequent generations. This theoretical framework laid foundational grounds for future exploration into mechanics, although it contained elements that stemmed from philosophical rather than experimental principles.','{}','{}','{"frequency": 2, "text_unit_ids": ["98f5af20b50979a6ceae00e0e262a4696f43fcd93e841c5eef7dcf55961a4513c7b0217df7f06d0572fe3bf238235fca6779737f60a3dedb4741275610b14f03", "98f5af20b50979a6ceae00e0e262a4696f43fcd93e841c5eef7dcf55961a4513c7b0217df7f06d0572fe3bf238235fca6779737f60a3dedb4741275610b14f03"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('49b21c31-38e3-4944-89fa-121e0dbc9755'::uuid,'THEORETICAL DEVELOPMENTS IN FLUID MECHANICS','MODEL','{}','THEORETICAL DEVELOPMENTS IN FLUID MECHANICS is an academic area that focuses on the study of principles and behaviors associated with fluid flow. This field relies heavily on rigorous theoretical analysis to explore and understand various phenomena related to fluids in motion, including their interactions within different environments and under varying conditions. Through this analytical approach, researchers in this discipline aim to develop a deeper understanding of complex fluid dynamics, contributing significantly to advancements in areas such as aerodynamics, hydrodynamics, and the design of efficient energy systems.','{}','{}','{"frequency": 2, "text_unit_ids": ["98f5af20b50979a6ceae00e0e262a4696f43fcd93e841c5eef7dcf55961a4513c7b0217df7f06d0572fe3bf238235fca6779737f60a3dedb4741275610b14f03", "98f5af20b50979a6ceae00e0e262a4696f43fcd93e841c5eef7dcf55961a4513c7b0217df7f06d0572fe3bf238235fca6779737f60a3dedb4741275610b14f03"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('66dd9569-b9a1-46f0-943c-b29c20b6d4f9'::uuid,'MODERN MEASUREMENT TOOLS','SYSTEM','{}','"Modern Measurement Tools" represent significant advancements in technological development that enabled precise and accurate measurements essential for validating fluid mechanics theories. These tools have bridged the gap between historical theoretical foundations laid down by philosophers such as Aristotle and practical experimental methods. Examples of early practical experiments included whirling arms and drop tests, which provided valuable empirical data to support or challenge the established theories. As technology evolved, these initial methods gave way to more sophisticated instruments that enhanced measurement accuracy, facilitating a deeper understanding of fluid dynamics. This progression from traditional approaches to modern technologies highlights the interplay between theoretical knowledge and experimental validation in the field of fluid mechanics.','{}','{}','{"frequency": 2, "text_unit_ids": ["98f5af20b50979a6ceae00e0e262a4696f43fcd93e841c5eef7dcf55961a4513c7b0217df7f06d0572fe3bf238235fca6779737f60a3dedb4741275610b14f03", "98f5af20b50979a6ceae00e0e262a4696f43fcd93e841c5eef7dcf55961a4513c7b0217df7f06d0572fe3bf238235fca6779737f60a3dedb4741275610b14f03"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('463b24bf-e926-4597-9dbb-c5a06a9aa26d'::uuid,'AIR','MATERIAL','{}','Air is a fluid that rushes into potential vacuums created when objects are in motion.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f4dbfdba-9c34-4235-a90e-66eb9b57baa5'::uuid,'POTENTIAL VACUUM','SYSTEM','{}','A system where air rushes to fill the gap between moving objects and other stationary obstructions, allowing continuous motion.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('4a21d0f8-9e1c-49f5-8ce1-c82e38ada656'::uuid,'MODERN CLASSICAL MECHANICS FRAMEWORK','MODEL','{}','/Framework established by Newton combining earlier work including fluid statics principles from Archimedes, Hero, Ctesibius, and others.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('31081232-b260-4ead-9555-10b2b952afcd'::uuid,'ARISTOTLE''S CONTINUUM CONCEPT','CONCEPT','{}','A concept that fluids are continuous, not made up of discrete particles; a notion Aristotle discussed which was not fully accepted until the 18th century.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f9d8d73f-c336-42d7-8687-bb752bce5e29'::uuid,'ARCHIMEDES'' PRINCIPLES','SYSTEM','{}','Fluid statics principles established around 287-212 B.C., recognized but not fully appreciated until the work of later scientists like Stevins, Galileo, and Castelli.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('85d73882-5c42-4a32-a5b5-d1a11d609b8c'::uuid,'HERO''S CONTRIBUTIONS','DEVICE','{}','Hero’s contribution to fluid mechanics, working after approximately 150 B.C., building on earlier principles.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ddd87d31-6518-4059-943d-137510c27d76'::uuid,'CTESIBIUS'' WORK','COMPONENT','{}','Influenced by Archimedes and contemporary with or slightly later than Hero, contributed to the foundation of fluid statics but not widely acknowledged at the time.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('b444f94f-66a1-4d7b-ae75-7a063129a27a'::uuid,'STEVINS'' FOUNDATION FOR FLUID STATICS','MODEL','{}','Worked on fluid mechanics in the 16th century (1548-1620), helped put fluid statics on a credible scientific basis, building upon earlier principles of Archimedes and others.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('04b13fe7-efae-402e-a296-9d8b3500824b'::uuid,'GALILEO''S CONTRIBUTIONS TO MECHANICS','MODEL','{}','Contributions to mechanical principles including interactions with fluids by the late 16th century to early 17th century Galileo (1564-1642).','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e441719c-4480-4e9c-aeab-53d458cfdbd4'::uuid,'CASTELLI’S RESEARCH IN MECHANICS','COMPONENT','{}','Reseacher who contributed to mechanics and fluid dynamics, building on work of earlier scientists like Stevins and Galileo.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c556b33a-1d8b-4e16-a718-a7f038505576'::uuid,'EDMUND HALLEY’S NOTE ON WING SIZE','DEVICE','{}','Published a note in 1691 suggesting calculations necessary to determine wing size for a feasible manned flight, considering the principles of mechanics and fluids.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('8feb7990-cb85-40ee-a4f9-038f6b32da7e'::uuid,'DANIEL BERNOULLI''S CONCEPTS IN FLUID DYNAMICS','MODEL','{}','Developed fundamental concepts of fluid dynamics during the mid-18th century (late 1700s A.D.), recognizing pressure as a key factor within fluids and establishing principles of fluid dynamics.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('7ccc0129-3477-4950-900d-e99a9efd547c'::uuid,'LEONARD EULER’S CONTRIBUTIONS TO MECHANICS','COMPONENT','{}','Wrote important equations related to fluid motion along with Bernoulli, developing foundational theories of fluid mechanics.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('663f0139-ebd8-4454-b5f9-25bf2c818679'::uuid,'NEWTON''S LAW OF VISCOSITY','MODEL','{}','Established the principles for viscous forces and friction between fluids and solids in his laws of motions, which were pivotal but not fully understood until later work by other mathematicians.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('1690d508-d75f-4469-8c67-8b0a6b27f219'::uuid,'ST VENANT, NAVIER & STOKES'' EQUATIONS','SYSTEM','{}','In 19th century (mid-1800s), these mathematicians developed full equations describing fluid motion that included friction, marking a significant advancement in the field of fluid mechanics but could not be generally solved due to complexity.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f7dcf2c7-57b4-4d58-b09c-7e7b6fe4e28f'::uuid,'VON HELMHOLTZ’S WORK ON VORTEX FILAMENTS','MODEL','{}','In 1850s, contributed greatly with his concepts of vortex filaments, sheets and discontinuities, enabling analysis of non-continuous fluid flows.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('2b5a4d09-3ce8-455d-b613-204456e3cc8a'::uuid,'LORD RALEIGH’S EXPANSION OF FLUID DYNAMICS CONCEPTS','COMPONENT','{}','Expanded on the work of von Helmholtz by applying these principles to a wider range of phenomena including atmospheric dynamics.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('11969e07-95d7-4ce9-9576-71d73e6b9592'::uuid,'LORD KELVIN''S ROLE IN MECHANICS DEVELOPMENT','MODEL','{}','Provided insights and contributions essential for understanding fluid mechanics, often collaborating with other mathematicians but his specific role was in expanding the conceptual framework beyond what von Helmholtz established.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('40040b0a-8493-4d39-8957-8e029dfb0bd9'::uuid,'LAMINAR PIPE FLOW MEASUREMENTS BY HAGEN & POISEUILLE','SYSTEM','{}','Performed experimental studies in mid-19th century, establishing basic principles on laminar flow through pipes that remain foundational.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('88ea7926-2890-47ce-bdbc-25171b3b9602'::uuid,'LAMINAR PIPE FLOW','MECHANISM','{}','Laminar pipe flow refers to a steady, streamlined type of fluid flow within tubes characterized by smooth, non-turbulent motion. Hagen and Pouiselle measured this, while Boussinesq also contributed to its understanding).','{}','{}','{"frequency": 1, "text_unit_ids": ["5985fc6749a64fb8e61f7a2dcaeb6777591d07e107e27e9f81ec141746d44adcac5a3c9000993f0f170c0b6328ef2350e35bc72f717da15ff3420d8f6ff42f91"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9a5f10aa-1d57-4d23-8dcd-334a04559ac7'::uuid,'LAMINAR FLAT PLATE','DEVICE','{}','A laminar flat plate is a specific geometry where the boundary layer can be studied analytically, used by Blasius for his solution to find the properties of laminar flow on such surfaces}.','{}','{}','{"frequency": 1, "text_unit_ids": ["5985fc6749a64fb8e61f7a2dcaeb6777591d07e107e27e9f81ec141746d44adcac5a3c9000993f0f170c0b6328ef2350e35bc72f717da15ff3420d8f6ff42f91"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c96ee400-5b90-4c6a-87b4-c043c33261c5'::uuid,'BOUSSINESQ','SCIENTIST','{}','Joseph Valentin Boussinesq (1842-1929) was a French physicist who contributed to fluid mechanics, thermal physics, and elasticity. He is credited with understanding the basis of boundary layers).','{}','{}','{"frequency": 1, "text_unit_ids": ["5985fc6749a64fb8e61f7a2dcaeb6777591d07e107e27e9f81ec141746d44adcac5a3c9000993f0f170c0b6328ef2350e35bc72f717da15ff3420d8f6ff42f91"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f197716a-6a01-4349-9377-63e111b6b08a'::uuid,'REYNOLDS','PERSON','{}','"Reynolds" likely refers to Osborne Reynolds (1842–1912), an English physicist renowned for his work on fluid-flow phenomena including turbulence, and it was him who identified laminar-to-turbulent transition principles by introducing what we now know as the Reynolds number}.','{}','{}','{"frequency": 1, "text_unit_ids": ["5985fc6749a64fb8e61f7a2dcaeb6777591d07e107e27e9f81ec141746d44adcac5a3c9000993f0f170c0b6328ef2350e35bc72f717da15ff3420d8f6ff42f91"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a4a648aa-e358-4ef0-8f8b-81cd03235522'::uuid,'KUTTA ZHUKOVSKY THEOREM','THEOREM','{}','"The Kutta-Zhukovsky theorem" (likely a misnomer; it should be referred to as the lifting line theory or Zhukovsky''s theorem), named after Martin Kutta and Nikolai Yezhof who developed circulation theory for finite wings. However, both are credited by modern accounts like Zhukovsky in Russia before WWI).','{}','{}','{"frequency": 1, "text_unit_ids": ["5985fc6749a64fb8e61f7a2dcaeb6777591d07e107e27e9f81ec141746d44adcac5a3c9000993f0f170c0b6328ef2350e35bc72f717da15ff3420d8f6ff42f91"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d2164831-a9a5-42a8-96b9-a3e9c60d2c89'::uuid,'LIFTING LINE THEORY','MODEL','{}','"The lifting line theory" is a theoretical approach to determine the lift on an airfoil based on its circulation and was developed primarily by Prandtl and contemporaries. It considers the vortices induced along the wing span (principally in the boundary layer) that contribute to lift}.','{}','{}','{"frequency": 1, "text_unit_ids": ["5985fc6749a64fb8e61f7a2dcaeb6777591d07e107e27e9f81ec141746d44adcac5a3c9000993f0f170c0b6328ef2350e35bc72f717da15ff3420d8f6ff42f91"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ef2d6e6e-cbd8-46dd-99c5-95b844222a00'::uuid,'LAMINAR BOUNDARY LAYER','MECHANISM','{}','Refers specifically to a laminar type of fluid flow near surfaces, where Prandtl and Blasius worked to develop solutions for its behavior on flat plates).','{}','{}','{"frequency": 1, "text_unit_ids": ["5985fc6749a64fb8e61f7a2dcaeb6777591d07e107e27e9f81ec141746d44adcac5a3c9000993f0f170c0b6328ef2350e35bc72f717da15ff3420d8f6ff42f91"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3127d379-5f3a-40fb-b053-7f44ddfbbf14'::uuid,'BAIRSTOW','PERSON','{}','Bairstow (1870-1955) was a British engineer who contributed to the field of aerodynamics, working particularly with NPL on dynamic analysis of aircraft motions. His work expanded upon the dynamic analyses that started from G.H. Bryan''s pioneering efforts).','{}','{}','{"frequency": 1, "text_unit_ids": ["5985fc6749a64fb8e61f7a2dcaeb6777591d07e107e27e9f81ec141746d44adcac5a3c9000993f0f170c0b6328ef2350e35bc72f717da15ff3420d8f6ff42f91"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('470fa66b-4987-46bc-b58b-ccad12bfe64d'::uuid,'HAGEN POUSIELLE FLOW','MECHANISM','{}','"Hagen-Poiseuille flow" refers to laminar, steady-state non-Newtonian fluid flow in a circular pipe, originally derived by Jean Léonard Marie Poiseuille (1797–1869) and Augustin-Jean Hagen (1795–1834). It sets the foundational theory for understanding laminar flows through conduits}.','{}','{}','{"frequency": 1, "text_unit_ids": ["5985fc6749a64fb8e61f7a2dcaeb6777591d07e107e27e9f81ec141746d44adcac5a3c9000993f0f170c0b6328ef2350e35bc72f717da15ff3420d8f6ff42f91"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('38ed1a03-2cf1-486e-87af-472679ac018d'::uuid,'G HAIRY BRYAN THEOREM','MODEL','{}','"The G.H. Bryan theorem" likely refers to the contributions of G.H. Bryan who was involved in dynamic analysis of aircraft motions but his work prior to 1904, and not well-known at the time to the Wright Brothers.','{}','{}','{"frequency": 1, "text_unit_ids": ["5985fc6749a64fb8e61f7a2dcaeb6777591d07e107e27e9f81ec141746d44adcac5a3c9000993f0f170c0b6328ef2350e35bc72f717da15ff3420d8f6ff42f91"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6d427e3b-43dc-4daf-8d97-19ea1e0bfbe3'::uuid,'CRAFT','DEVICE','{}','A craft designed for superior gliding performance, analogous to modern sailplanes','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ab7aebc8-f560-41b0-8ff8-64b9650ba81d'::uuid,'WINDMILLS32','DEVICE','{}','Windmills in Babylon around 1700BC, used for converting wind energy into mechanical power','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('2d71a54d-3e7a-4652-962e-7f091096eaf2'::uuid,'KITES33','DEVICE','{}','Kites being flown in China before the 5th century BC, used for lifting objects by wind power','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9c05c6d0-d298-49c6-9b6d-c3d048e83c7c'::uuid,'ROTO-COPTER35','DEVICE','{}','Possible early rotor-based aircraft concept in China, likely a precursor to modern helicopters or drones with rotors for vertical motion','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('91bf0ec7-c481-4f67-a3d3-43411ed6acb5'::uuid,'LEONARDO DA VINCI15','PERSON','{}','Italian polymath who made critical advancements in understanding aerodynamics, flapping wing mechanisms and early helicopters','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('34bc8797-d0f1-466f-859c-ff9e4f624f4e'::uuid,'CLOCKWORK DRIVEN HELICOPTER','DEVICE','{}','Russian scientist M.Lomonossov''s 1700s innovation, an early mechanical helicopter design','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('2f1b3c28-9e0d-4e29-9911-574fc8fe7db9'::uuid,'HOT AIR BALLOON','DEVICE','{}','French hot air balloons of 1783 demonstrating principles of aerial navigation and passenger flight','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('04c00793-4cc2-49b9-b4a9-42206076e1c4'::uuid,'MANNED GLIDER','DEVICE','{}','Manned gliders proposed by Leonardo da Vinci, early steps towards personal flight apparatuses','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('2e794bc7-37a3-4fac-bf70-0392cb946cdb'::uuid,'FLUID FLOW PATTERNS13','MECHANISM','{}','Leonardo da Vinci''s understanding of fluid dynamics, crucial for propellers and turbines used in craft mechanics','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d9802951-f9a4-45ef-8f1f-d5b214ac8615'::uuid,'WHIRLING ARM8','DEVICE','{}','Experimental device by Cayley to study aerodynamics, enabling detailed analysis and design of flight crafts','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5690c479-4235-4909-a568-cb8adf7ce3bd'::uuid,'MODEL GLIDER1804-1809','MODEL','{}','Early flight model with a trimmed state, key milestone in aviation research by Cayley','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6897313e-5f01-453f-bde5-6290ecd72b20'::uuid,'FULL-SIZED GLIDER1809','DEVICE','{}','Large-scale implementation of Cayley’s aerodynamic theories, early step towards practical flight design','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('7af7f810-710c-4a49-ad37-0ec27aa5d925'::uuid,'PROPELLER DRIVEN AERIAL CARRIAGE','DEVICE','{}','Early concept for steam-powered aircraft with propellers, design work by Henson1848-1852','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('92ccff91-82a3-448b-b965-83cb83110e42'::uuid,'STEAM-POWERED AIRCRAFT3M SPAN15-18','DEVICE','{}','Small-scale testbed for steam power, capable of short flights by Stringfellow1842-1857','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('2437ff3c-978f-4ea1-bab2-6f42ca704954'::uuid,'PASSENGER FLIGHT','SYSTEM','{}','First instance of human flight with a passenger1783, marking a leap from experimental to practical use','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5a0b6d01-c462-4b89-b0c6-31e515706cb0'::uuid,'PROPELLER DRIVEN STEAM POWERED AERIAL CARRIAGE','DEVICE','{}','A device initially conceptualized by early aviation pioneers, characterized by its use of a steam engine to drive a propeller for propulsion in an air vehicle','{}','{}','{"frequency": 1, "text_unit_ids": ["4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('aefce5fd-b673-4e42-bcee-567368880058'::uuid,'CAYLEY''S GLIDER','DEVICE','{}','CAYLEY''S GLIDER, developed by George Cayley in 1852, is a significant early design in aviation history. This man-carrying glider played a pivotal role in advancing aerodynamic principles and pioneering the separation of lift, equilibrium, and propulsion tasks essential for flight. By focusing on these distinct functions, Cayley''s creation laid the groundwork for later developments in heavier-than-air machines that utilized dynamic lift mechanisms. The 1852 model marked a crucial step forward in the quest to achieve sustainable, pilot-carrying gliders, influencing subsequent generations of aerospace innovators and aircraft designs.','{}','{}','{"frequency": 3, "text_unit_ids": ["4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e2332086-5833-4fdd-a36b-5da8c7324822'::uuid,'GUNPOWDER ENGINE','MATERIAL','{}','The "GUNPOWDER ENGINE," an experimental engine developed in the late 19th century by Sir George Cayley, aimed to power aircraft. However, the engine did not meet the requirements for being both powerful and reliable. This engineering attempt was part of Cayley''s broader efforts in aviation research during a time when early pioneers were exploring ways to solve the challenges of sustained powered flight.','{}','{}','{"frequency": 3, "text_unit_ids": ["4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('8ca0ec61-d72d-4025-b69f-f9e9e2bd3765'::uuid,'COMPRESSED AIR ENGINE','DEVICE','{}','"COMPRESSED AIR ENGINE" is an experimental engine concept proposed by Sir George Cayley in the mid-19th century as a potential means of aircraft propulsion. Although interesting theoretically, this design did not achieve practical success primarily due to its inherent limitations in power output and reliability. This concept represented one of several early attempts by Cayley to explore novel methods for powered flight, yet it never realized its full potential as a viable technology in aviation history.','{}','{}','{"frequency": 3, "text_unit_ids": ["4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('240c42d4-6e12-4986-a251-78e4a80b4d95'::uuid,'PÉNAUD''S RUBBER MOTOR POWERED GLIDER','DEVICE','{}','PÉNAUD''S RUBBER-MOTOR POWERED GLIDER, developed in 1871, is noted for its historical significance as an important milestone in the evolution of powered flight. This aircraft was a stable design capable of flying over 39 meters and represented a key advancement by early aviation pioneers towards achieving controlled, powered flight.','{}','{}','{"frequency": 3, "text_unit_ids": ["4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('598a14ba-c114-43e3-8899-80585b09d448'::uuid,'VEHICLESTABILITY','SYSTEM','{"обеспечивает баланс в полёте","обеспечивает управление полётом"}','Unicycle-like instability of bicycles in the lateral plane, requiring continuous rider intervention to maintain vertical orientation','{}','{}','{"frequency": 1, "text_unit_ids": ["3afa04cc7530a641a3fd45906a688d4d426fc2e94b2b585d2d5b048682c638b5d8cd601b89ec4e804b881be405f7431c8a546e371ae8a5e5f7c753897b8c882b"]}','2026-07-17 10:37:07.080969','2026-07-17 10:37:07.080969','history_development_aeronautics'),
	 ('9007427a-7192-485f-a541-2efbccb65b00'::uuid,'NEWTON''S WORK ON BODIES INTERACTION','THEORY','{}','Newton''s work on force acting on bodies in flows, advancing understanding of aerodynamic principles)"relationship"','{}','{}','{"frequency": 2, "text_unit_ids": ["a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad", "a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('4a25c4b9-7227-4900-9367-d6d94c5b88ea'::uuid,'FORCE','MECHANISM','{}','Force acting on bodies from an incoming flow, described by the formula F = ρ S V² sin² α','{}','{}','{"frequency": 1, "text_unit_ids": ["a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('8ccf7fdd-43bd-4d08-b552-93e4b8120f5e'::uuid,'NEWTON''S HYPOTHESIS','MODEL','{}','Hypothesis about the interaction of air particles with streamlined surfaces used by Newton to derive his force formula','{}','{}','{"frequency": 2, "text_unit_ids": ["a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae", "a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('60cf86b0-b905-49d3-831b-3235f5b5249a'::uuid,'FLAT PLATE','DEVICE','{}','A flat, streamlined surface for which the provided formula is applied','{}','{}','{"frequency": 2, "text_unit_ids": ["a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae", "a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('c99f57ab-ca57-4599-9e07-6bd58ab7bcc1'::uuid,'MONTGOMERY''S GLIDER','DEVICE','{}','MONTGOMERY''S GLIDER, developed in 1884, is documented as one of the pioneering attempts in aviation history. Built by an individual named Montgomery in the United States, this manned monoplane glider featured cambered aerofoils—curved surfaces that were crucial for producing lift and enhancing stability during flight. The design represented a significant early effort to achieve controlled flight capabilities, marking an important step towards the realization of heavier-than-air flight technologies.','{}','{}','{"frequency": 3, "text_unit_ids": ["4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('db16155b-d35f-4a7b-9ef0-62094f423a37'::uuid,'ADER''S STEAM-POWERED MACHINE','SYSTEM','{}','The "ADER''s Steam-Powered Machine" was a pioneering steam-powered aircraft that demonstrated significant advancements in early aviation technology. Developed by Louis-Dominique Ader, this machine marked the first successful steam-powered device capable of controlled flight, setting it apart from earlier attempts. Notably, on October 9, 1897, at Mont-Moulin La Gallette near Paris, Ader conducted a demonstration where the machine executed what appeared to be a "powered hop," marking an essential step in the development of aerial vehicles.
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('a08bb59f-b3e6-463f-a002-a8eb19557bd7'::uuid,'LILIENTHAL''S WHIRLING ARM','DEVICE','{}','(1891) "An apparatus devised by Otto Lilienthal for testing wing forces and lift coefficients; it involved rotating wings at high speed in open air, providing crucial data that advanced early aviation theory on aerodynamics."','{}','{}','{"frequency": 1, "text_unit_ids": ["4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('41b0d4ff-08a7-41ca-b435-ff43fb3afc85'::uuid,'HISTORICAL OUTLINE','SYSTEM','{}','The historical process described traces back to prehistoric times when humans started imitating bird flight, progressing through ancient and medieval ideas, to the 1783 invention by Montgolfier brothers','{}','{}','{"frequency": 1, "text_unit_ids": ["a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('e707a8d7-6b50-4c55-9a5b-a4e110b19cfc'::uuid,'ANCIENT HUMANS','PART','{}','Desire to fly like birds, early inspirations for aerodynamic principles.','{}','{}','{"frequency": 1, "text_unit_ids": ["a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('bf98c63e-6b31-4a45-b593-9305178f5f18'::uuid,'NATURAL DESIRE TO IMITATE BIRD FLIGHT','MECHANISM','{}','Behavior of birds inspired human thought on flight and the development of aerodynamic concepts','{}','{}','{"frequency": 1, "text_unit_ids": ["a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('c88d3f56-c767-4deb-ae98-c6fdd08afa53'::uuid,'WOODEN FIGURINE','MODEL','{}','Ancient Egyptian wooden model, initially mistaken for a bird statuette but later identified as a glider. Vertical part served as rudder; exact copy demonstrated capability.','{}','{}','{"frequency": 1, "text_unit_ids": ["a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('858f11c8-d9b6-4d9a-99d8-05152fc6ddfe'::uuid,'DAEDALUS AND ICARUS MYTH','MYTH','{}','Greek myth highlighting early recognition of flight principles','{}','{}','{"frequency": 2, "text_unit_ids": ["a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad", "a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('d2bbccdc-a7a9-4c28-bba7-4b841fd4d1a6'::uuid,'GREEK CULTURE, HELLENISTIC PERIOD','SYSTEM','{}','Period that began movement towards modern scientific aerodynamics with understanding of air weight by Aristotle','{}','{}','{"frequency": 2, "text_unit_ids": ["a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad", "a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('92c494f6-b7bf-47cd-88ee-5c5ddd456bb7'::uuid,'HIRAM MAXIM','PERSON','{}','Hiram Maxim was an inventor who produced the first steam-powered monoplane that could lift off the ground but lacked control','{}','{}','{"frequency": 1, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e6e72fd7-1557-411b-be62-80a3ae445762'::uuid,'STEAM POWERED MONOPLANE','DEVICE','{}','The steam-powered monoplane developed by Hiram Maxim, capable of vertical takeoff but uncontrolled','{}','{}','{"frequency": 1, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b19973ad-57df-421b-9b9b-8dafdee2ac0c'::uuid,'PERCY PILCHER','PERSON','{}','English aviation pioneer who continued Lilienthal''s gliding work and tragically died in a crash similar to Lilienthal’s','{}','{}','{"frequency": 1, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('d9e2ae2c-f3fb-4156-96d7-a8f7f64c73f9'::uuid,'OCTAVE CHANUTE','PERSON','{}','Octave Chanute was an American civil engineer who played a significant role in early aviation developments. He funded and supported the construction of several glider designs, particularly focusing on biplane structures inspired by Otto Lilienthal''s work. Chanute’s contributions extended beyond financial support; he also collaborated closely with pioneering aviators such as the Wright brothers, introducing them to advanced flight design principles including the innovative Pratt truss. This collaboration between Chanute and the Wrights facilitated mutual learning and advancements in heavier-than-air aircraft technology. Through his efforts, Chanute helped bridge earlier research from Lilienthal with more refined structural designs, significantly influencing early aviation development.','{}','{}','{"frequency": 3, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5", "a1689fa4557c7bd9828498b6af22e4d56a6e70b706bc03a66df0ec58854f6cb93cfb6e67be14e6cf7954609e79e3b6bd423a0ba59422819f13f132672854041e", "ccac1a178375331bc449ac2d2eec635f0983c00e6d254912345c012c0c41f3a9cc65da465cf715f8bc206801bb7f81cd82c005354ce5454c3970c507c2045930"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c93e0819-1966-4ff4-bd1b-0317f1664ae8'::uuid,'PRATT TRUSS','MECHANISM','{}','Structural component introduced to aircraft design by Octave Chanute through his collaboration with Wright brothers','{}','{}','{"frequency": 1, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3e0f610e-e1f9-4522-9057-5690d7d3b841'::uuid,'SAMUEL P LANGLEY','PERSON','{}','Astronomer who developed unsuccessful steam-powered flying models and later significant manned flight attempts, using whirling arms for aerodynamic data','{}','{}','{"frequency": 1, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a70f54f6-5006-4a87-a79f-4e9f8b905c45'::uuid,'GRANTED GOVERNMENT AND CHARITY FUNDS TO CONSTRUCT SUCCESSFUL STEAM POWERED FREE FLYING MODELS','SYSTEM','{}','Government and charity support provided by Samuel Langley for model aircraft development','{}','{}','{"frequency": 1, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('0d0c09f7-b4bf-48fd-b9de-372a40770084'::uuid,'WRIGHT BROTHERS'' FIRST POWERED GLIDER','DEVICE','{}','First glider flown by the Wright brothers in 1901, preceding their first powered flight','{}','{}','{"frequency": 1, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e10de561-fd5b-4543-b6ec-ae67a9c4fcd8'::uuid,'SANTOS DUMONT','PERSON','{}','French aviator who flew a powered airship and was inspired by the Wrights'' success, first making a powered manned flight in Europe in 1906','{}','{}','{"frequency": 1, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('2b51225d-e336-4dad-8787-61ede3963ca5'::uuid,'EIFEL TOWER','GEO','{}','The Eiffel Tower in France where Santos Dumont flew his powered airship','{}','{}','{"frequency": 1, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('4291b21a-031a-4aad-b62d-fafe046ac18c'::uuid,'WRIGHT BIPLANES SOLD IN EUROPE','SYSTEM','{}','European sale of many Wright-designed and built biplanes as a result of demonstration tours by the Wright brothers','{}','{}','{"frequency": 1, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('4ea0390d-264e-4d1a-a19d-ff0013d34de7'::uuid,'FIRST WORLD WAR','GEO','{}','Signified an era during which aviation technology progressed rapidly due to military demands, especially for aerial reconnaissance and combat','{}','{}','{"frequency": 2, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5", "ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9b4977eb-14ac-4df9-81be-a62b465c2412'::uuid,'PERCY PILCHER13','PERSON','{}','English aviation pioneer who continued Lilienthal''s gliding work and tragically died in a crash similar to Lilienthal’s','{}','{}','{"frequency": 1, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('b1e9c986-5f07-4f1e-9b07-ccae19870b2b'::uuid,'OCTAVE CHANUTE13,38','PERSON','{}','American civil engineer who collaborated with the Wright brothers and introduced them to advanced flight structures, including the Pratt truss','{}','{}','{"frequency": 1, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('63ada80a-fda6-4a7a-b8b3-6041d982bdf4'::uuid,'LANGLEY''S LATER WELL-FUNDED ATTEMPTS AT A MANNED POWERED FLIGHT','_SYSTEM_::','{}','Langley''s significant but unsuccessful later attempts at developing a powered aircraft','{}','{}','{"frequency": 1, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('93060ca6-f34e-480b-b621-490e56a2bcdf'::uuid,'SAMUEL P LANGLEY39','PERSON','{}','Respected astronomer who gained government and charity funding to construct models, later attempting manned powered flight','{}','{}','{"frequency": 1, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a6f25b4d-2ebf-4d6d-945c-2c05d5dfb645'::uuid,'SANTOS DUMONT IN FRANCE','PERSON','{}','French aviator who flew a powered airship around the Eifel Tower, inspired by the Wrights’ success and making the first European manned flight in 1906','{}','{}','{"frequency": 1, "text_unit_ids": ["ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9a025b8a-c69f-4662-b717-140dbdcf9e44'::uuid,'FREE AND SEMI-FREE EXPERIMENTS','SYSTEM','{}','These include methods like drop tests, wind exposure without interference, and towed bodies to study airflow and aerodynamics','{}','{}','{"frequency": 1, "text_unit_ids": ["5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('4f3000df-ff99-49c1-be2e-b6a4ddaea5fe'::uuid,'WATER','MATERIAL','{}','Used in early experiments for simulating air flow at low speeds due to its similarity with air','{}','{}','{"frequency": 2, "text_unit_ids": ["5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b", "5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('7e639dd5-d756-4634-85a8-2ecbeb790626'::uuid,'AIRFLOW','MECHANISM','{}','The primary subject of experimentation, relating to the movement of air around objects such as aircraft','{}','{}','{"frequency": 2, "text_unit_ids": ["5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b", "5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('2507eda4-4d37-4685-b77d-0a63dc73cd9b'::uuid,'STEVINS','PERSON','{}','An early experimentalist who conducted recorded drop test experiments in 1586, primarily to determine the role of weight on fall rates','{}','{}','{"frequency": 2, "text_unit_ids": ["5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b", "5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('10365147-c5d7-4e69-9270-8c164e31aa20'::uuid,'GALILEO','PERSON','{}','Subsequently expanded experimental methods to include more sophisticated ones that allowed for controlled variable testing','{}','{}','{"frequency": 2, "text_unit_ids": ["5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b", "5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a6b8617e-1ed4-4b4c-8053-cd3536addf78'::uuid,'EIFFEL','PERSON','{}','"EIFFEL," referring to Gustave Eiffel, was a pioneering civil engineer who made significant contributions to the understanding of pressure distributions on wings through his systematic experimental approach. His work involved the development and application of advanced release mechanisms that ensured consistency in experimental outcomes. Eiffel''s innovative methods laid foundational knowledge in aerodynamics and structural engineering, showcasing a blend of theoretical insights with practical experimentation.','{}','{}','{"frequency": 3, "text_unit_ids": ["5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b", "5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b", "e0ded24d363ec39e76d9e983a1bafea9a1e9accb8059322ef7065b07c4c84c9cee4caa65c00b8bf702b00a6751810904936f74916a3ef15893333841e710c08c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('2847023e-7e25-410e-971d-fe875c9696f9'::uuid,'NATURAL WIND','COMPONENT','{}','Used in free flight tests, allowing models to experience the natural wind and measure resultant forces','{}','{}','{"frequency": 2, "text_unit_ids": ["5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b", "5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('85a65f75-31ed-4858-89b3-d116fef6a9a2'::uuid,'GLIDER FLIGHTS','DEVICE','{}','Part of the free flight method, where models are used without power for measuring the effects of natural wind','{}','{}','{"frequency": 2, "text_unit_ids": ["5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b", "5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('95a1d74c-af51-4cb3-9b35-79435b7b5532'::uuid,'TOWED BODIES','MODEL','{}','A method where objects are drawn through air by an active towing source to study aerodynamic forces, minimizing direct mechanical connection for interference','{}','{}','{"frequency": 2, "text_unit_ids": ["5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b", "5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('defcb792-f468-410b-8a24-312e4c2081e4'::uuid,'SIMON STEVINS','PERSON','{}','Simon Stevins was a Dutch engineer and mathematician known for his work on hydrostatics, statics, and mechanics. He was born in 1548 and died in 1620','{}','{}','{"frequency": 2, "text_unit_ids": ["420bf471d6efd14f20451de42dd132dbbb1f30032fe7872183bfede6d0e70d8eb4713e527c05d323ff76f0721a4d224b6eb876f0522c8f248b177d4af5b3a251", "420bf471d6efd14f20451de42dd132dbbb1f30032fe7872183bfede6d0e70d8eb4713e527c05d323ff76f0721a4d224b6eb876f0522c8f248b177d4af5b3a251"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b277edaf-6c7d-449d-8f9e-589f3e1654f1'::uuid,'WATERWORKS','SYSTEM','{}','Waterworks refer to systems or works built for distributing water, frequently encompassing storage reservoirs, aqueducts, canals, pumps, and fountains','{}','{}','{"frequency": 2, "text_unit_ids": ["420bf471d6efd14f20451de42dd132dbbb1f30032fe7872183bfede6d0e70d8eb4713e527c05d323ff76f0721a4d224b6eb876f0522c8f248b177d4af5b3a251", "420bf471d6efd14f20451de42dd132dbbb1f30032fe7872183bfede6d0e70d8eb4713e527c05d323ff76f0721a4d224b6eb876f0522c8f248b177d4af5b3a251"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('58bcd071-2130-4f8c-b006-cfb4beec45e7'::uuid,'HYDROSTATICS','MODEL','{}','Hydrostatics, a branch of fluid mechanics, focuses on the study of fluids at rest. This field encompasses an array of phenomena including forces, pressures, and flows associated with static bodies of fluid. It also delves into specific aspects such as density, pressure, buoyancy, and other related properties observed in water or air when they are stationary. By examining these elements under conditions where the fluids do not undergo any motion, hydrostatics provides foundational understanding for a variety of applications, from engineering principles to scientific research.','{}','{}','{"frequency": 2, "text_unit_ids": ["420bf471d6efd14f20451de42dd132dbbb1f30032fe7872183bfede6d0e70d8eb4713e527c05d323ff76f0721a4d224b6eb876f0522c8f248b177d4af5b3a251", "420bf471d6efd14f20451de42dd132dbbb1f30032fe7872183bfede6d0e70d8eb4713e527c05d323ff76f0721a4d224b6eb876f0522c8f248b177d4af5b3a251"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e7e1658b-7551-4c52-94a2-a69748aa2d85'::uuid,'HYGHENS','PERSON','{}','Christiaan Hygens, or Huygens, was a Dutch mathematician and physicist who lived from 1629 to 1695. He made significant contributions to the study of dynamics and probability theory','{}','{}','{"frequency": 1, "text_unit_ids": ["420bf471d6efd14f20451de42dd132dbbb1f30032fe7872183bfede6d0e70d8eb4713e527c05d323ff76f0721a4d224b6eb876f0522c8f248b177d4af5b3a251"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('cdfff8b9-2a16-4468-bf6f-f9a27eef759a'::uuid,'PICARD','PERSON','{}','Gilles Personne de Prony, also known as Picard, was a French civil engineer who made important contributions to mathematical science. He worked on the design of waterwheels and other mechanical devices','{}','{}','{"frequency": 1, "text_unit_ids": ["420bf471d6efd14f20451de42dd132dbbb1f30032fe7872183bfede6d0e70d8eb4713e527c05d323ff76f0721a4d224b6eb876f0522c8f248b177d4af5b3a251"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('dc768ab8-e9a7-4794-8cfe-a05cb4b075c9'::uuid,'CASSINI','PERSON','{}','Jean Dominique Cassini was an Italian-French astronomer and engineer. In addition to his work in astronomy, he contributed to hydrodynamics and mechanics, particularly with regard to fluid resistance measurements','{}','{}','{"frequency": 1, "text_unit_ids": ["420bf471d6efd14f20451de42dd132dbbb1f30032fe7872183bfede6d0e70d8eb4713e527c05d323ff76f0721a4d224b6eb876f0522c8f248b177d4af5b3a251"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ad9e2365-1a46-40c7-83d3-dde6382ef127'::uuid,'ACADÉMIE ROYALE DES SCIENCES','SYSTEM','{}','The Royal Academy of Sciences was a learned body established in France which focused on scientific research and was active during the reigns of Louis XIV through Napoleon Bonaparte''s early years. It was known for its rigorous methods of investigation','{}','{}','{"frequency": 1, "text_unit_ids": ["420bf471d6efd14f20451de42dd132dbbb1f30032fe7872183bfede6d0e70d8eb4713e527c05d323ff76f0721a4d224b6eb876f0522c8f248b177d4af5b3a251"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('42b8f4ff-0f31-4347-870c-2fdbbe252a7e'::uuid,'GALILEO GALILEI','PERSON','{}','Galileo was an Italian astronomer, physicist, engineer, philosopher, and mathematician. He is credited with making significant innovations in the fields of mechanics and astronomy as well as being a pioneer in using experiments to validate scientific theories','{}','{}','{"frequency": 1, "text_unit_ids": ["420bf471d6efd14f20451de42dd132dbbb1f30032fe7872183bfede6d0e70d8eb4713e527c05d323ff76f0721a4d224b6eb876f0522c8f248b177d4af5b3a251"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b93c7df3-79bc-4f48-9af3-f58613b549c8'::uuid,'PENDULUM','DEVICE','{}','A pendulum used for drop tests with different shaped masses to measure resistance factors','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('27fc0a5a-8446-4176-8e35-36b0b40ffdca'::uuid,'MASS SHAPE','COMPONENT','{}','Different shapes used on the pendulum for testing in air and water, affecting fluid resistance','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('138d9a24-cfa9-48bc-bde0-eca2bebbc9df'::uuid,'RESISTANCE','MECHANISM','{}','A property measured during the drop tests under different conditions, influenced by mass shape, velocity, and fluid density','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a269a5a5-eb40-4e7f-a8f2-504489bec050'::uuid,'VELOCITY SQUARE DEPENDENCE','SYSTEM','{}','(\(v^2\)), a relationship observed in resistance measurements where the resistance is proportional to the square of the velocity','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('0d70351a-1995-46da-8eba-3f93dfcbaf84'::uuid,'FLUID DENSITY','MATERIAL','{}','An attribute impacting resistance differently based on whether air or water was used; Newton recognized its variable effect along with velocity and diameter','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('396d5996-c592-4b56-ade3-7698762771dd'::uuid,'TESTS (BY NEWTON, HAUKSBEE, DESAGULIERS)','MODEL','{}','(Experiments) conducted by Newton in St Pauls Cathedral in 1710 and further tests by Hauksbee and later Desaguliers at Eiffel Tower, using various materials like lead weights or air-filled bladders','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('810fb4d6-8b31-41df-ad4b-0a40e1a50e70'::uuid,'HAUKSBEE','PERSON','{}','(Scientist), responsible for conducting the experiments on drop tests under Newton''s presidency of Royal Society','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('54f17f96-c768-47d7-8bae-f2228311ae51'::uuid,'JOHN DESAGULIERS','PERSON','{}','(Scientist) who took over Hauksbee’s position as demonstrator after his death in 1713 and continued experimenting','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('91d49266-06b7-463c-b36a-f3d3f82f0f39'::uuid,'ST PAULS CATHEDRAL','PLACE','{}','(Location) where Hauksbee''s drop tests were conducted under Newton''s supervision','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('a5f614da-6440-4849-ab74-039b59d924b3'::uuid,'LEAD WEIGHTS','COMPONENT','{}','Material used by Desaguliers in his experiments at St. Paul''s, differing from air-filled bladders of earlier tests','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('7c040441-2ec2-497d-a28d-542d05f82d7d'::uuid,'AIR-FILLED BLADDERS','COMPONENT','{}','(Component) that replaced lead weights during early testing phases, filled with air to vary weight and shape in experiments','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('cfbae27b-23f4-4872-9357-b1b56aca3a96'::uuid,'PENAUD (BY BALLOON)','PERSON','{}','(Person) used for testing streamline bodies, focusing on their drag characteristics through observations from a balloon','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('7fbba56f-a3c6-4679-b692-0e60081c91de'::uuid,'DRAG MEASUREMENTS (CAILLETET & COLARDEAU)','MODEL','{}','(Analysis) involving drop tests of up to 120 meters around Eiffel Tower in the late 19th century using sophisticated recording systems','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('67682438-0b09-4823-82d5-e61158b68d49'::uuid,'LEAD WEIGHTS (BY EIFFEL)','COMPONENT','{}','(Component used by Eiffel in his 1902 drop tests to measure the drag of streamlined objects at a height of 300 meters','{}','{}','{"frequency": 2, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f", "8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('339c34fc-6586-4968-a081-b0ea669510a0'::uuid,'BLADDERS FILLED WITH AIR (BY EIFFEL)','COMPONENT','{}','The entity "BLADDERS FILLED WITH AIR (BY EIFFEL)" refers to components designed and tested by Gustave Eiffel for use during high-altitude drag measurements. These bladders, filled with air, were integral parts of Eiffel''s experimental setup conducted in his 1902 investigations. The primary purpose of these devices was to measure the air resistance experienced by objects at high altitudes. Eiffel’s experiments aimed to gather crucial data that could be valuable for various engineering applications, especially those related to aerodynamics and flight dynamics. Through rigorous design and testing processes, Eiffel ensured the reliability and effectiveness of these bladders in providing accurate measurement results during his pioneering research.','{}','{}','{"frequency": 2, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f", "8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('dc6a9c4e-99b7-4049-ba6b-ba3428d0b189'::uuid,'SEPERATED FLOW GENERATING VORTICES','PHENOMENON','{}','(Observation of fluid dynamics where vortices form around blunt bodies, later detailed through drawings','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d6717aa9-90df-4471-8b1f-49ce6a9e4841'::uuid,'VORTEX STREET','PHENOMENON','{}','(Fluid mechanics) observed in the context of separated flows around objects with a leading and trailing edge at different velocities','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3cda5691-9817-486d-b30d-48221e1da12d'::uuid,'STREAMLINED BODY (BY PONCELET)','SHAPE','{}','(Shape of an object designed to reduce fluid resistance), specifically noted for having a thicker trailing region','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a2dab33f-8765-47d1-b8c5-80b75e43b036'::uuid,'DANIEL BERNOULLI','PERSON','{}','(Scientist) who conducted tank flow experiments and confirmed the continuity equation, also measuring reduced pressure with increased velocity','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('08252a05-43b6-41b6-a641-fd97cb1d15d9'::uuid,'CONTINUITY EQUATION','MODEL','{}','(A physical law governing fluid dynamics where mass is conserved within a flow system; confirmed by Daniel Bernoulli to measure pressure variations based on fluid speed changes','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('09f3216a-299f-4da9-83ec-409fa8523648'::uuid,'BALLISTICS (BY ROBINS)','DOMAIN','{}','(Field of study) focused on the motion and effects of cannonball trajectories, leading him to recognize supersonic drag and the Magnus effect in projectiles','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ff6b1319-5104-4ec3-8321-cd501242dd63'::uuid,'MAGNUS EFFECT','PHENOMENON','{}','(Phenomenon observed when a spinning sphere generates lift or drag, originally discovered in ballistics studies but not widely recognized until much later','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('0dc3a131-0952-4a0b-85dc-17a4a8db9446'::uuid,'SUPERSONIC DRAG','PROPERTY','{}','(Drag observed at hypersonic speeds, noted first by Robins but more conclusively documented later','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('565d2e6b-64e4-49f3-a338-7b529278c293'::uuid,'MAGNUS EFFECT (BY ROBINS)','PHENOMENON','{}','(Phenomenon initially recognized in ballistics studies, affecting the trajectory of spinning projectiles and studied further','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ebe1b4ce-d7d2-4121-8094-98a4a9695d35'::uuid,'CAILLETET & COLARDEAU''S DROP TESTS','MODEL','{}','(Experiments) conducted by Cailletet and Colardeau on drag measurements between 1892-1844 using sophisticated recording systems for accuracy','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('0bad6fd2-54d9-448a-8fb5-ab620b152270'::uuid,'DRAG COEFFICIENT','PROPERTY','{}','(Measure of the drag force on an object relative to its size, velocity, and the fluid through which it is moving; a key factor in the resistance mechanism','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('63764b8d-81c4-4215-99da-8d26b46940f5'::uuid,'BOUGUER','PERSON','{}','"Bouguer, who worked between 1746 and possibly later, contributed to the understanding of drag using towed models. He was one of several researchers focusing on this aspect in the 18th century."','{}','{}','{"frequency": 1, "text_unit_ids": ["573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('77d406fd-32a3-4fbd-8593-6d1b680bd8d7'::uuid,'CHAPMAN','PERSON','{}','"Chapman''s work, dated 1768, focused on measuring the drag of ship models using towed methods."','{}','{}','{"frequency": 2, "text_unit_ids": ["573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec", "573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('12b841cd-c596-4e14-ab64-49ad8dadde78'::uuid,'JULIEN','PERSON','{}','"Julien''s work in 1848 involved measuring the drag of streamlined bodies using water tests."','{}','{}','{"frequency": 2, "text_unit_ids": ["573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec", "573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('1accdda6-401f-4651-9ef3-6670cc462028'::uuid,'HERVE-MANGIN & DURAND-CLAYE','GROUP','{}','"This group performed railway train tests on streamlined bodies in 1870, contributing to the understanding of fluid dynamics around aerodynamic shapes."','{}','{}','{"frequency": 2, "text_unit_ids": ["573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec", "573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('2741f8b7-7a0d-4d62-b5ff-ab76e455d1d3'::uuid,'SOREAU & CANOVETTI','GROUP','{}','Soreau and Canovetti''s pioneering research, conducted in 1903, significantly advanced the understanding of air resistance or "drag." By conducting meticulous experiments on streamlined bodies, they were able to build upon existing knowledge in aerodynamics. The pair demonstrated a thorough approach by potentially testing these forms not only through rigorous experimental methods but also under natural wind conditions. These dual methodologies ensured a more comprehensive analysis of the forces at play, contributing valuable insights into the behaviors and characteristics of streamlined shapes as they interact with air flow.','{}','{}','{"frequency": 2, "text_unit_ids": ["573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec", "573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c5b57618-9e14-4f35-9118-519632542f46'::uuid,'WELLINGTON','PERSON','{}','"Wellington''s train tests, conducted in 1878, focused on the accuracy and interference challenges of towed experiments. By testing bodies mounted on a train, he highlighted issues like wake effects that might affect test reliability."','{}','{}','{"frequency": 2, "text_unit_ids": ["573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec", "573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('2e1f23d8-ad96-443e-ac97-702addeac8c6'::uuid,'BAKER','PERSON','{}','"Baker’s research, performed between 1794 (assuming an error) and 1884, was about wind tests on plates, specifically looking into pressure forces on larger surfaces."','{}','{}','{"frequency": 2, "text_unit_ids": ["573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec", "573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('292070e3-ebec-49f6-b36b-be3b92864763'::uuid,'E MACH','PERSON','{}','"Mach''s groundbreaking work photographing supersonic shock waves (1887) was highly influential for post-World War II developments in aerodynamics and fluid dynamics research. It provided direct visual evidence of complex flow behaviors that were crucial for advancements."','{}','{}','{"frequency": 2, "text_unit_ids": ["573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec", "573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('740f6626-c35b-43c9-a29f-c224a7e77f68'::uuid,'STANTON','PERSON','{}','STANTON''s tests conducted at the National Physical Laboratory (NPL) in 1904 utilized natural wind forces over high towers. These experiments demonstrated significant progress towards more accurate outdoor testing methods that can be applied to practical settings such as aircraft design and evaluation. This work laid foundational groundwork for advancements in aerodynamic testing and design, reflecting Stanton''s pivotal role in enhancing the reliability and applicability of outdoor test methodologies during this period.','{}','{}','{"frequency": 2, "text_unit_ids": ["573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec", "573d5db6e587374521f111a47eaa08e2ce573235b08716d91bbe053504fe503530293339ede873a3ac356c3d376fcb97e005ef76112125385fa9e127d8e42fec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9b25365a-6fbd-43ab-b9a3-e8208cd9e7c1'::uuid,'TRAIN WAKE','SYSTEM','{}','A disturbance in air flow caused by a moving train','{}','{}','{"frequency": 1, "text_unit_ids": ["55e473f9ecac8cd67790067e6eab0198e01f4defc514be87f835b5c567883e65d857bb0c55de712e20d7bed24782b9a7ad7f49d93a4ae738a71114a86c61a98d"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('bdf740b6-847f-4866-863c-ac6947a0409c'::uuid,'ELECTRIC CAR AT ST CYR','DEVICE','{}','An electrically driven large wing for aerodynamic testing purposes, used to compare wind tunnel results with free flight conditions and correct predictions on whole aircraft models','{}','{}','{"frequency": 2, "text_unit_ids": ["55e473f9ecac8cd67790067e6eab0198e01f4defc514be87f835b5c567883e65d857bb0c55de712e20d7bed24782b9a7ad7f49d93a4ae738a71114a86c61a98d", "55e473f9ecac8cd67790067e6eab0198e01f4defc514be87f835b5c567883e65d857bb0c55de712e20d7bed24782b9a7ad7f49d93a4ae738a71114a86c61a98d"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b12da279-e1f9-4b36-b990-ffc718159817'::uuid,'DVL (DEUTSCHE VERSUCHSANSTALT FÜR LUFTFAHRT ZU ADLERSHOF)','MODEL','{}','German experimental facility to test forces on aeronautical devices using large wing apparatus mounted on an aerodynamic car propelled by a railway locomotive for the purpose of testing aircraft wings','{}','{}','{"frequency": 2, "text_unit_ids": ["55e473f9ecac8cd67790067e6eab0198e01f4defc514be87f835b5c567883e65d857bb0c55de712e20d7bed24782b9a7ad7f49d93a4ae738a71114a86c61a98d", "55e473f9ecac8cd67790067e6eab0198e01f4defc514be87f835b5c567883e65d857bb0c55de712e20d7bed24782b9a7ad7f49d93a4ae738a71114a86c61a98d"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a2cc95b4-8d58-453b-9c45-f5e9f7235fdc'::uuid,'WING WAKE','SYSTEM','{}','Air disturbance caused by moving surfaces attached to a carriage, initially used at Frankfurt before being developed into more sophisticated designs such as those at DVL and St Cyr','{}','{}','{"frequency": 2, "text_unit_ids": ["55e473f9ecac8cd67790067e6eab0198e01f4defc514be87f835b5c567883e65d857bb0c55de712e20d7bed24782b9a7ad7f49d93a4ae738a71114a86c61a98d", "55e473f9ecac8cd67790067e6eab0198e01f4defc514be87f835b5c567883e65d857bb0c55de712e20d7bed24782b9a7ad7f49d93a4ae738a71114a86c61a98d"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('ec97517b-092e-4231-85da-11d7b03a06c6'::uuid,'SIN2 DEPENDENCE OF LIFT ON INCLINED PLATES','MODEL','{}','A hypothetical relationship where the magnitude of aerodynamic lift is proportional to the square of the sine of the angle of attack of an airfoil, which was later disproved by Borda using his whirling arm method','{}','{}','{"frequency": 2, "text_unit_ids": ["55e473f9ecac8cd67790067e6eab0198e01f4defc514be87f835b5c567883e65d857bb0c55de712e20d7bed24782b9a7ad7f49d93a4ae738a71114a86c61a98d", "55e473f9ecac8cd67790067e6eab0198e01f4defc514be87f835b5c567883e65d857bb0c55de712e20d7bed24782b9a7ad7f49d93a4ae738a71114a86c61a98d"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('1aeb15da-6922-45eb-bf8d-735508a90467'::uuid,'MAJOR VON PARSEVAL''S WORK','PERSON','{}','Responsible for measuring forces on aircraft wings at DVL under direction of the German Society of Mechanical Engineers','{}','{}','{"frequency": 2, "text_unit_ids": ["55e473f9ecac8cd67790067e6eab0198e01f4defc514be87f835b5c567883e65d857bb0c55de712e20d7bed24782b9a7ad7f49d93a4ae738a71114a86c61a98d", "55e473f9ecac8cd67790067e6eab0198e01f4defc514be87f835b5c567883e65d857bb0c55de712e20d7bed24782b9a7ad7f49d93a4ae738a71114a86c61a98d"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('eb924790-7f9d-41f6-b49c-44d35c509f28'::uuid,'ROBINS'' EXPERIMENTS','MODEL','{}','Initial contributions to aerodynamic testing using whirling arms, which later influenced other researchers like Borda and Smeaton','{}','{}','{"frequency": 1, "text_unit_ids": ["55e473f9ecac8cd67790067e6eab0198e01f4defc514be87f835b5c567883e65d857bb0c55de712e20d7bed24782b9a7ad7f49d93a4ae738a71114a86c61a98d"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c8262ade-67e7-440f-9a07-1520c1b0ca0c'::uuid,'ESNAULT PELTERIE''S SETUP','DEVICE','{}','Used a surface attached to an automobile for aerodynamic testing, contributing to the development of more sophisticated test setups like those at DVL and St Cyr','{}','{}','{"frequency": 1, "text_unit_ids": ["55e473f9ecac8cd67790067e6eab0198e01f4defc514be87f835b5c567883e65d857bb0c55de712e20d7bed24782b9a7ad7f49d93a4ae738a71114a86c61a98d"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('199a4f27-cb16-4a0c-8632-327a2699bf9c'::uuid,'ST CYR SYSTEM','SYSTEM','{}','A comprehensive set of tests including electric cars and large wings used for comparing wind tunnel results with free flight conditions','{}','{}','{"frequency": 1, "text_unit_ids": ["55e473f9ecac8cd67790067e6eab0198e01f4defc514be87f835b5c567883e65d857bb0c55de712e20d7bed24782b9a7ad7f49d93a4ae738a71114a86c61a98d"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('fdfdf3c1-ec7a-4675-9a6f-bfb7b60ba28f'::uuid,'NIPHER''S RESEARCH','MODEL','{}','Explored forces on surfaces (plates) in 1902, contributing to the broader understanding of aerodynamic principles','{}','{}','{"frequency": 1, "text_unit_ids": ["55e473f9ecac8cd67790067e6eab0198e01f4defc514be87f835b5c567883e65d857bb0c55de712e20d7bed24782b9a7ad7f49d93a4ae738a71114a86c61a98d"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('62c908c7-4d98-4396-8aef-efa6c8106a3d'::uuid,'WINDMILL','SYSTEM','{}','Mechanical systems designed to convert the energy of moving air into rotational kinetic energy. Smeaton59 tested such devices during early aerodynamic study.','{}','{}','{"frequency": 2, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0", "16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ebc1298f-2242-4b8d-b664-448bdb591c5c'::uuid,'AEROFOIL','COMPONENT','{}','Airfoil-shaped objects meant to generate lift and reduce drag, used in windmill design as well as aerofoil testing on whirling arm','{}','{}','{"frequency": 2, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0", "16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('36767ba4-e252-4a18-a000-b469d1b5bbb3'::uuid,'ARM RADIUS','MATERIAL','{}','parameter of the device describing its size which could be around 1 meter for early apparatuses. Can vary between different test devices like Smeaton''s with a 1m radius and Lilienthal''s 4.3m radius arm.','{}','{}','{"frequency": 1, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('cd837142-89eb-4b77-bc97-88b8fc450f59'::uuid,'TEST OBJECT','COMPONENT','{}','objects placed on or near the whirling arm to measure forces, air resistance, and other mechanical properties in various tests by Hutton, Edgeworth, Vince, Robins, Borda, Cayley, Lilienthal, Atkinson & Dalglish, Chapman, Moy & Jay, Phillips','{}','{}','{"frequency": 1, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('f0d412ef-fe50-478e-9ac7-d90956ae3d39'::uuid,'CENTER OF PRESSURE (CP)','SYSTEM','{}','A measure or region where the air resistance acting on an object is considered to be a single force. In 1879, Moy & Jay59 found forward movement of this parameter in their tests.','{}','{}','{"frequency": 1, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('04bc1d78-66eb-469d-a070-1d19b5446435'::uuid,'ANEMOMETER','DEVICE','{}','Instrument used for measuring wind speed used by Combes, Casartelli, Dalglish, Atkinson, and Wood to calibrate their devices','{}','{}','{"frequency": 1, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9c4b68a8-bb50-4ec2-acd5-2093644c16e2'::uuid,'FLAT PLATE AEROFOIL','COMPONENT','{}','A thin wing-like structure designed primarily as a flat plate tested by Cayley59 in 1804 on the whirling arm. Used to observe lift force with angle of attack','{}','{}','{"frequency": 1, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c8e89021-ee97-4935-a424-6232ee626c62'::uuid,'LIVE BIRDS','COMPONENT','{}','Real organisms used as part of biological testing in flight force measurements, specifically by Marey44','{}','{}','{"frequency": 1, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('45e071dc-8853-452c-ac35-7bffb2bce7dc'::uuid,'TEST SURFACES','COMPONENT','{}','Objects attached to or tested on both ends of the whirling arm for evaluating lift performance. Lilienthal36,59 used these in his tests.','{}','{}','{"frequency": 1, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('dd72532a-42d1-4301-891c-7e8fe00fd539'::uuid,'FRICTION AND ARM RESISTANCE','MODEL','{}','Variables measured along with forces during windmill arms rotation to improve understanding of aerodynamic and mechanical aspects. Montgomery36 included it in his 1885 study','{}','{}','{"frequency": 1, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('8568ca85-1a88-41ba-ba5a-97cb6e5986ad'::uuid,'AEROFOIL LIFT PERFORMANCE','SYSTEM','{}','A measure or set of tests conducted on curved surfaces versus flat plates, where Montgomery found that curved surfaces performed more effectively.','{}','{}','{"frequency": 1, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('57d58bdf-3140-4967-a9a0-6904e48ea974'::uuid,'ADIABATIC COMPRESSION','MECHANISM','{}','Adiabatic compression occurs when air flow passes through a changing cross-section.','{}','{}','{"frequency": 1, "text_unit_ids": ["2d9fdd18fbb30369988222506fc6af76775a9970c876b024d039f1156ef34f3f17266c64951a1221502b45b881305de03ffdda41d4d7de0a29ea5d1a8aa25ad3"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('6229e85e-fd90-4af7-a125-ccc148ed3d13'::uuid,'SIN Α DEPENDENCE FOR LIFT FORCE','MODEL','{}','A hypothesis supported by results from Ackroyd9 and later studies suggesting a linear relationship between lift force and angle of attack.','{}','{}','{"frequency": 1, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('1910c518-2107-4e5c-8e1f-16fb37dc92c8'::uuid,'WEIGHT DRIVEN WHIRLING ARMS','SYSTEM','{}','Mechanisms employing weights for generating rotational force on the whirling arm, also seen in the works of Combes and others mentioned.','{}','{}','{"frequency": 1, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('c70d0b16-0617-4892-adf7-d3fab502429e'::uuid,'STEAM POWERED WHIRLING ARM','DEVICE','{}','A steam-powered mechanism suggested to be invented by Phillips59, possibly larger in scale than previous test devices used in earlier studies.','{}','{}','{"frequency": 1, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('87d7a02b-00e4-46e4-801a-27ff22993ad1'::uuid,'AIR FLOW PATTERNS','MODEL','{}','Patterns observed during the rotation of air over an object tested on whirling arms like circular or parallel flows. Relevant to the early limitations noted by Smeaton and Hutton et al.','{}','{}','{"frequency": 1, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3fba037e-a90c-4e38-9c7d-0b7f03281098'::uuid,'FORCE MEASUREMENT','SYSTEM','{}','Procedure for quantifying effects of wind, lift, drag, torque etc., executed using different apparatus from whirling arm methods to live bird studies','{}','{}','{"frequency": 1, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('cbe7c36f-80c3-4784-914d-cb5702bad00f'::uuid,'MONTGOMERY36','SYSTEM','{}','Montgomery conducted an investigation on curved lifting surfaces in 1885','{}','{}','{"frequency": 1, "text_unit_ids": ["aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('0eb3acc9-bb1a-4397-8b42-ea8862819013'::uuid,'ARM OF 3.3 M RADIUS','PART','{}','A device with a 3.3 meter arm for investigating lift performance','{}','{}','{"frequency": 2, "text_unit_ids": ["aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab", "aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e67c583e-03e5-4262-a9f8-a3c403c2e617'::uuid,'PHILLIPS59','SYSTEM','{}','Phillips built two large steam-powered whirling arms to confirm wind tunnel test results in the same year as Montgomery''s investigation','{}','{}','{"frequency": 2, "text_unit_ids": ["aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab", "aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('645be747-36c2-4343-acf6-6b4e19e32d8b'::uuid,'15.2 M RADIUS STEAM POWERED WHIRLING ARM','DEVICE','{}','The largest whirling arm of Phillips, measuring various wing configurations and producing better lift than flat plates','{}','{}','{"frequency": 2, "text_unit_ids": ["aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab", "aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9f008e9e-6995-4c88-afaf-c6b832e03629'::uuid,'TWIN MULTIPLANE FLIGHT ATTEMPTS IN 1893 AND SUCCESSFULLY IN 1905','MODEL','{}','Phillips used test results to attempt flight, achieving success by 1905','{}','{}','{"frequency": 1, "text_unit_ids": ["aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('31996ed9-e1ed-4db7-a2de-c9ee414b7e0d'::uuid,'LARGE STEAM POWERED WHIRLING ARM WITH PROPELLER SYSTEM NEAR THE MEASURED OBJECT','DEVICE','{}','Maxim''s whirling arm had a propeller or anemometer causing flow disturbance','{}','{}','{"frequency": 2, "text_unit_ids": ["aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab", "aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('174922a7-b28e-457a-9727-d07eab338b23'::uuid,'DINES60','SYSTEM','{}','Meteorologist Dines used a large 8.5 m radius steam-powered and governed whirling arm in 1889 to measure various shaped plates','{}','{}','{"frequency": 2, "text_unit_ids": ["aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab", "aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('b77234bb-ae86-44a1-bf89-83533b78ac4e'::uuid,'LANGLEY39','MODEL','{}','Langley built a large whirling arm of 9.25 m radius with sophisticated force balances for assessing his flying machine designs in 1890, reaching speeds up to 45 m/s indoors','{}','{}','{"frequency": 2, "text_unit_ids": ["aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab", "aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('44994cb9-47a4-4fc9-a791-a68929321ede'::uuid,'CONSERVATION LAWS','SYSTEM','{}','Foundation for mathematical models, including conservation of energy, momentum, and angular momentum along with the continuity equation','{}','{}','{"frequency": 1, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('d9bc7dff-77f5-4b3e-aee7-5143a4b1a069'::uuid,'MASS CONSERVATION LAW','MODEL','{}','Expressed through the continuity equation, which ensures that the inflow of fluid or gas is compensated by a change in density within a fixed volume','{}','{}','{"frequency": 1, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('e83df063-3c03-46da-ba1a-c7081226a3ce'::uuid,'SMALL CHEAP WHIRLING TABLE FROM GAS BARREL','COMPONENT','{}','Thurston at East London College constructed a small, inexpensive whirling table using a gas barrel around 1912','{}','{}','{"frequency": 2, "text_unit_ids": ["aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab", "aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ba7f0561-6cb7-4d65-9329-d4ab6bcf46eb'::uuid,'TWIN MULTIPLANE FLIGHT ATTEMPTS IN 1893 AND SUCCESSFULLY IN 1890, THEN 1905','MODEL','{}','Phillips used test results to attempt flight, achieving success by 1905','{}','{}','{"frequency": 1, "text_unit_ids": ["aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('af2c8298-cb9b-4495-8a39-781c2ea3e340'::uuid,'LINEAR TRACK CARS','DEVICE','{}','Linear track cars were machines built to run on linear tracks in order to obtain full-scale results of experiments','{}','{}','{"frequency": 2, "text_unit_ids": ["653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc", "653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f4167ad7-e0c7-489e-9afa-06a0d721166d'::uuid,'VICKERS APPARATUS','SYSTEM','{}','The Vickers apparatus was one among the early whirling arm devices used for aerodynamic testing','{}','{}','{"frequency": 2, "text_unit_ids": ["653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc", "653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b1376e69-f87a-4a46-8e4e-ffe7403e0b37'::uuid,'ST CYR ESTABLISHMENT','SYSTEM','{}','St Cyr established a whirling arm device after the Vickers apparatus but it appears to have been little-used compared with linear track cars invested in by other establishments','{}','{}','{"frequency": 2, "text_unit_ids": ["653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc", "653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d3f4d83c-a7e0-47b2-a901-fa69f884aa38'::uuid,'BERLIN ESTABLISHMENT','SYSTEM','{}','The Berlin establishment also built a whirling arm device after the Vickers apparatus, and like St Cyr, it was not heavily utilized due to investments in linear track cars at those locations','{}','{}','{"frequency": 2, "text_unit_ids": ["653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc", "653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('67455c79-03cd-4002-992d-6c85c5c76f03'::uuid,'HOT WIRE ANEMOMETRY','MECHANISM','{}','A hot-wire anemometer is used for calibrating velocity measurements in aerodynamics testing','{}','{}','{"frequency": 2, "text_unit_ids": ["653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc", "653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('199a2165-89cf-476f-b4a9-825d5c17359b'::uuid,'DYNAMIC MODEL','MODEL','{}','These are models created to test dynamic characteristics, which were investigated using whirling arms after the second world war','{}','{}','{"frequency": 2, "text_unit_ids": ["653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc", "653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('8cd9463f-8098-473d-baf3-e17f0bc1750f'::uuid,'STABILITY DERIVATIVES','COMPONENT','{}','Stability derivatives are derived from measurements taken on models in testing and pertain to an aircraft''s aerodynamic stability','{}','{}','{"frequency": 2, "text_unit_ids": ["653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc", "653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('1f5186a1-1487-4d87-9616-b5feb6f25635'::uuid,'MAREY, EIFFEL, AND PRANDTL TUNNELS','DEVICE','{}','Early pioneers in the design of more advanced wind tunnels with improved flow characteristics, particularly in terms of low turbulence','{}','{}','{"frequency": 2, "text_unit_ids": ["653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc", "653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e20effd0-d626-4b96-85fa-39735da78dd4'::uuid,'SETTLING CHAMBER WITH SCREENS','COMPONENT','{}','These are parts used in modern turbines to reduce turbulence','{}','{}','{"frequency": 2, "text_unit_ids": ["653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc", "653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('308fef04-b04b-4661-a421-d9d819415e6c'::uuid,'SHARP ENTRANCE LEADING EDGE','COMPONENT','{}','"SHARP ENTRANCE LEADING EDGE" refers to a notable feature in early wind tunnel designs. These leading edges, characterized by their sharpness, induced significant flow separation issues during testing. This caused substantial complexities and the need for long settling lengths before accurate measurements could be obtained. The entry points of these wind tunnels were prone to generating flow separation due to their geometry, making initial model testing unreliable until adequate settling had occurred. This characteristic was a common challenge faced by engineers as they refined early models to achieve more precise and efficient testing conditions in wind tunnel environments.','{}','{}','{"frequency": 2, "text_unit_ids": ["653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc", "653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('652b76db-3c32-4620-99d3-a990ee0bbd8e'::uuid,'WIND CHANNELS','SYSTEM','{}','An alternative term for earlier forms of aerodynamic testing devices similar to modern wind tunnels but often less equipped with sophisticated control systems','{}','{}','{"frequency": 1, "text_unit_ids": ["653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('beb504fd-26ab-4689-9f91-fba11d596c9f'::uuid,'FREE AIR FLOW','SYSTEM','{}','Representing free air flow requires applying corrections to results in wind tunnels, as recognized by Prandtl','{}','{}','{"frequency": 1, "text_unit_ids": ["0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('eddf1a2e-79a3-4e52-bd2e-efbe26e646dd'::uuid,'SMOOTHING RETURN FLOW','MECHANISM','{}','Adjustment process to mitigate disturbances induced by the return flow mechanism in wind tunnels','{}','{}','{"frequency": 2, "text_unit_ids": ["0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602", "0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('1154d484-5fe2-4f28-a53e-dc3cc5d7c2a5'::uuid,'CLOSED RETURN (CR) TUNNELS','SYSTEM','{}','Type of tunnel design that uses confined return flow from the working section to maintain uniform airflow, requiring less power to achieve desired airspeeds','{}','{}','{"frequency": 2, "text_unit_ids": ["0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602", "0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f1488d81-5988-4a3d-88a6-ed0f85175215'::uuid,'OPEN RETURN (STRAIGHT THROUGH FLOW) (OR) TUNNELS','SYSTEM','{}','Another type of wind tunnel design where return flow is direct and open, potentially leading to faster and uneven airflow without constraints from tunnel walls','{}','{}','{"frequency": 2, "text_unit_ids": ["0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602", "0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('e326c184-d20c-4ce2-b244-f1eb3fe1841f'::uuid,'SHARP ENTRANCES IN WIND TUNNELS','COMPONENT','{}','"SHARP ENTRANCES IN WIND TUNNELS" were early designs typically marked by abrupt entry points. These designs frequently led to the formation of separation bubbles, regions where air flow was disrupted and no longer remained uniformly laminar. To ensure more consistent airflow within the tunnel, which is crucial for accurate testing and analysis in aerodynamics, these initial configurations required additional length or longer tunnels compared to later, more refined entries.','{}','{}','{"frequency": 2, "text_unit_ids": ["0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602", "0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6e4217bb-59d5-4a53-af05-fd26bbff36e8'::uuid,'SEPARATION BUBBLES','SYSTEM','{}','Areas of fluid flow where the air detaches from the walls at sharp entrances, forming unstable zones that require additional tunnel length for uniform velocity distribution','{}','{}','{"frequency": 2, "text_unit_ids": ["0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602", "0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ec8d85cb-eba4-4d3f-93cc-80af534fdc0d'::uuid,'OPEN WORKING SECTIONS IN WIND TUNNELS','SYSTEM','{}','Designs characterized by the lack of tunnel walls within the working section, leading to less constrained and potentially more turbulent flows compared to closed sections','{}','{}','{"frequency": 2, "text_unit_ids": ["0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602", "0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('548f5405-3196-4f17-93cf-ee4bc9a37436'::uuid,'CLOSED WORKING SECTIONS IN WIND TUNNELS','SYSTEM','{}','Tunnel configurations with boundary walls that significantly impact lift and drag measurements due to modified airflow patterns','{}','{}','{"frequency": 2, "text_unit_ids": ["0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602", "0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3f222cc4-79e0-44e3-abe7-f9cde180fb60'::uuid,'SMOKE VISUALISATION TUNNEL OF ETIENNE MAREY','DEVICE','{}','A low-speed wind tunnel specifically designed for visualizing airflows using smoke, offering theoretical insights without the influence of fan swirl or other mechanical effects','{}','{}','{"frequency": 2, "text_unit_ids": ["0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602", "0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5f5ebf5e-abaa-46d5-9cb2-fb24dd29f1fc'::uuid,'SCREEN TURBULENCE REDUCTION IN EARLY WIND TUNNELS','MECHANISM','{}','Devices used to reduce turbulent flow within wind tunnels before advancements in screen technology became common','{}','{}','{"frequency": 2, "text_unit_ids": ["0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602", "0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('2d618455-52b0-4ea5-8acd-9400be6f3550'::uuid,'FRANCIS WENHAM''S WIND TUNNEL','DEVICE','{}','One of the earliest recognized designs catalogued by earlier authors, claimed as the first by some but later evidence suggests earlier contemporaries (Sir Henry Hussey-Vivian and others) also built similar wind tunnel devices in the late 19th century','{}','{}','{"frequency": 2, "text_unit_ids": ["0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602", "0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('519b94f7-21cb-492c-b5bc-1abf7ea177e7'::uuid,'WIND CHANNEL TUBE IN FRANCIS WENHAM''S TUNNEL','COMPONENT','{}','A fundamental part of Wenham’s design, a long vertical wooden tube used to create airflows for testing','{}','{}','{"frequency": 2, "text_unit_ids": ["0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602", "0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('cf90320b-efd0-4652-a9f7-a8355981bbb4'::uuid,'BLAST PIPE IN FRANCIS WENHAM''S WIND TUNNEL','COMPONENT','{}','Component attached to the upper end of the wind channel tube providing a means to introduce high-pressure air into the system','{}','{}','{"frequency": 2, "text_unit_ids": ["0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602", "0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('1cdefdac-7bba-404f-b25d-a701ef6625c3'::uuid,'STEAM PIPE INDUCING FLOW IN FRANCIS WENHAM''S WIND TUNNEL','SYSTEM','{}','A critical component used to further enhance airflow within the tunnel, connecting to a Cornish boiler for added pressure or velocity control','{}','{}','{"frequency": 2, "text_unit_ids": ["0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602", "0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('694e17b4-abc1-48b0-99d0-aad7d965dd14'::uuid,'61 M SQUARE OPEN AT BOTH ENDS','SYSTEM','{}','\The system is a tunnel with an 61-meter-square cross-sectional area that is open at its upper and lower ends, used to study flow characteristics within it.','{}','{}','{"frequency": 1, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3a73faaa-2c21-454e-9c24-1886a8767ff2'::uuid,'CORNISH BOILER','DEVICE','{}','\The apparatus that provided steam to induce flow into the anemometer by connecting it via a blast pipe and steam pipe with a diameter of 0.23 meters, situated around the upper closure of the device','{}','{}','{"frequency": 2, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78", "4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('4d9ca007-b750-4de7-8be7-699a1cea7f09'::uuid,'BIRAM ANEMOMETER','COMPONENT','{}','\A component in the box used for measuring velocity or wind speed within the tunnel.','{}','{}','{"frequency": 2, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78", "4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('cd06b54b-8071-4f1c-9b3b-a982b605cea9'::uuid,'FLOW CONTROL SLIDERS','COMPONENT','{}','\Components within the system that control and modulate the flow of air as it passes through the tunnel, influencing measurements taken by the anemometer.','{}','{}','{"frequency": 2, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78", "4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('0022fa87-f86d-44a2-b131-e4cadd6d8ff0'::uuid,'SHARP FLOW INLET','PART','{}','\An element in the device that causes air to sharply accelerate as it enters the main section of the wind tunnel, affecting flow conditions within the system.','{}','{}','{"frequency": 2, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78", "4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('8b8c07b0-a467-430e-9d94-efad9a1085f3'::uuid,'STEAM INJECTOR','DEVICE','{}','\A component or mechanism used to introduce steam into the tunnel''s working section and return flow, likely located downstream from the sharp inlet to manage flows effectively.','{}','{}','{"frequency": 2, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78", "4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('23c3e9f8-deae-4de9-88f2-49a749326313'::uuid,'F.H. WENHAM WIND TUNNEL','SYSTEM','{}','\The wind test equipment produced by Wenham at the request of and funding from the Aeronautical Society in England in 1870 and constructed by John Browning at Greenwich. This system was utilized to measure aerodynamic forces on planar surfaces.','{}','{}','{"frequency": 2, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78", "4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f1ec9897-67a9-4c91-a16e-a5c993f802d8'::uuid,'STEAM ENGINE-DRIVEN FAN','DEVICE','{}','\A component used within the wind tunnel for driving air through it, powered by a steam engine.','{}','{}','{"frequency": 2, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78", "4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5bed106f-a416-46b1-bfa4-00efdc544856'::uuid,'BLOW DOWN TUNNEL','SYSTEM','{}','\A type of wind tunnel with an open working section and return flow region that does not have a closed boundary, described in the passage as being smaller than previous tunnels but capable of achieving velocities up to 18 meters per second at its test surface.','{}','{}','{"frequency": 2, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78", "4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5ae02dc7-12ed-4aa7-bf87-eb96fce94751'::uuid,'TEST AEROFOIL SURFACES','COMPONENT','{}','\The surfaces within the tunnel designed to be subjected to air flow for measuring lift and drag forces on planes, limited in approach angle beyond 15 degrees from the flow direction in Wenham''s design.','{}','{}','{"frequency": 2, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78", "4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('24017510-357b-429e-93b2-c24953b949fd'::uuid,'JOHN BROWNING','PERSON','{}','\The constructor of the F.H. Wenham Wind Tunnel at Greenwich.','{}','{}','{"frequency": 1, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('28026c53-fab7-437e-9023-37f765d4be83'::uuid,'GREENWICH','LOCATION','{}','\The location where John Browning built the F.H. Wenham Wind Tunnel.','{}','{}','{"frequency": 1, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('45284614-8904-4c1b-8831-bee8bae91fbf'::uuid,'AERONAUTICAL SOCIETY','ORGANIZATION','{}','\The body that funded and requested the creation of the F.H. Wenham Wind Tunnel.','{}','{}','{"frequency": 1, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('544014f5-0d0f-42de-ab88-2db453be139f'::uuid,'STEVE W.R. LONGRIDGE7313','PERSON','{}','\Author or referent of the Longridge configuration described in the passage, possibly a historical figure contributing to wind tunnel design advancements.','{}','{}','{"frequency": 1, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('0fa733c6-c8eb-4b73-86de-f1a6375a2737'::uuid,'GLIDER EXPERIMENTS','ACTIVITY','{}','\Experiments by Wenham that led to initial observations on the aerodynamic properties of cambered surfaces and leading edge lift mechanisms.','{}','{}','{"frequency": 1, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d8b8ff2f-20f4-4001-8bf2-6219404eedbd'::uuid,'CAMBERED SURFACES','COMPONENT','{}','\Aerofoil shapes with a curved top surface and flat bottom used to observe higher lift compared to plain plates according to Wenham''s observations.','{}','{}','{"frequency": 1, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('23f2d200-d028-4b73-ac08-0e2ece0e9a1e'::uuid,'FLAT PLATES','DEVICE','{}','Flat plates are the primary components under discussion, which were compared against aerofoils for their lift characteristics.','{}','{}','{"frequency": 1, "text_unit_ids": ["6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('dd755730-1c6a-44a7-85f4-571df2f01e94'::uuid,'V.A. PASHKEVITCH76,','COMPONENT','{}','The first wind tunnel constructed by V.A. Pashkevitch at the Mikhailov military academy in 1871, characterized as rectangular in section, used for measuring drag of projectiles without an anemometer but with a force balance.','{}','{}','{"frequency": 1, "text_unit_ids": ["6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('52af2fcb-a35a-4cf4-ae9c-6de2f8de1cc6'::uuid,'3-METER DIAMETER WIND CHANNEL','SYSTEM','{}','The 3-meter diameter wind channel was first described in 1874 by French engineers Auguste de Louvrie and Jules Armagard. This simple device was designed for testing surfaces exposed to wind conditions within the three-meter diameter wind tunnel. Essentially, it comprised just a fan and a cylindrical tube, which together facilitated controlled airflow necessary for experimentation purposes. The primary function of this setup was to simulate various wind scenarios on test surfaces, thereby providing valuable data for researchers and engineers working in aerodynamics and related fields. This early design laid the foundational principles for modern wind channel testing techniques.','{}','{}','{"frequency": 3, "text_unit_ids": ["6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa", "6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa", "6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('8249f7ac-d5bd-4ca2-aa39-73bd34240e16'::uuid,'H.F. PHILLIPS','SYSTEM','{}','H.F. Phillips built a closed working section wind tunnel in 1885 to test flat and cambered surfaces, measuring lift and drag using a simple mechanical balance and showing that camber significantly improved lift but also increased drag.','{}','{}','{"frequency": 1, "text_unit_ids": ["6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('e7556eb7-e099-416b-ab6e-889dbf0b96a2'::uuid,'MONTGOMERY25','SYSTEM','{}','Montgomery constructed a smoke/water tunnel to observe flow over simple aerofoils with a closed section and suck-down flow in 1891, not connected directly to the more rigid wind tunnels but still used for aerodynamic testing.','{}','{}','{"frequency": 1, "text_unit_ids": ["6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('84a28cf7-0e19-4f4c-9b40-0bd4c9306117'::uuid,'KERNOT78','SYSTEM','{}','Professor Kernot built a simple blowdown wind tunnel in 1893 driven by a fan/propeller for basic aerodynamic testing, a straightforward yet effective design.','{}','{}','{"frequency": 1, "text_unit_ids": ["6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('edad204c-6d58-4abe-ad0d-fb77ae05cc73'::uuid,'LEAD EDGE PART OF THE AEROFOIL','PART','{}','Part specifically responsible for generating most of the lift in an aerofoil.','{}','{}','{"frequency": 2, "text_unit_ids": ["6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa", "6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a32f4da6-8474-4311-a893-02dac8eaf5b1'::uuid,'V.A. PASHKEVITCH76','PERSON','{}','Person who constructed a rectangular section wind tunnel in 1871 for measuring the drag of projectiles using a force balance system.','{}','{}','{"frequency": 2, "text_unit_ids": ["6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa", "6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('53c2c7c2-12b6-40f0-9dd3-6890ed2b85f7'::uuid,'H.F. PHILLIPS77','PERSON','{}','Person who built a 0.25 by 0.43 m closed working section wind tunnel in 1885, using steam injection for testing lift and drag with a simple mechanical balance.','{}','{}','{"frequency": 2, "text_unit_ids": ["6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa", "6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6a908d67-07f8-4274-897f-cf717e197279'::uuid,'AEROFOLIA','DEVICE','{}','Devices around which air forces are measured','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d7ee9dd4-f02d-4e57-b4ff-9baee07ad2f3'::uuid,'FAN/','COMPONENT','{}','Fan component of Kernot78''s tunnel, which was driven by a gas engine.','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('92d1e4d0-7c1e-439d-83e8-94d71d85fad6'::uuid,'PROPELLER/','MECHANISM','{}','Propeller as part of the drive mechanism for the fan in Kernot78’s tunnel. It is driven by a gas engine.','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e9372263-31b4-45e4-b688-111b10c43128'::uuid,'GAS ENGINE/','COMPONENT','{}','Gas engine used to drive the fan and propeller in Kernot78''s 1893 blowdown tunnel.','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c5931653-d72b-4cac-84f4-c7184db7c213'::uuid,'ASYMMETRIC IRREGULAR SHAPE DUCT/','MECHANISM','{}','Irregular-shaped duct through which a circular axial flow was turned at a right angle, then converged to a higher velocity square jet in Kernot78''s experiment.<|','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('1ed49d66-c9a8-4fe2-be05-691955af8201'::uuid,'MACH42 TUNNEL','SYSTEM','{}','1893 small closed channel built by Ludwig Mach with dimensions 0.18 x 0.25 m, using a fan for flow visualization.<|','{}','{}','{"frequency": 2, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99", "9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b7035782-8f01-4c5a-952b-09f5aa71fe68'::uuid,'CHIMNEY DRAFT SUCTION/','MECHANISM','{}','Suction force used in the tunnel created by Irminger and Vogt in Denmark to investigate airflow around buildings from 1894-1895. The suction was generated by a powerhouse chimney draft.<|','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('0974e782-4b6f-431d-b37c-adae69f3b192'::uuid,'POWERHOUSE CHIMNEYS/','MECHANISM','{}','Source of suction for the tunnel built in Denmark in 1895, driven by a chimney draft from a powerful house.<|','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('542d8de3-a8c3-4a9c-8d5e-6488613e20b3'::uuid,'IMA MAXIM SPORE TUNNEL','SYSTEM','{}','Large blowdown tunnel constructed by Hiram Maxim in 1896 with dimensions 0.91 x 0.91 m and featuring measurements on aerofoils, bodies, and cascades for evaluation of forces on his aeroplane.<|','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('60fcf249-686e-427b-b20e-33f835a7d6c8'::uuid,'FAN IN MAXIM SPORE TUNNEL/','COMPONENT','{}','Fan-driven by a belt attached to a steam engine which obtained high velocities in Maxim’s 1896 blowdown tunnel. It had limitations due to insufficient vanes and lack of settling chambers.<|','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('4b66586b-3547-46a8-9be1-bd801c7bb213'::uuid,'STEAM ENGINE IN MAXIM SPORE TUNNEL/','COMPONENT','{}','Steam engine used to drive the fan in Hiram Maxim''s large wind channel of 1896 for aerodynamic measurements on aerofoils, bodies and cascades.<|','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('89377293-fba0-4c10-870c-275ffa446739'::uuid,'WELLS80 TUNNEL/','SYSTEM','{}','A wind tunnel built around 1896 in the USA not providing further details on its specific configuration or measurements conducted. It is mentioned only in passing compared to others described here.<|','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a5c51b33-2b27-4a1e-93ce-ae2fc583fc91'::uuid,'GAS ENGINE','COMPONENT','{}','Gas engine used to drive the fan and propeller in Kernot78''s 1893 blowdown tunnel.<|','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('33cbd6b1-20da-4aed-aa0e-e77d2ea01618'::uuid,'CHIMNEY DRAFT SUCTION','MECHANISM','{}','Suction force used in the tunnel created by Irminger and Vogt in Denmark to investigate airflow around buildings from 1894-1895. The suction was generated by a powerhouse chimney draft.<|','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('bb337cae-1271-4ebc-ad52-83f75c8647c2'::uuid,'POWERHOUSE CHIMNEYS','MECHANISM','{}','Source of suction for the tunnel built in Denmark in 1895, driven by a chimney draft from a powerful house.<|','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('9e922be4-5e31-47c3-9a70-bb884ba2d298'::uuid,'FAN IN MAXIMS TUNNEL','COMPONENT','{}','Fan-driven by a belt attached to a steam engine which obtained high velocities in Maxim’s 1896 blowdown tunnel. It had limitations due to insufficient vanes and lack of settling chambers.<|','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3b748fed-984c-47d9-a7d6-e747a6cd27ba'::uuid,'STEAM ENGINE IN MAXIMS TUNNEL','COMPONENT','{}','Steam engine used to drive the fan in Hiram Maxim''s large wind channel of 1896 for aerodynamic measurements on aerofoils, bodies and cascades.<|','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('7da85619-6226-4f46-8669-e5279a9057ab'::uuid,'RENARD69 AIRSHIP TUNNEL','SYSTEM','{}','A smaller tunnel built by Renard in 1896 with a diameter of 0.81 meters to measure air drag for airships. The flow was reported to be poor due to lack of effort in improving it.<|','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f66d9a61-fb55-47f6-81b4-9944bba13ab0'::uuid,'WELLS80 TUNNEL','SYSTEM','{}','A wind tunnel built around 1896 in the USA, though with limited details provided on its specific configuration or measurements conducted. Mentioned only in passing compared to others described here.<|','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f103eb6d-ed51-4360-8352-84dcf898dbf7'::uuid,'BLAST WINDT UNNEL','SYSTEM','{}','Wind tunnel 1x0.95 meter built by Wells in 1896 at MIT using ventilation system for air supply; measured forces on flat plates, confirmed Smeaton coefficient''s incorrectness, poor performance due to lack of systematic effort','{}','{}','{"frequency": 2, "text_unit_ids": ["427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe", "427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('4551c842-2d90-4b5b-aacd-7667544fea2c'::uuid,'METALIC AIRSH IIP','DEVICE','{}','Large metallic airship designed by Russian pioneer Konstantin Tsiolkovsky in 1896 for computing power requirements; had wind tunnel with open working section and a weight-driven fan, operated for only 11 seconds','{}','{}','{"frequency": 1, "text_unit_ids": ["427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('88a1fe34-d5c8-4cae-9a19-1fc66c52bf50'::uuid,'PAP ER MODELS','MATERIAL','{}','Models used in measurements of the wind tunnel designed by Konstantin Tsiolkovsky in 1896, made of paper','{}','{}','{"frequency": 2, "text_unit_ids": ["427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe", "427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a2a25198-77fc-40ef-85c1-3035c9e81d76'::uuid,'DRA G COEFFICIENT','MODEL','{}','Drag coefficient value claimed for spheres by 1899, initially estimated as 0.5 and later more systematic methods developed','{}','{}','{"frequency": 2, "text_unit_ids": ["427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe", "427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b9729f3a-242f-4749-93eb-834e7ca4b131'::uuid,'BL OW D WINDT UNNEL','SYSTEM','{}','Blower tunnel constructed by Konstantin Tsiolkovsky in 1899 with a larger open working section, claimed to have better drag coefficient measurements but still had issues like lack of settling chamber and flow straighteners','{}','{}','{"frequency": 2, "text_unit_ids": ["427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe", "427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f80bc56f-f5e2-4437-b296-485e68bb872c'::uuid,'BLOW FAN FOR WORKING SECTION','PART','{}','Fan used for the working section of Konstantin Tsiolkovsky''s 1899 wind tunnel, powered by a weight-driven mechanism','{}','{}','{"frequency": 2, "text_unit_ids": ["427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe", "427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('e6c39480-3f39-44f8-873c-73904e88e9e5'::uuid,'SETTL NG CHAMBER','DEVICE','{}','Absence of this device in the mentioned wind tunnels was noted as an issue affecting flow stability','{}','{}','{"frequency": 2, "text_unit_ids": ["427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe", "427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5e227601-284f-497f-81b8-e774068405bb'::uuid,'DANISH W IND TUNNELS','SYSTEM','{}','Two tunnels constructed in Denmark with diameters of 50 cm and 1 m capable of 10 meters per second velocity by P. LaCour, used for work on windmills','{}','{}','{"frequency": 2, "text_unit_ids": ["427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe", "427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('8053e699-4a0a-4854-b2bd-53fb86f1fc54'::uuid,'CHRONOPHOTOGRAPHY INVENTIONS OF ETIENNE-JULES M AREY','SYSTEM','{}','Inventions made in 1899 and 1900 by Marey to visualize streamline flows, separated flows for research, showing many new phenomena for the first time','{}','{}','{"frequency": 2, "text_unit_ids": ["427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe", "427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5867343d-56ac-4281-a6aa-2edd0f6f50d2'::uuid,'CHRONOPHOTOGRAPHY CHANNELS BY ETIENNE-JULES M AREY','SYSTEM','{}','Channels built in 1899 and 1900 to visualize streamline and separated flows by Marey, significant for researching aerodynamics and fluid dynamics','{}','{}','{"frequency": 2, "text_unit_ids": ["427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe", "427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('27e2f17f-f349-4194-bb76-04ca8a707bd1'::uuid,'METALIC AIRSHIP','DEVICE','{}','Large metallic airship designed by Russian pioneer Konstantin Tsiolkovsky in 1896 for computing power requirements; had wind tunnel with open working section and a weight-driven fan, operated for only 11 seconds','{}','{}','{"frequency": 1, "text_unit_ids": ["427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('55966e4d-73e7-4840-9183-2d8672743def'::uuid,'ZHKOVSKY STRAIGHT SQUARE SECTION W INDT UNNEL','SYSTEM','{}','Zhukovsky''s square section tunnel with windows created in 1902, designed to enhance visual observation capabilities for researchers','{}','{}','{"frequency": 1, "text_unit_ids": ["427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d048d299-143c-477e-a9f4-fffe79ea1ddd'::uuid,'ZAHM WIND TUNNEL','DEVICE','{}','A large wind tunnel, 1.83 m square, built by Zahm at the USA, featuring a suction fan and electric motor of 8.95 kW for measuring skin friction and forces on wings and airship hulls','{}','{}','{"frequency": 2, "text_unit_ids": ["af0b7dc953d20f99423204bc6976714fb8bc794b04cf5ce8101cfceef20985a957bc6eca2691ec075aaa01420b302e2b2b0c8d5a5c0d508a6dabb65c91d84d5a", "af0b7dc953d20f99423204bc6976714fb8bc794b04cf5ce8101cfceef20985a957bc6eca2691ec075aaa01420b302e2b2b0c8d5a5c0d508a6dabb65c91d84d5a"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('45186177-ad93-455a-9ee4-5f619d18c306'::uuid,'HONEYCOMB STRUCTURE','MATERIAL','{}','Component used in the construction of the large wind tunnel with dense screens to smooth flow','{}','{}','{"frequency": 2, "text_unit_ids": ["af0b7dc953d20f99423204bc6976714fb8bc794b04cf5ce8101cfceef20985a957bc6eca2691ec075aaa01420b302e2b2b0c8d5a5c0d508a6dabb65c91d84d5a", "af0b7dc953d20f99423204bc6976714fb8bc794b04cf5ce8101cfceef20985a957bc6eca2691ec075aaa01420b302e2b2b0c8d5a5c0d508a6dabb65c91d84d5a"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('286b3463-7c13-485a-870f-66eed1b6d075'::uuid,'SCREWED DIVERGENT DUCT','COMPONENT','{}','A duct that leads from the fan, seen in half-scale models but not clearly visible in full-size tunnel photographs','{}','{}','{"frequency": 2, "text_unit_ids": ["af0b7dc953d20f99423204bc6976714fb8bc794b04cf5ce8101cfceef20985a957bc6eca2691ec075aaa01420b302e2b2b0c8d5a5c0d508a6dabb65c91d84d5a", "af0b7dc953d20f99423204bc6976714fb8bc794b04cf5ce8101cfceef20985a957bc6eca2691ec075aaa01420b302e2b2b0c8d5a5c0d508a6dabb65c91d84d5a"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5f9845fc-7eff-4f4c-b91b-8a5e9e8b6ff4'::uuid,'WRIGHTS'' WIND TUNNEL','DEVICE','{}','Small wind tunnel built by Wright brothers with a blowdown fan powered by a gasoline engine capable of 12 m/s, intended to measure forces and performance for their gliders and flyers','{}','{}','{"frequency": 2, "text_unit_ids": ["af0b7dc953d20f99423204bc6976714fb8bc794b04cf5ce8101cfceef20985a957bc6eca2691ec075aaa01420b302e2b2b0c8d5a5c0d508a6dabb65c91d84d5a", "af0b7dc953d20f99423204bc6976714fb8bc794b04cf5ce8101cfceef20985a957bc6eca2691ec075aaa01420b302e2b2b0c8d5a5c0d508a6dabb65c91d84d5a"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('7ce7a717-fff9-45b3-94e7-223d42ce238a'::uuid,'MECHANICAL BALANCE','MODEL','{}','A novel ratio mechanical balance used in the small wind tunnel created by Wrights','{}','{}','{"frequency": 2, "text_unit_ids": ["af0b7dc953d20f99423204bc6976714fb8bc794b04cf5ce8101cfceef20985a957bc6eca2691ec075aaa01420b302e2b2b0c8d5a5c0d508a6dabb65c91d84d5a", "af0b7dc953d20f99423204bc6976714fb8bc794b04cf5ce8101cfceef20985a957bc6eca2691ec075aaa01420b302e2b2b0c8d5a5c0d508a6dabb65c91d84d5a"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f9fcbd13-df11-4861-b704-3c596e17c61b'::uuid,'FREESTREAM AIR DYNAMICS RESEARCH','MODEL','{}','Studies on flow inside a copy of Wrights'' wind tunnel, conducted by Dodson highlighting non-uniformity, lack of swirl elimination and low test Reynolds number','{}','{}','{"frequency": 1, "text_unit_ids": ["af0b7dc953d20f99423204bc6976714fb8bc794b04cf5ce8101cfceef20985a957bc6eca2691ec075aaa01420b302e2b2b0c8d5a5c0d508a6dabb65c91d84d5a"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('064e3e1e-9935-4953-9371-e6c381fb879c'::uuid,'WRIGHTS MECHANISM','MECHANISM','{}','The Wrights'' unique balance design for rapid tests, providing them with their best data set','{}','{}','{"frequency": 1, "text_unit_ids": ["f2ee2a48ece9792c2a41e9ef8523bac39c978616667ba97f16a7e58a5f9587b6b64e5046d7ff5d1443f11029123fc3893dc0c15cfc70ec93778bbea10e47f9f7"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('be10bfad-77a7-412c-919c-ac1cdb3c4241'::uuid,'WRIGHT WIND TUNNEL','SYSTEM','{}','A wind tunnel built by the Wright brothers that had specific faults in its flow process which affected their data measurements but was still superior to other early wind tunnels of that period','{}','{}','{"frequency": 1, "text_unit_ids": ["f2ee2a48ece9792c2a41e9ef8523bac39c978616667ba97f16a7e58a5f9587b6b64e5046d7ff5d1443f11029123fc3893dc0c15cfc70ec93778bbea10e47f9f7"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f046f392-4078-4ad4-9a62-879e634765c3'::uuid,'PRANDTL FAN-POWERED WIND TUNNEL','SYSTEM','{}','The full-scale wind tunnel used by Prandtl, initially small (0.3m x 0.2m cross-section), powered with a fan and water channel for fluid experiments','{}','{}','{"frequency": 1, "text_unit_ids": ["f2ee2a48ece9792c2a41e9ef8523bac39c978616667ba97f16a7e58a5f9587b6b64e5046d7ff5d1443f11029123fc3893dc0c15cfc70ec93778bbea10e47f9f7"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('548f3680-55c1-4ec4-935c-dc615db2def5'::uuid,'NATIONAL PHYSICAL LABORATORY (NPL)','ORGANIZATION','{}','(NPL) in England began obtaining state funds to build their first wind tunnel, which they used to measure forces on plates and structures. It used an electric motor-powered fan to achieve a speed of 9m/s','{}','{}','{"frequency": 2, "text_unit_ids": ["f2ee2a48ece9792c2a41e9ef8523bac39c978616667ba97f16a7e58a5f9587b6b64e5046d7ff5d1443f11029123fc3893dc0c15cfc70ec93778bbea10e47f9f7", "f2ee2a48ece9792c2a41e9ef8523bac39c978616667ba97f16a7e58a5f9587b6b64e5046d7ff5d1443f11029123fc3893dc0c15cfc70ec93778bbea10e47f9f7"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('bf7acf9b-7b86-43e4-93c5-d7141465ddc0'::uuid,'BALLOON FACTORY/ROYAL AIRCRAFT FACTORY (RAF)','ORGANIZATION','{}','(The Balloon Factory was renamed RAF in 1909, indicating their expanded efforts and focus on aircraft research during this period','{}','{}','{"frequency": 1, "text_unit_ids": ["f2ee2a48ece9792c2a41e9ef8523bac39c978616667ba97f16a7e58a5f9587b6b64e5046d7ff5d1443f11029123fc3893dc0c15cfc70ec93778bbea10e47f9f7"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('0a020a8b-242b-4657-86ed-d6c2b1e08525'::uuid,'ROYAL AIRCRAFT FACTORY (RAF)','ORGANIZATION','{}','(The Balloon Factory was renamed RAF in 1909, indicating their expanded efforts and focus on aircraft research during this period','{}','{}','{"frequency": 1, "text_unit_ids": ["f2ee2a48ece9792c2a41e9ef8523bac39c978616667ba97f16a7e58a5f9587b6b64e5046d7ff5d1443f11029123fc3893dc0c15cfc70ec93778bbea10e47f9f7"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a06133f3-60f4-41c5-bd77-6af5015461de'::uuid,'MOBIL WATER','MATERIAL','{}','(Though not explicitly named in text, water was a key material used in Prandtl''s flow channel for studying fluid dynamics, so its role is implied','{}','{}','{"frequency": 1, "text_unit_ids": ["f2ee2a48ece9792c2a41e9ef8523bac39c978616667ba97f16a7e58a5f9587b6b64e5046d7ff5d1443f11029123fc3893dc0c15cfc70ec93778bbea10e47f9f7"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c1ffe567-eddd-4b24-bf02-e2742d0c1556'::uuid,'ELECTRIC MOTOR','MECHANISM','{}','(The electric motor powered the fan in NPL''s wind tunnel, making it part of their system','{}','{}','{"frequency": 1, "text_unit_ids": ["f2ee2a48ece9792c2a41e9ef8523bac39c978616667ba97f16a7e58a5f9587b6b64e5046d7ff5d1443f11029123fc3893dc0c15cfc70ec93778bbea10e47f9f7"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('669071df-a47e-413c-9787-b3eb3e3a6a50'::uuid,'TAPE MEASURE','MECHANISM','{}','(Inferred from mentioning measurement inaccuracies, such as "20% over the central portion" and "14% in error", indicating some mechanism or device was used for measuring errors in coefficients)','{}','{}','{"frequency": 1, "text_unit_ids": ["f2ee2a48ece9792c2a41e9ef8523bac39c978616667ba97f16a7e58a5f9587b6b64e5046d7ff5d1443f11029123fc3893dc0c15cfc70ec93778bbea10e47f9f7"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('df3574eb-29b2-45bb-88d3-171482dde5d1'::uuid,'BALLOON','DEVICE','{}','A device for inflating and containing gas to achieve flight, initially expanded at the Balloon factory','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('15d09d4e-d93f-46a5-8f0c-ecee6fb7fffd'::uuid,'WIND TUNNEL (WIND TUNNEL 86)','SYSTEM','{}','A facility used to test aerodynamics, with multiple configurations including square wooden tube, open return and rectangular section tunnels. Used for various purposes such as testing airfoils, propellers, and full-scale airplanes.','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('109b2a67-a7ac-4b1e-9abf-289dd2a98f02'::uuid,'WIND TUNNEL (ZHUKOVSKY''S 1906 TUNNEL)','SYSTEM','{}','A wind tunnel with dimensions of 0.63 by 0.63 m used to measure aerofoil performance and centres of pressure, powered by a 1.5 kW electric fan capable of speeds up to 20 m/s initially, later 11m/s','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('7dc1e8bc-cec9-41ab-b13f-88a766dec580'::uuid,'MICROMANOMETER','DEVICE','{}','A pressure instrument or manometer used alongside Caselli anemometers to measure airflow speed.','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('62816f01-9f08-4e29-97f1-a891c5045bbd'::uuid,'GLASS WINDOW','PART','{}','A part included in the Zhukovsky''s wind tunnel for model observation during tests.','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('7b5a00d4-1e98-4d9d-b4ba-c8b0b654112a'::uuid,'EIFFEL TUNNELS','SYSTEM','{}','Implied reference to the type of tunnel design (closed working section, open jet, with smooth walls and fan-driven air flow controls), possibly similar to G.A. Crocco''s','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9ab68588-c2b9-4e8e-ba45-609e79801991'::uuid,'MONTGOMERY''S WIND TUNNEL (1908 TUNNEL)','SYSTEM','{}','A 0.61 by 1 m square section closed working section wind tunnel with a centrifugal fan and electric motor, used to examine flow around aerofoils, propellers, and wings.','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e9b543a0-eb31-4445-81a6-cddeedfe7298'::uuid,'RYABOUSHINSKY''S WIND TUNNEL (MOSCOW TUNNEL)','SYSTEM','{}','A 1.2 m diameter rectangular section wind tunnel with a single suction fan powered by an electric motor capable of speeds up to 6.5 m/s, utilized for investigating airscrews and bodies in flight.','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('04817011-c589-42a6-83fe-7570938b097d'::uuid,'FORLANINI''S WIND TUNNEL (MILAN TUNNEL)','SYSTEM','{}','Details not confirmed, wind tunnel located in Milan used for investigations of wings.','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('e79d4ef9-3e09-4413-846f-2d4639e49bb3'::uuid,'BALLOON FACTORY','FACILITY','{}','A location where balloons and possibly other lightweight aircraft were manufactured before the renaming to RAF','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('552d5715-4aa8-434b-b83d-b7dc7fbb02ee'::uuid,'WIND TUNNEL (1907 RAF TUNNEL)','SYSTEM','{}','A 1.2 m square section open return tunnel with a closed working section capable of 13 m/s, driven by a 4 bladed propeller and electric motor used to test airfoils, wings, and full-scale airplanes at the RAF.','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9a1c7e0e-41f7-4a60-a11c-526ba0390010'::uuid,'AIRSHIP MODEL','DEVICE','{}','A model tested in G.A. Crocco''s 1908 wind tunnel for aerodynamic and propulsion testing.','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b19b49aa-736e-48c5-bc97-576df4a12343'::uuid,'FULL-SCALE AIRPLANE','DEVICE','{}','A full-scale aircraft tested in RAF''s 1907 wind tunnel for aerodynamic and performance testing.','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('65ca01e4-3c6b-4b75-b536-2ce3250ac981'::uuid,'AIRSCREW','DEVICE','{}','A test subject for airflow resistance and performance in Ryaboushinsky''s Moscow tunnel.','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6b8b60d9-7490-49f8-946c-67dc6dc76cb9'::uuid,'CENTRIFUGAL FAN','DEVICE','{}','Power source for G.A. Crocco''s 1908 and Montgomer''s tunnels, providing required airflow for testing.','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('dc8e3140-be0e-4382-8a99-83602718e1ee'::uuid,'WIND TUNNEL (FIRUZABAD''S TUNNEL)','SYSTEM','{}','Facility with specified dimensions and capabilities used in aerodynamic testing.','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6807d9f2-597f-4432-998c-69198e96bfa6'::uuid,'CLOTH WALLPAPER LINING','PART','{}','An interior feature of the RAF''s 1907 wind tunnel, enhancing its functionality for airflow control and test subject interaction.','{}','{}','{"frequency": 1, "text_unit_ids": ["ef3abb8012f6cecd19692d0c1a9ddb0f78b2d363feb6706a8c630bfb0c9dea1ef09ecd3ec44494748f1d9f3cbdbbbfde6c63f36fea8fe1cf8ffb674a245603d3"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('409aa2e7-c02a-46b6-b90d-79ffe126c92b'::uuid,'RAF87','SYSTEM','{}','RAF87 built a wind tunnel with characteristics as described.','{}','{}','{"frequency": 1, "text_unit_ids": ["6c043286a724707e324c0aa9bd1e28f9c44eaaaa396eebf578400d5cb0cb167ac12bec61fdd45d7cfa6f63f53e15f92c08aeae6493271704143d122caa10dcec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ac551a6e-f407-400a-91a9-758a3ea41921'::uuid,'NPL DESIGN','MODEL','{}','The National Physical Laboratory''s design used as the basis for copying by other institutions, notable features include its square section with no racecourse return path until 1909','{}','{}','{"frequency": 1, "text_unit_ids": ["6c043286a724707e324c0aa9bd1e28f9c44eaaaa396eebf578400d5cb0cb167ac12bec61fdd45d7cfa6f63f53e15f92c08aeae6493271704143d122caa10dcec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('75718a53-1824-4bdd-8577-4b03df369767'::uuid,'ARISTOTLE','PERSON','{}','Recognized the weight of air and contributed to posing solutions for flight problems','{}','{}','{"frequency": 2, "text_unit_ids": ["a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad", "a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('2801bebb-c971-4886-bdc3-8cc4a3d2f80b'::uuid,'STANDARD_NOTATION','SYSTEM','{}','"Standard notation" used to denote the body force F and pressure gradient ∇p relevant for motion dynamics.','{}','{}','{"frequency": 1, "text_unit_ids": ["f6c3b3b269e7af478487328e5313e02a8c137117cbe55dacc0858717330e7e05c2ae5032253aaf5d9ddafd9ecef1939f5b0aaf00ae9bd44a279c22bd1b4c6c20"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('02b037ce-eed0-4588-9f60-2670aab1f426'::uuid,'NPL TUNNEL','SYSTEM','{}','The National Physical Laboratory''s original design of a test wind tunnel, initially proposed in 1907 but not built until 1909 without the racecourse return path. It serves as a model for later designs in Eiffel''s research.','{}','{}','{"frequency": 1, "text_unit_ids": ["6c043286a724707e324c0aa9bd1e28f9c44eaaaa396eebf578400d5cb0cb167ac12bec61fdd45d7cfa6f63f53e15f92c08aeae6493271704143d122caa10dcec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('30b056e4-7749-441f-8d40-95dd399d76fd'::uuid,'NPL CORE DESIGN','MODEL','{}','The fundamental design of the NPL tunnel that served as the basis for modifications and copies by other institutions such as the East London College and Eiffel''s Champ des Mars tunnel.','{}','{}','{"frequency": 1, "text_unit_ids": ["6c043286a724707e324c0aa9bd1e28f9c44eaaaa396eebf578400d5cb0cb167ac12bec61fdd45d7cfa6f63f53e15f92c08aeae6493271704143d122caa10dcec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('1707b80d-1663-41f7-90d7-ee949f403434'::uuid,'GUIDE BLADES','MECHANISM','{}','Guide Blades are components designed and implemented within the corner areas of a wind tunnel, as described by L. Prandtl''s work on closed return designs. These guide blades play a crucial role in enhancing flow uniformity across the wind tunnel by strategically altering the air flow direction at critical corners. Through their precise placement and engineering, guide blades help to mitigate turbulence and ensure more consistent airflow patterns, thereby improving overall performance and accuracy of tests conducted within the wind tunnel environment.','{}','{}','{"frequency": 2, "text_unit_ids": ["6c043286a724707e324c0aa9bd1e28f9c44eaaaa396eebf578400d5cb0cb167ac12bec61fdd45d7cfa6f63f53e15f92c08aeae6493271704143d122caa10dcec", "6c043286a724707e324c0aa9bd1e28f9c44eaaaa396eebf578400d5cb0cb167ac12bec61fdd45d7cfa6f63f53e15f92c08aeae6493271704143d122caa10dcec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('dd3b8147-59dd-4200-9ae7-93e7737d52e0'::uuid,'PITOT TUBE AND MICROMANOMETER','MEASUREMENT DEVICE','{}','The PITOT TUBE AND MICROMANOMETER, integral components utilized in the experimental setup created by Ludwig Prandtl, played a crucial role in the research and development of aerodynamics and aircraft design. They served as key tools for accurately measuring flow speeds within the closed return tunnel that Prandtl constructed. These instruments are essential for investigating the complex behavior of airflow around aircraft models. By employing both PITOT tubes, which measure total pressure, and micromanometers, researchers could gain detailed insights into the dynamic interactions between air currents and various airfoil geometries. This data was fundamental in advancing our understanding of airflow dynamics and optimizing aircraft design through precise measurements and analysis.','{}','{}','{"frequency": 2, "text_unit_ids": ["6c043286a724707e324c0aa9bd1e28f9c44eaaaa396eebf578400d5cb0cb167ac12bec61fdd45d7cfa6f63f53e15f92c08aeae6493271704143d122caa10dcec", "6c043286a724707e324c0aa9bd1e28f9c44eaaaa396eebf578400d5cb0cb167ac12bec61fdd45d7cfa6f63f53e15f92c08aeae6493271704143d122caa10dcec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('23cb02bd-3eb3-4739-950a-ee8e3c7bcbae'::uuid,'EIFFEL RESEARCH PROGRAMME','MODEL','{}','A substantial private-funded research program by Eiffel involving aerodynamic testing that began with drop tests in aviation and continued through the development of wind tunnels like those at Champ des Mars and Auteuil.','{}','{}','{"frequency": 1, "text_unit_ids": ["6c043286a724707e324c0aa9bd1e28f9c44eaaaa396eebf578400d5cb0cb167ac12bec61fdd45d7cfa6f63f53e15f92c08aeae6493271704143d122caa10dcec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5ab4b016-326e-49d4-b32d-1b48865f78f2'::uuid,'ZHKUOVSKY76','SYSTEM','{}','Engineer who built a large-diameter wind tunnel with a suction fan to test various aerofoil flows at the Imperial University of Moscow in 1909','{}','{}','{"frequency": 2, "text_unit_ids": ["e0ded24d363ec39e76d9e983a1bafea9a1e9accb8059322ef7065b07c4c84c9cee4caa65c00b8bf702b00a6751810904936f74916a3ef15893333841e710c08c", "e0ded24d363ec39e76d9e983a1bafea9a1e9accb8059322ef7065b07c4c84c9cee4caa65c00b8bf702b00a6751810904936f74916a3ef15893333841e710c08c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a949894a-bc50-4158-90dd-60de1389ba06'::uuid,'KOUCHINO','PLACE','{}','Research establishment funded entirely by Ryabushinsky himself, which was distinct from Zhukovsky''s at Imperial Technical School','{}','{}','{"frequency": 2, "text_unit_ids": ["e0ded24d363ec39e76d9e983a1bafea9a1e9accb8059322ef7065b07c4c84c9cee4caa65c00b8bf702b00a6751810904936f74916a3ef15893333841e710c08c", "e0ded24d363ec39e76d9e983a1bafea9a1e9accb8059322ef7065b07c4c84c9cee4caa65c00b8bf702b00a6751810904936f74916a3ef15893333841e710c08c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b17f8b4f-49bf-4904-9a7f-9c576eaab2f6'::uuid,'RYABUSHINSKY HIMSELF','PERSON','{}','Funded all research developments in the rival establishment at Kouchino up to 1915','{}','{}','{"frequency": 2, "text_unit_ids": ["e0ded24d363ec39e76d9e983a1bafea9a1e9accb8059322ef7065b07c4c84c9cee4caa65c00b8bf702b00a6751810904936f74916a3ef15893333841e710c08c", "e0ded24d363ec39e76d9e983a1bafea9a1e9accb8059322ef7065b07c4c84c9cee4caa65c00b8bf702b00a6751810904936f74916a3ef15893333841e710c08c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('94770ff2-4b1e-4ede-b4b2-9ff4720d606f'::uuid,'TWO TUNNELS','SYSTEM','{}','Two tunnels still in use in 1960 related to Eiffel''s early work on wing pressure distributions','{}','{}','{"frequency": 2, "text_unit_ids": ["e0ded24d363ec39e76d9e983a1bafea9a1e9accb8059322ef7065b07c4c84c9cee4caa65c00b8bf702b00a6751810904936f74916a3ef15893333841e710c08c", "e0ded24d363ec39e76d9e983a1bafea9a1e9accb8059322ef7065b07c4c84c9cee4caa65c00b8bf702b00a6751810904936f74916a3ef15893333841e710c08c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d8ea613e-7e13-48e9-86a4-1875e373750a'::uuid,'NPL61,59','INSTITUTION','{}','UK organization that constructed a water channel to test flow visualisation and Lagrangian studies at 0.6 m/s in 1909','{}','{}','{"frequency": 1, "text_unit_ids": ["e0ded24d363ec39e76d9e983a1bafea9a1e9accb8059322ef7065b07c4c84c9cee4caa65c00b8bf702b00a6751810904936f74916a3ef15893333841e710c08c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f5c68c98-c9d3-40f3-82b2-56d6054c388d'::uuid,'BALANCE SYSTEM','DEVICE','{}','A system developed for supporting models during testing and measuring all forces acting on them, crucial for accurate flow investigations around aircraft models conducted within more refined wind tunnel designs.','{}','{}','{"frequency": 1, "text_unit_ids": ["6c043286a724707e324c0aa9bd1e28f9c44eaaaa396eebf578400d5cb0cb167ac12bec61fdd45d7cfa6f63f53e15f92c08aeae6493271704143d122caa10dcec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('623c0b24-ef00-47e9-ab60-a1aadf93ac14'::uuid,'EIFFEL TUNNEL AT AUTEUIL','DEVICE','{}','The Eiffel Tunnel at Auteuil, also known as the second installation of Gustave Eiffel’s wind tunnel, was located in Auteuil from 1912 until the 1940s. This facility, situated where the Champ des Mars originally stood, played a crucial role in aerodynamic testing during its operational period. Recognized for its precision and systematic methods, the tunnel provided highly accurate data regarding pressure distributions on wings and other aviation components. Its continued operation into the 1940s underscores its importance in maintaining advanced aerodynamic research standards throughout that era.','{}','{}','{"frequency": 2, "text_unit_ids": ["6c043286a724707e324c0aa9bd1e28f9c44eaaaa396eebf578400d5cb0cb167ac12bec61fdd45d7cfa6f63f53e15f92c08aeae6493271704143d122caa10dcec", "6c043286a724707e324c0aa9bd1e28f9c44eaaaa396eebf578400d5cb0cb167ac12bec61fdd45d7cfa6f63f53e15f92c08aeae6493271704143d122caa10dcec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('523d955e-40aa-40b9-bf01-b5d96c913950'::uuid,'RAF87 TUNNEL','SYSTEM','{}','Wind tunnel built by RAF87 with a 1.2 m square section and a propeller-driven mechanism in an open working condition.','{}','{}','{"frequency": 1, "text_unit_ids": ["6c043286a724707e324c0aa9bd1e28f9c44eaaaa396eebf578400d5cb0cb167ac12bec61fdd45d7cfa6f63f53e15f92c08aeae6493271704143d122caa10dcec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('1e982088-9acc-46b9-87b0-c2bebe977f0e'::uuid,'NATIONAL PHYSICAL LABORATORY (NPL) DESIGN','MODEL','{}','The basic design of the NPL wind tunnel that served as the foundation for many other designs, including the RAF87 tunnel and Eiffel''s tunnels but without racecourse return path until 1909.','{}','{}','{"frequency": 1, "text_unit_ids": ["6c043286a724707e324c0aa9bd1e28f9c44eaaaa396eebf578400d5cb0cb167ac12bec61fdd45d7cfa6f63f53e15f92c08aeae6493271704143d122caa10dcec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c68a580d-3b54-40de-a1b4-dbea9734a314'::uuid,'CITY UNIVERSITY','ORGANIZATION','{}','Former name of Northampton College where Frederick Handley Page''s wind tunnel was built','{}','{}','{"frequency": 2, "text_unit_ids": ["e0ded24d363ec39e76d9e983a1bafea9a1e9accb8059322ef7065b07c4c84c9cee4caa65c00b8bf702b00a6751810904936f74916a3ef15893333841e710c08c", "e0ded24d363ec39e76d9e983a1bafea9a1e9accb8059322ef7065b07c4c84c9cee4caa65c00b8bf702b00a6751810904936f74916a3ef15893333841e710c08c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('0c925934-c90b-4afa-b4e9-299bcc5494ca'::uuid,'TUNNEL','DEVICE','{}','A device used to test aerodynamic performance, with varying specifications and usages','{}','{}','{"frequency": 1, "text_unit_ids": ["2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('06fda21c-b3b0-41fe-a8a6-505ea3c079a2'::uuid,'O400 BOMBER','MODEL','{}','An aircraft model from the first world war that required tunnel-based design assistance for its development','{}','{}','{"frequency": 2, "text_unit_ids": ["2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e", "2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('20ff4946-65ff-4e8f-9ed9-354166b7925b'::uuid,'NEW 1.2M SQUARE SECTION TUNNEL (NPL91,59)','DEVICE','{}','Installed at NPL in 1911, this tunnel proved superior to earlier models and featured a precise balance. It was utilized up until 1913 for aerodynamic testing.','{}','{}','{"frequency": 2, "text_unit_ids": ["2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e", "2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('97da682e-7f80-4655-a475-8dd104ebeb22'::uuid,'WIND TUNNELS AT ST PETERSBURG (ST PETERSBURG, RUSSIA)','DEVICE','{}','Wind tunnels were built here in 1912, but no specific details are given','{}','{}','{"frequency": 1, "text_unit_ids": ["2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('2cac843b-915f-4fe5-917d-a354a5536099'::uuid,'LARGE 2.3M CLOSED RETURN TUNNEL FOR US NAVY (NPL, USA)','DEVICE','{}','This tunnel was built under the supervision of Zahm in 1913 and used for extensive aerodynamic investigations on whole aircraft models','{}','{}','{"frequency": 2, "text_unit_ids": ["2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e", "2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('86b3a9c8-4a9b-49ae-a29a-1fa6e1399071'::uuid,'TECHNISCHEN HOSCHULE AACHEN TUNNELS (AACHEN, GERMANY)','SYSTEM','{}','Reported tunnels here may refer to different facilities and their associated tests. The specifics are not fully clear.','{}','{}','{"frequency": 2, "text_unit_ids": ["2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e", "2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('2bdd47a0-0193-4f9e-a2f1-86aaa690eec6'::uuid,'TUNNEL WITH 2M SQUARE SECTION REPORTED BY HUNSAKER AT MIT (MASSACHUSETTS INSTITUTE OF TECHNOLOGY, USA)','DEVICE','{}','Built in 1913 as a copy of the NPL 1.2m tunnel; it was used for aerodynamic studies','{}','{}','{"frequency": 2, "text_unit_ids": ["2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e", "2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('1b544f25-5b6e-4f72-a51e-53b817ab7076'::uuid,'2M DIAMETER TUNNEL REPORTED BY WARNER (1920) (UNKNOWN LOCATION)','DEVICE','{}','Installed sometime around 1920, this tunnel showed poor performance and noisy issues but its exact location is unknown','{}','{}','{"frequency": 2, "text_unit_ids": ["2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e", "2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('1009478c-3b6d-42fa-bc8e-ef6df6576ce0'::uuid,'TUNNEL USED BY JUNKERS AT AACHEN (AACHEN, GERMANY)','DEVICE','{}','Shared facility with other tunnels in the city; also may have had a 2m diameter. The specific model or details are unclear.','{}','{}','{"frequency": 2, "text_unit_ids": ["2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e", "2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a2ce1371-bc5b-4545-9e98-f80f4b97b35a'::uuid,'1M DIAMETER TUNNEL AND 2M DIAMETER TUNNEL INSTALLED SIDE-BY-SIDE BY EIFFEL AT AUTEUIL (AUTEUIL, FRANCE)','DEVICE','{}','Part of Eiffel''s relocation to Auteuil in Paris; these tunnels performed comprehensive aerodynamic investigations for aircraft models during WWI','{}','{}','{"frequency": 1, "text_unit_ids": ["2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3b3840ac-09f9-4885-adb0-fda903c7d85a'::uuid,'SMALL WIND TUNNELS BUILT AT ST CYR (ST CYR, FRANCE)','SYSTEM','{}','Several tunnels were built here by 1913, including one advanced model with settlement chambers and contraction features. Details are scarce.','{}','{}','{"frequency": 2, "text_unit_ids": ["2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e", "2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5f4cfe57-377a-45bd-ad4b-bdd5426be8c0'::uuid,'2.5M SQUARE HELICOPTER ROTORS TESTING TUNNEL INSTALLED BY ZHUKOVSKY (RUSSIA)','DEVICE','{}','Installed circa 1915 at a Russian facility, mainly for investigating helicopter rotors but specific details absent','{}','{}','{"frequency": 1, "text_unit_ids": ["2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5d17ddd9-1e05-4796-8ae0-81737c5492f7'::uuid,'BLIMP','DEVICE','{}','Blimp designs are being tested with a gasoline engine and propeller.','{}','{}','{"frequency": 1, "text_unit_ids": ["1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
