	 ('90226b6e-4a0d-4b65-8a65-4f528d8ffa8f'::uuid,'GASOLINE ENGINE','COMPONENT','{}','Gasoline engine powers the blimp','{}','{}','{"frequency": 1, "text_unit_ids": ["1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ca22e201-2537-4be5-a5ab-0d22444a153a'::uuid,'2.5M SQUARE TUNNEL','DEVICE','{}','A 2.5m square tunnel was installed in Russia for investigating helicopter rotors, used by Zhukovsky.','{}','{}','{"frequency": 1, "text_unit_ids": ["1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3926774b-e070-45fc-800d-5a75e843ccd0'::uuid,'JUNKERS TUNNEL','DEVICE','{}','At Dessau, Junkers built a new octagonal tunnel for his metal wings tests','{}','{}','{"frequency": 2, "text_unit_ids": ["1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0", "1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('09f1f823-f227-4fc8-94e3-6288068feaa4'::uuid,'ROYAL AIRCRAFT FACTORY TUNNEL','DEVICE','{}','A copy of the NPL 1.2m tunnel was installed at Royal Aircraft Factory for aircraft model testing.','{}','{}','{"frequency": 2, "text_unit_ids": ["1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0", "1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('74963795-794e-47c8-9814-5edfb595da8a'::uuid,'PRANDTL-WIND-TUNNEL','DEVICE','{}','In Germany, Prandtl installed his second larger wind tunnel which improved performance compared to the first one','{}','{}','{"frequency": 2, "text_unit_ids": ["1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0", "1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('345a1c17-eabf-4331-b629-a8e579609463'::uuid,'PITOT TUBE','COMPONENT','{}','Pitot tube and micromanometer were used for measuring flow speeds.','{}','{}','{"frequency": 2, "text_unit_ids": ["1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0", "1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f36a3d4c-dc41-4a6b-ba5c-19e8bf9fcacd'::uuid,'MOTOR CONE','COMPONENT','{}','Motor is faired by a cone during testing in this wind tunnel','{}','{}','{"frequency": 2, "text_unit_ids": ["1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0", "1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e1c3adeb-eedb-40bf-892c-291a012d72fc'::uuid,'WIRE SYSTEM','SYSTEM','{}','Models are supported on a wire system and attached to an automatic balance for measuring forces during tests.','{}','{}','{"frequency": 2, "text_unit_ids": ["1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0", "1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e32a9066-4c11-4477-a5e8-73a9a208aa90'::uuid,'MODEL','DEVICE','{}','The entity "MODEL" refers to a critical component in flight research. Models were employed not only as isolated structures but also integrated into complete devices for various research purposes. These models played an essential role in aerodynamic testing and design validation, serving as physical representations that could be subjected to real-world conditions without the risks associated with full-scale aircraft.
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('de483430-86ce-4274-a7ec-36e4d6f23438'::uuid,'SMALL OCTAGONAL TUNNEL','DEVICE','{}','Built by the US Bureau of Standards in 1918, a small octagonal wind tunnel was constructed.','{}','{}','{"frequency": 1, "text_unit_ids": ["75e55aae79fa4fef8afa00e4bf79f6f1f694d27b10f227c1f393bd8cf61700080ce3c057271ae7311d2d3cd09b4445ff1281543e67c2ce7840a138c9f1467077"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ea55ac9b-c46a-4fad-8610-c3d7992ff41e'::uuid,'TUNNEL AT THE ZEPPELIN WORKS','DEVICE','{}','Despite not being confirmed, it is mentioned that a large wind tunnel existed at the Zeppelin works and also one in Vienna.','{}','{}','{"frequency": 2, "text_unit_ids": ["75e55aae79fa4fef8afa00e4bf79f6f1f694d27b10f227c1f393bd8cf61700080ce3c057271ae7311d2d3cd09b4445ff1281543e67c2ce7840a138c9f1467077", "75e55aae79fa4fef8afa00e4bf79f6f1f694d27b10f227c1f393bd8cf61700080ce3c057271ae7311d2d3cd09b4445ff1281543e67c2ce7840a138c9f1467077"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('8d7e7dbd-2766-4b51-aaff-361520abf2c4'::uuid,'AERODYNAMICS INVESTIGATION BECOMING A MATTER OF NATIONAL PRESTIGE','MODEL','{}','After 1918, wind tunnel testing was seen as important for national pride and attracted significant funding.','{}','{}','{"frequency": 2, "text_unit_ids": ["75e55aae79fa4fef8afa00e4bf79f6f1f694d27b10f227c1f393bd8cf61700080ce3c057271ae7311d2d3cd09b4445ff1281543e67c2ce7840a138c9f1467077", "75e55aae79fa4fef8afa00e4bf79f6f1f694d27b10f227c1f393bd8cf61700080ce3c057271ae7311d2d3cd09b4445ff1281543e67c2ce7840a138c9f1467077"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('edbdecbe-03f6-4469-a837-2e6938219681'::uuid,'FREE AND SEMI-FREE FLIGHT TESTS','METHOD','{}','Tests during this period confirmed the dependencies of resisting forces on area, fluid density, and velocity squared, with Eiffel''s work being particularly accurate.','{}','{}','{"frequency": 2, "text_unit_ids": ["75e55aae79fa4fef8afa00e4bf79f6f1f694d27b10f227c1f393bd8cf61700080ce3c057271ae7311d2d3cd09b4445ff1281543e67c2ce7840a138c9f1467077", "75e55aae79fa4fef8afa00e4bf79f6f1f694d27b10f227c1f393bd8cf61700080ce3c057271ae7311d2d3cd09b4445ff1281543e67c2ce7840a138c9f1467077"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('7fbf9843-96a6-4b1a-8d0a-dfbd8f5d9781'::uuid,'WHIRLING ARM DEVICES','MECHANISM','{}','Whirling Arm Devices were utilized to measure flow resistance through the application of a known falling weight as a motive force. These devices, however, had limitations due to their inability to account for the wake effects caused by rotating tested items that experienced disturbed flow conditions. This inherent drawback persisted until advancements in technology during the 20th century introduced more reliable pitot-static tubes, which helped mitigate these issues by better accounting for the complex fluid dynamics involved. Despite this improvement, Whirling Arm Devices remained a critical tool for early flow measurement studies, providing foundational insights into fluid resistance that were essential for subsequent developments in aerodynamics and hydrodynamics.','{}','{}','{"frequency": 2, "text_unit_ids": ["75e55aae79fa4fef8afa00e4bf79f6f1f694d27b10f227c1f393bd8cf61700080ce3c057271ae7311d2d3cd09b4445ff1281543e67c2ce7840a138c9f1467077", "75e55aae79fa4fef8afa00e4bf79f6f1f694d27b10f227c1f393bd8cf61700080ce3c057271ae7311d2d3cd09b4445ff1281543e67c2ce7840a138c9f1467077"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e3dca83c-543c-4d68-ab42-491044995be1'::uuid,'LARGE WIND TUNNEL IN VIENNA','DEVICE','{}','Though not confirmed, a large wind tunnel is mentioned as existing in Vienna alongside tunnels at the Zeppelin works.','{}','{}','{"frequency": 1, "text_unit_ids": ["75e55aae79fa4fef8afa00e4bf79f6f1f694d27b10f227c1f393bd8cf61700080ce3c057271ae7311d2d3cd09b4445ff1281543e67c2ce7840a138c9f1467077"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('91049232-9ad8-4012-882a-1a045519e830'::uuid,'TIRUZIA''S ALHAMIA PRISON','GEO','{}','Prison location in Tiruzia, though not directly related to the text about wind tunnels.','{}','{}','{"frequency": 1, "text_unit_ids": ["75e55aae79fa4fef8afa00e4bf79f6f1f694d27b10f227c1f393bd8cf61700080ce3c057271ae7311d2d3cd09b4445ff1281543e67c2ce7840a138c9f1467077"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('dac17630-43b3-45ba-9484-af9d17794392'::uuid,'ST CYR LARGE SCALE TRACK TESTS','DEVICE','{}','Large track tests used by Eiffel to calibrate his wind tunnel results, a related method of testing.','{}','{}','{"frequency": 1, "text_unit_ids": ["75e55aae79fa4fef8afa00e4bf79f6f1f694d27b10f227c1f393bd8cf61700080ce3c057271ae7311d2d3cd09b4445ff1281543e67c2ce7840a138c9f1467077"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('64fe49ed-9d0e-4bbe-97bd-2bfd5d42fb61'::uuid,'POTENTIAL ENERGY OF KINETIC MOTION','MECHANISM','{}','Potential energy associated with the air''s velocity.','{}','{}','{"frequency": 1, "text_unit_ids": ["2d9fdd18fbb30369988222506fc6af76775a9970c876b024d039f1156ef34f3f17266c64951a1221502b45b881305de03ffdda41d4d7de0a29ea5d1a8aa25ad3"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('6af25651-0567-4fcb-b2f8-a902532c7ffb'::uuid,'ADIABATIC INDEX FOR AIR','MATERIAL','{}','The adiabatic index, k = 1.4, characterizes the behavior of air under adiabatic conditions.','{}','{}','{"frequency": 1, "text_unit_ids": ["2d9fdd18fbb30369988222506fc6af76775a9970c876b024d039f1156ef34f3f17266c64951a1221502b45b881305de03ffdda41d4d7de0a29ea5d1a8aa25ad3"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('34711820-e63a-4ee7-970e-a6e219f86277'::uuid,'COMPRRESIBLE FLOW','SYSTEM','{}','Flow where air properties like density, temperature change due to acceleration or deceleration in the streamtube','{}','{}','{"frequency": 1, "text_unit_ids": ["c8c5897c0dcab93d58d200fc9f0c15f81f8e093f6028b3f4e6d11e4efab906fb1aee05f08e53d8e44917ed87c14b9f1efbe47459b1d09dc02a6aff9bd1212cf2"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('e310c022-d622-4c19-a242-f271559af62a'::uuid,'ANEMOMETER CALIBRATION','MODEL','{}','Using whirling arms to calibrate anemometers involves setting up and measuring air flow speed using a rotating arm with known geometry>','{}','{}','{"frequency": 3, "text_unit_ids": ["bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a", "bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a", "bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c661320a-295d-4a7f-9089-d2c3605c92cf'::uuid,'DRAG MEASUREMENT','APPLICATION','{}','Measuring the resistance of various objects in the flow by assessing how much they slow down the fluid motion, accurate to within 20-30% for some whirling arms>','{}','{}','{"frequency": 3, "text_unit_ids": ["bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a", "bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a", "bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9d63f5d2-a29d-4e3f-ad6e-2caa4f8fab81'::uuid,'LIFT MEASUREMENT','MEASURE','{}','Determining the upward force on wing sections using whirling arms; key players included Cayley, Lilienthal, and Langley who could measure lift forces up to within 20-30% accuracy>','{}','{}','{"frequency": 1, "text_unit_ids": ["bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('70b38e70-01ac-4efb-bdf1-38fc568cd38b'::uuid,'FLAT PLATE DRAG DEPENDENCE CONFIRMATION','DISCOVERY','{}','Whirling arms confirmed that the second power of velocity (V^2) influences air resistance for flat plates>','{}','{}','{"frequency": 3, "text_unit_ids": ["bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a", "bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a", "bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('dd98f155-e6a4-496e-b446-8ef4035aff98'::uuid,'CAMBERED AEROFOIL PERFORMANCE TESTING','ASSAY','{}','Whirling arms were used to determine whether cambered airfoils or flat plates produced greater lift, aiding in the selection of aerofoil shapes for aircraft development>','{}','{}','{"frequency": 1, "text_unit_ids": ["bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6e26eb19-866f-46cf-a69f-e140e2e1726f'::uuid,'COMPETITION BETWEEN AEROFOIL SHAPES DETERMINATION','EVALUATION','{}','Whirling arm tests helped decide which wing shapes generated more lift, critical for optimizing aircraft performance>','{}','{}','{"frequency": 1, "text_unit_ids": ["bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b9374438-2a15-431b-82e7-07e0d35bf6d0'::uuid,'CP MOVEMENT WITH INCIDENCE CHANGE DETECTION','OBSERVATION','{}','Determining the point of highest pressure (cp) shift as the angle of attack changes using whirling arms, important for understanding dynamic fluid interactions at varying angles>','{}','{}','{"frequency": 3, "text_unit_ids": ["bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a", "bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a", "bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f8521f63-44d6-4e02-9b41-549dee227b23'::uuid,'WIND TUNNEL DEVELOPMENT LIMITATIONS','LIMITATION','{}','Pre-1908 wind tunnels had issues with flow smoothing and lack of adequate swirl reduction systems, hampering precision measurements despite their utility in developing aerodynamic techniques>','{}','{}','{"frequency": 3, "text_unit_ids": ["bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a", "bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a", "bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c94111c2-3400-4fce-93c6-62e90036b595'::uuid,'PRANDTL''S TUNNEL IMPROVEMENTS','IMPROVEMENT','{}','Introduced better swirl reduction methods to overcome limitations found in earlier wind tunnels after 1908, enabling higher quality flow for more accurate tests>','{}','{}','{"frequency": 3, "text_unit_ids": ["bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a", "bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a", "bad2d51ceb36600b316dd9e9559a9c537449b7988c1b3cff40a6201ad6c19b9adb9b92e7900d7b444e642f5b22112ecf93bb086b0a57f7bc5ec5e294e014471a"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
