	 ('bd6852aa-6078-44ba-acef-c353957ffd86'::uuid,'PRECISION PITOT-STATIC TUBES','DEVICE','{}','Used for more precise measurements of wind tunnel flows alongside hot wire anemometers and micromanometers','{}','{}','{"frequency": 2, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('524eaadf-66c1-4841-be6e-78873fb9ca80'::uuid,'HOT WIRE ANEMOMETERS','DEVICE','{}','Used for more precise measurements of wind tunnel flows alongside precision pitot-static tubes and micromanometers','{}','{}','{"frequency": 2, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e4d9d556-f763-4ef5-aff4-cc031d32e1cf'::uuid,'MICROMANOMETERS','DEVICE','{}','Used for more precise measurements of wind tunnel flows alongside hot wire anemometers and precision pitot-static tubes','{}','{}','{"frequency": 2, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c217b817-645e-42be-828d-72c25ca1f508'::uuid,'ACCURATE FORCE BALANCES','DEVICE','{}','Measuring tools used in conjunction with precision pitot-static tubes, hot wire anemometers, and micromanometers to achieve precise measurements','{}','{}','{"frequency": 2, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6741c341-19fe-460d-95d0-0b2de8a13567'::uuid,'MODERN EFFICIENT AEROFOILS','MODEL','{}','Developed using better quality wind tunnel flows for accurate measurement after 1908','{}','{}','{"frequency": 2, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6d9422a6-a0b6-42dc-a9ba-5bd751054100'::uuid,'QMC GUST TUNNEL','SYSTEM','{}','A specific type of tunnel used in 1969 to study the effects of gusts on aerofoil performance','{}','{}','{"frequency": 2, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('867b39ba-2b63-4d40-b8eb-da209e67203e'::uuid,'THICKLY BRACED MONOPLANES','SYSTEM','{}','Structural design choice necessitated by using thin aerofoil shapes with relatively small nose radii due to their structural weakness','{}','{}','{"frequency": 2, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('546ecb75-22a9-4e46-854d-ea89b8aec394'::uuid,'BIPLANES','SYSTEM','{}','Alternative and more structurally robust flying machines that were used when monoplane wings'' weaknesses led to extra drag issues','{}','{}','{"frequency": 2, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('fc442b50-3539-4744-984b-71e234bd4eb6'::uuid,'CLOSED SECTIONS TUNNELS','SYSTEM','{}','Tunnels with closed sections that had growing boundary layers, causing a maximum velocity increase in the axial direction of flow','{}','{}','{"frequency": 2, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('8a7543aa-e916-4c49-bea0-5e7882a6529d'::uuid,'OPEN SECTION WIND TUNNELS','SYSTEM','{}','Tunnels without full enclosure, leading to instability due to vortex shedding from jet edges','{}','{}','{"frequency": 2, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('1f338840-8ed0-49ae-8bae-23c70d065620'::uuid,'SEPARATION BUBBLE ON UPPER SURFACE','PHENOMENON','{}','A separation phenomenon observed with model aerofoils at lower Reynolds numbers during flight in some open section tunnels','{}','{}','{"frequency": 2, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('40b7988f-bcb9-4132-9cfd-c655f6d2e3fd'::uuid,'WING DRAG','PERFORMANCE','{}','Inaccurate estimates using closed working section tunnels due to wall interference, needing corrections not fully understood until the 1920s','{}','{}','{"frequency": 2, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b876255d-3b96-4906-87ca-2b16948e33ce'::uuid,'VARIABLE DENSITY TUNNELS','SYSTEM','{}','Developed after World War I to overcome Reynolds number problems by creating more realistic test environments','{}','{}','{"frequency": 2, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e8b90d2d-8a26-4ea2-b7b8-8580aeb4fc15'::uuid,'ARCHIMEDES','PERSON','{}','Key figures in early aerodynamic principles, understood nature of floating bodies through his work','{}','{}','{"frequency": 2, "text_unit_ids": ["a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad", "a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('648b9103-a4e3-40d8-8990-23bad6c5e837'::uuid,'ADER','ORGANIZATION','{}','Early aircraft maker who attempted to build flying machines; his achievements are noted as part of the timeline for early attempts at man-powered flight','{}','{}','{"frequency": 2, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('21ca80a0-56c9-4e73-97dc-0f5af8149a90'::uuid,'MAXIM','PERSON','{}','MAXIM was a pivotal early aviation pioneer, recognized for his groundbreaking contributions to the development of practical flying machines in the late 19th century. His work played a crucial role in advancing the timeline towards powered human flight, serving as an essential milestone alongside other notable figures such as Sir George Cayley and François Pilâtre de Rozier.
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('9a73aaa9-b0d3-4054-9c74-e9abdb0377f3'::uuid,'WHIRLING ARM EXPERIMENTS','MECHANISM','{}','These were a series of experiments conducted by Cayley on his whirling arm device to study the forces acting on airfoils, contributing significantly to early aviation concepts.','{}','{}','{"frequency": 1, "text_unit_ids": ["f5cd08a5bba8e5f1cac73b2168b03f440d049e82b880cf5ff9b03a61f932ab149f55ecbff1e2e45fc298cd176b96304c704c6f0d04ce87977c3be47e617c941b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('48e36647-7ee4-4329-b6e8-2e2cba221ea7'::uuid,'LATERAL STABILITY DIHEDRAL DEVICE','DEVICE','{}','Dihedral was used in Cayley''s designs to achieve lateral stability.','{}','{}','{"frequency": 1, "text_unit_ids": ["f5cd08a5bba8e5f1cac73b2168b03f440d049e82b880cf5ff9b03a61f932ab149f55ecbff1e2e45fc298cd176b96304c704c6f0d04ce87977c3be47e617c941b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c35f6a03-64c8-4d9a-9d6a-51b99b500ccb'::uuid,'POWER UNITS OF CAYLEY','MECHANISM','{}','While Cayley experimented with power units like compressed air or explosives, he did not succeed in powering his machines effectively.','{}','{}','{"frequency": 1, "text_unit_ids": ["f5cd08a5bba8e5f1cac73b2168b03f440d049e82b880cf5ff9b03a61f932ab149f55ecbff1e2e45fc298cd176b96304c704c6f0d04ce87977c3be47e617c941b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f91aa464-af5c-443d-ab23-315ede3b7bb0'::uuid,'WRIGHT BROTHERS'' FLYING MACHINE','MECHANISM','{}','The Wright brothers ultimately succeeded where earlier pioneers like Cayley, Du Temple, and Maxim had not. Their machine included full 6-axis control systems and understanding of stabilizing forces.','{}','{}','{"frequency": 1, "text_unit_ids": ["f5cd08a5bba8e5f1cac73b2168b03f440d049e82b880cf5ff9b03a61f932ab149f55ecbff1e2e45fc298cd176b96304c704c6f0d04ce87977c3be47e617c941b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('0f272903-5d5c-494c-8617-705be2e6e9c6'::uuid,'PROPULSION SYSTEM OF MAXIM','MECHANISM','{}','Maxim’s propulsion system involved a complex setup but it was insufficient for effectively powering his aircraft design fully.','{}','{}','{"frequency": 1, "text_unit_ids": ["f5cd08a5bba8e5f1cac73b2168b03f440d049e82b880cf5ff9b03a61f932ab149f55ecbff1e2e45fc298cd176b96304c704c6f0d04ce87977c3be47e617c941b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('418cbdd9-5e5d-439f-8589-d68ed7fd3476'::uuid,'WRIGHT SISTERS','PERSON','{}','While not explicitly mentioned, their contribution as part of the broader context can be inferred. The Wright sisters supported and played various roles in helping their brother Wilbur and Orville with early aviation experiments.','{}','{}','{"frequency": 1, "text_unit_ids": ["f5cd08a5bba8e5f1cac73b2168b03f440d049e82b880cf5ff9b03a61f932ab149f55ecbff1e2e45fc298cd176b96304c704c6f0d04ce87977c3be47e617c941b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d6caabf1-262a-4838-8ea4-2365962e471b'::uuid,'COMPRESSION AIR-POWERED VEHICLE OF MAXIM','MECHANISM','{}','Maxim experimented with compressed air as a power source for aircraft but it was not fully effective in powering his design as comprehensively as the Wrights'' efforts later on.','{}','{}','{"frequency": 1, "text_unit_ids": ["f5cd08a5bba8e5f1cac73b2168b03f440d049e82b880cf5ff9b03a61f932ab149f55ecbff1e2e45fc298cd176b96304c704c6f0d04ce87977c3be47e617c941b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f99c2cbe-d22b-4e6f-9bce-abe1e2114ebb'::uuid,'ADERS'' EXPERIMENTATION','MECHANISM','{}','Ader experimented with powered aircraft but his work lacked the full understanding of control mechanisms required for successful flights, as observed in the Wright brothers'' later advancements.','{}','{}','{"frequency": 1, "text_unit_ids": ["f5cd08a5bba8e5f1cac73b2168b03f440d049e82b880cf5ff9b03a61f932ab149f55ecbff1e2e45fc298cd176b96304c704c6f0d04ce87977c3be47e617c941b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9ee9c3bb-c591-4cf3-86f4-3d6972ffab7f'::uuid,'DIHEDRAL','MECHANISM','{}','Maxim used substantial dihedral in his design which provided some stability','{}','{}','{"frequency": 1, "text_unit_ids": ["ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('92766971-dcac-41b4-add9-8292909d8735'::uuid,'PENDULUM STABILITY','MECHANISM','{}','Based on Pendulum Stability, Maxim''s design relied heavily on natural stability rather than sophisticated control mechanisms','{}','{}','{"frequency": 2, "text_unit_ids": ["ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79", "ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('619e3edb-c003-421d-824f-41b532d1669e'::uuid,'CONTROLLED FLIGHT SYSTEM','SYSTEM','{}','The aeronauts were attempting to achieve sustained controlled flight but lacked the necessary mechanisms and systems for adequate control','{}','{}','{"frequency": 2, "text_unit_ids": ["ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79", "ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e2339678-4984-462f-8bb2-2cd3dd8d52ef'::uuid,'WHIRLING ARMS APPARATUS','DEVICE','{}','Lilienthal used whirling arms for empirical experiments which provided him with initial data about wing lift and drag but had some inaccuracies due to the Smeaton coefficient','{}','{}','{"frequency": 2, "text_unit_ids": ["ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79", "ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('cf3eefc0-cfc3-42c2-924f-6dbd7f05f1eb'::uuid,'WING LIFT AND DRAG DATA','MATERIAL','{}','Data from Lilienthal''s experiments, although not fully accurate, were sufficiently useful for his purpose in designing gliders','{}','{}','{"frequency": 2, "text_unit_ids": ["ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79", "ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ce8cbce7-e541-4fd2-a8df-11e1a65be87e'::uuid,'LIFT /DRAG POLARS','MECHANISM','{}','Lilienthal''s derived polars based on wing lift and drag data, useful but erroneous due to measurement methods','{}','{}','{"frequency": 2, "text_unit_ids": ["ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79", "ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('8f0a217d-7adc-4907-8451-e0c50b0d8a78'::uuid,'GLIDERS (MONOPLANE & BIPLANE)','DEVICE','{}','Lilienthal''s successful glider designs including both monoplanes and biplanes greatly influenced early aviation; gained much public attention, contributing to the field advancements','{}','{}','{"frequency": 2, "text_unit_ids": ["ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79", "ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c3f6b3d1-5d70-4ff2-a7b8-928c7202ae20'::uuid,'ALMA REDACTION OF DRAG','MECHANISM','{}','Streamlined shape concept introduced by Leonardo da Vinci to minimize drag','{}','{}','{"frequency": 2, "text_unit_ids": ["a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad", "a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('cb1853b1-027c-4b4d-b848-c61b7c3fc529'::uuid,'ENGINE','MECHANISM','{}','Lilienthal had plans to develop an engine for his best machines, aiming towards powered flight capabilities','{}','{}','{"frequency": 2, "text_unit_ids": ["ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79", "ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('47d445cf-5e12-49e9-9659-9fbc4619d514'::uuid,'PILOT''S BODY MOVEMENT CONTROL','MECHANISM','{}','Otto Lilienthal’s control mechanisms relied on the pilot manipulating the center-of-gravity (cg) position through body movement in response to forces exerted by the glider; useful for gliding but inadequate for sustained powered flight','{}','{}','{"frequency": 2, "text_unit_ids": ["ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79", "ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5c00325b-662b-4f2c-b7b7-9646bf14067e'::uuid,'GLIDING EXPERIENCE','EXPERIENCE','{}','Although Pilcher had significant flying experience, his limited understanding of aerodynamics led him away from Lilienthal’s data and into ineffective modifications like changing tailplane designs without adequate analysis','{}','{}','{"frequency": 2, "text_unit_ids": ["ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79", "ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3af72fc9-6a6a-4689-a20a-8f0d9795fbf2'::uuid,'ROLL AND YAW MECHANICS','MECHANISM','{}','Pilcher did not appear to have sufficient understanding of how changes in roll and yaw could affect lift distribution on the wing, limiting his effective control mechanisms for powered flight','{}','{}','{"frequency": 2, "text_unit_ids": ["ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79", "ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('4042e262-2736-486d-b3e2-db18ada8f517'::uuid,'ASPECT RATIO OF WINGS','MATERIAL','{}','The use of low aspect ratio wings by Pilcher would be inadequate for powered flight, requiring more power to achieve lift and stability; this was a significant design flaw in achieving controlled manned-powered flight','{}','{}','{"frequency": 2, "text_unit_ids": ["ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79", "ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('deb2117e-d353-4c3d-a56c-b7118fb50c61'::uuid,'S.P. LANGLEY','PERSON','{}','An astronomer with access to workshops who showed interest in aviation projects but did not contribute significantly to the development of control mechanisms, possibly due to his background in astronomy rather than engineering','{}','{}','{"frequency": 2, "text_unit_ids": ["ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79", "ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5d087a04-85d4-4e52-93d4-da390e164502'::uuid,'WORKSHOPS AND FACILITIES','SYSTEM','{}','Langley had resources like workshops which could have been utilized for experimental work related to aeronautics if he prioritized such projects','{}','{}','{"frequency": 2, "text_unit_ids": ["ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79", "ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('70e5d748-798c-4c69-ad50-18549d0687de'::uuid,'LANGLEY NO.5 MODEL','MODEL','{}','Langley''s No. 5 model, a large aerodynamic machine that could fly quite well with tandem wings and improvements in stability engineering.','{}','{}','{"frequency": 1, "text_unit_ids": ["baaa62fd839985ce0a3d03b2d98ddcadb6f3444480414cdd20d36ee69e47687c9474cf34e27996edfbc0ef5e505f086b7089d7dffa034ef135e1881d1386aee9"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('4295d37d-05dd-446c-9670-40dd7ad57b95'::uuid,'SP LANGLEY','PERSON','{}','S.P. Langley was an astronomer who pioneered work on lateral flight mechanics and developed various components for early attempts at manned flight','{}','{}','{"frequency": 1, "text_unit_ids": ["baaa62fd839985ce0a3d03b2d98ddcadb6f3444480414cdd20d36ee69e47687c9474cf34e27996edfbc0ef5e505f086b7089d7dffa034ef135e1881d1386aee9"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('4c834fde-cfc7-44d2-994d-41d9360c6f17'::uuid,'RUBBER POWERED MODEL AIRCRAFT','MODEL','{}','A smaller-scale version of the aerodrome designed and tested before transitioning to steam power for further advancements','{}','{}','{"frequency": 1, "text_unit_ids": ["baaa62fd839985ce0a3d03b2d98ddcadb6f3444480414cdd20d36ee69e47687c9474cf34e27996edfbc0ef5e505f086b7089d7dffa034ef135e1881d1386aee9"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('53aa4900-b310-4959-84a5-c43a8a199f6b'::uuid,'STEAM POWERED MODEL AIRCRAFT','MODEL','{}','An improved iteration of Langley''s initial experiments, demonstrating more promising results as it successfully flew longer distances.','{}','{}','{"frequency": 1, "text_unit_ids": ["baaa62fd839985ce0a3d03b2d98ddcadb6f3444480414cdd20d36ee69e47687c9474cf34e27996edfbc0ef5e505f086b7089d7dffa034ef135e1881d1386aee9"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c93708d9-c86c-4e47-b6c2-32e9ef2ac6cc'::uuid,'QUARTER-SCALE MODEL AIRCRAFT','MODEL','{}','Smaller version of the full-size aircraft used for preliminary testing to validate design concepts and performance estimates.','{}','{}','{"frequency": 1, "text_unit_ids": ["baaa62fd839985ce0a3d03b2d98ddcadb6f3444480414cdd20d36ee69e47687c9474cf34e27996edfbc0ef5e505f086b7089d7dffa034ef135e1881d1386aee9"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9eac7fec-6a5a-4bec-8ebf-475c03c11a5f'::uuid,'LANGLEY AERODROME','MECHANISM','{}','Langley''s final design, characterized by its large size and successful flights in 1896, marked the culmination of his efforts in flight mechanics research.','{}','{}','{"frequency": 1, "text_unit_ids": ["baaa62fd839985ce0a3d03b2d98ddcadb6f3444480414cdd20d36ee69e47687c9474cf34e27996edfbc0ef5e505f086b7089d7dffa034ef135e1881d1386aee9"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c503a30f-7cdd-4d34-83ff-64562f991fef'::uuid,'FULL-SIZE MAN-CARRYING MACHINE','DEVICE','{}','The full-size machine Langley built as part of his attempt to develop a powered aircraft, including critical components like the 38kW engine and tandem wing configuration.','{}','{}','{"frequency": 1, "text_unit_ids": ["baaa62fd839985ce0a3d03b2d98ddcadb6f3444480414cdd20d36ee69e47687c9474cf34e27996edfbc0ef5e505f086b7089d7dffa034ef135e1881d1386aee9"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('9c5c2813-14ce-4e8e-a22d-a0db2298b399'::uuid,'STEAM POWERED FLIGHT MECHANICS','MECHANISM','{}','Langley''s initial experiments with steam-powered aircraft contributed significantly to understanding the mechanics required for controlled flight, influencing later work on powered models and full-scale machines.','{}','{}','{"frequency": 1, "text_unit_ids": ["baaa62fd839985ce0a3d03b2d98ddcadb6f3444480414cdd20d36ee69e47687c9474cf34e27996edfbc0ef5e505f086b7089d7dffa034ef135e1881d1386aee9"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9eebed6c-0f57-4a9d-9c8b-a7af45153293'::uuid,'38KW ENGINE EXPERIMENTS','MECHANISM','{}','Experiments conducted by Langley''s team to test the 38kW engine before integrating it into his full-scale aircraft, crucial for ensuring power requirements were met.','{}','{}','{"frequency": 1, "text_unit_ids": ["baaa62fd839985ce0a3d03b2d98ddcadb6f3444480414cdd20d36ee69e47687c9474cf34e27996edfbc0ef5e505f086b7089d7dffa034ef135e1881d1386aee9"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('bf45ea0d-6e1b-4cd9-bd5c-d1d41c1c5244'::uuid,'POTOMAC HOUSEBOAT LAUNCHING SYSTEMS','DEVICE','{}','Langley''s catapult system on the Potomac houseboat was critical for launching his full-size and quarter-scale models into flight, facing initial issues that were later resolved.','{}','{}','{"frequency": 1, "text_unit_ids": ["baaa62fd839985ce0a3d03b2d98ddcadb6f3444480414cdd20d36ee69e47687c9474cf34e27996edfbc0ef5e505f086b7089d7dffa034ef135e1881d1386aee9"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ab0c0d27-e90e-4342-8009-1965966db34c'::uuid,'TANDEM WING FLIGHT MECHANICS','MECHANISM','{}','Langley’s tandem wing design addressed stability issues found in earlier models, leading to successful flights and critical lessons for future designs.','{}','{}','{"frequency": 1, "text_unit_ids": ["baaa62fd839985ce0a3d03b2d98ddcadb6f3444480414cdd20d36ee69e47687c9474cf34e27996edfbc0ef5e505f086b7089d7dffa034ef135e1881d1386aee9"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('525b9c4d-61a2-4125-b56a-27a81f290d6e'::uuid,'MODEL B AEROFOIL101','MODEL','{}','Specific model used for testing in the wind tunnel, similar to the #12 foil tested by the Wrights','{}','{}','{"frequency": 2, "text_unit_ids": ["f00e0f4896ef7e654f0b9064f83af4a50743e28b0dcf2bd9e4690fa37d4b7715ac4b7e0182423e2ed1d7e43936675d08dd37ec7927a4af85700aaa71e0999b32", "f00e0f4896ef7e654f0b9064f83af4a50743e28b0dcf2bd9e4690fa37d4b7715ac4b7e0182423e2ed1d7e43936675d08dd37ec7927a4af85700aaa71e0999b32"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c8b08813-38e9-4a79-bec3-db37eae2542b'::uuid,'WRIGHT''S FLYING MACHINE','DEVICE','{}','The device, a heavier than air powered machine, that the Wright brothers made and flew successfully','{}','{}','{"frequency": 2, "text_unit_ids": ["f00e0f4896ef7e654f0b9064f83af4a50743e28b0dcf2bd9e4690fa37d4b7715ac4b7e0182423e2ed1d7e43936675d08dd37ec7927a4af85700aaa71e0999b32", "f00e0f4896ef7e654f0b9064f83af4a50743e28b0dcf2bd9e4690fa37d4b7715ac4b7e0182423e2ed1d7e43936675d08dd37ec7927a4af85700aaa71e0999b32"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5e89b6ce-3e2a-4ee0-95c4-bdcd89e05f12'::uuid,'STATIC AEROELASTIC DIVERGENCE','MECHANISM','{}','The mechanism of wing failure speculated but not confirmed as the cause for the second flight''s issues','{}','{}','{"frequency": 1, "text_unit_ids": ["f00e0f4896ef7e654f0b9064f83af4a50743e28b0dcf2bd9e4690fa37d4b7715ac4b7e0182423e2ed1d7e43936675d08dd37ec7927a4af85700aaa71e0999b32"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6115ce22-a4c4-4392-b6c2-669ee80a119d'::uuid,'FLOW SEPARATION','MECHANISM','{}','Flow separation refers to a phenomenon where fluid flow detaches from surfaces, impacting aerodynamics and lift/drag ratios.','{}','{}','{"frequency": 1, "text_unit_ids": ["344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('7077058a-c0cb-4e86-8da7-eccb931f804a'::uuid,'DARVINIS''S THEORIS','MODEL','{}','Theoriz of Da Vinci did not widely understand the concept of flow separation until after his time','{}','{}','{"frequency": 1, "text_unit_ids": ["344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b7fe964c-4106-4cb0-980d-e7d8c22482c9'::uuid,'20TH CENTURY','SYSTEM','{}','Period in history where the significance of flow separation was more broadly recognized and understood','{}','{}','{"frequency": 2, "text_unit_ids": ["344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997", "344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('32b59c7f-fbad-4240-9d87-98c88a0f6e40'::uuid,'FORCE MEASUREMENT DEVICES','MECHANISM','{}','Early tools used to measure forces, often crude, lacking in precision and uniformity','{}','{}','{"frequency": 1, "text_unit_ids": ["344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('4d63b652-e01a-4338-b33c-0cfe418454b2'::uuid,'CYLINDRICAL ARM EXPERIMENTS','EXPERIMENT','{}','Investigations involving whirling arms, a primitive method for studying circulation flows at the time','{}','{}','{"frequency": 2, "text_unit_ids": ["344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997", "344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('87e09a28-5648-4960-beb6-5830f0ab8c6d'::uuid,'FIRE LANTERN','DEVICE','{}','The flying lantern is a prototype of a hot-air balloon, initially used for instilling fear among enemies','{}','{}','{"frequency": 1, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('dee04203-90db-4c78-a7b6-64c067fab3f1'::uuid,'PAPER BAG','MATERIAL','{}','Paper bags were used to create the fabric envelope in early prototypes of hot-air balloons and flying lanterns','{}','{}','{"frequency": 1, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('1eacabd8-9a8b-4d41-adff-2b1ee3d5abe2'::uuid,'LAMP','DEVICE','{}','Lamps provided heat for generating lift using hot air in balloons and lanterns','{}','{}','{"frequency": 1, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('2a7d6c43-3948-4961-bc1c-67f901efc2fc'::uuid,'PAPER KITE','DEVICE','{}','Paper kites were used to tether a man during the 6th century AD, possibly inspired by earlier prototypes.','{}','{}','{"frequency": 1, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('85744842-3631-4d50-bd67-b4b8955b49c7'::uuid,'WIND TUNNEL PRACTICE','SYSTEM','{}','Early practices in wind tunnel use, often characterized by poor non-uniform flow fields and lack of systematic procedures','{}','{}','{"frequency": 1, "text_unit_ids": ["344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ab9152a9-0481-48f1-af91-fedcbb4600fa'::uuid,'LOW TURBULENCE FLOW FIELD','MATERIAL','{}','Desired condition for more accurate measurements, though not always achieved due to the state-of-the-art technology limitations','{}','{}','{"frequency": 1, "text_unit_ids": ["344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('02dda6d3-c73e-42c4-a5a2-12f42e6f5132'::uuid,'LIFT-DRAG RATIO','MECHANISM','{}','Ratio of lift to drag forces, important in understanding aircraft performance dynamics and improving flight capabilities','{}','{}','{"frequency": 1, "text_unit_ids": ["344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('2b6726fe-a2e4-4aec-be6e-3921e12c9dc9'::uuid,'CAMBERED AEROFOILS','DEVICE','{}','Aerofoil shapes that have the upper surface made significantly steeper than the lower one to improve aerodynamic efficiency','{}','{}','{"frequency": 2, "text_unit_ids": ["344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997", "344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('7af09efe-5cc1-472c-b5b9-88112a1dccde'::uuid,'CENTRE OF PRESSURE','MECHANISM','{}','Point on an airfoil where the resultant force of airflow acts, influencing lift and drag properties','{}','{}','{"frequency": 1, "text_unit_ids": ["344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a24a07c8-bbe4-4c8e-aad9-1a0c184c34e8'::uuid,'LIFT DEPENDENCE ON Α NOT ON SIN2Α','MODEL','{}','For small angles, lift depends linearly on angle of attack (α) rather than sinusoidal power terms','{}','{}','{"frequency": 1, "text_unit_ids": ["344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('154829b7-555e-4a96-9ba4-72484a6866e9'::uuid,'WING FLIGHT EXPERIMENTS','EXPERIMENT','{}','Investigations involving actual wing flight tests to study aerodynamic properties and performance','{}','{}','{"frequency": 2, "text_unit_ids": ["344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997", "344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3544d108-8c8b-4664-90f4-657d9334cf3a'::uuid,'3D WINGS','SYSTEM','{}','Modern airfoil geometry in three dimensions, more complex than the two-dimensional models studied earlier','{}','{}','{"frequency": 1, "text_unit_ids": ["344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('dd658b21-dcef-4ee1-b323-f77d12584057'::uuid,'2D AEROFOILS','MODEL','{}','Traditional simplified flat plates used as a basic study for aerodynamics and flight dynamics','{}','{}','{"frequency": 2, "text_unit_ids": ["344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997", "344efe13bfabd43811b4b92dcd8830e39b7952af8db7d1ec81c9c2c4ffb2902bb61610c1f9f1d14538c7ab4395ddd352f1f6ee30c1e6bfd2e85df38700699997"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('76cab97e-08c4-438f-b1c3-618b0b53724a'::uuid,'WIKIPEDIA','SYSTEM','{}','Wikipedia describes humanity''s dream of flight and key historical milestones in aviation','{}','{}','{"frequency": 1, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('321749ee-152b-4bfb-9b54-5fa2c6011266'::uuid,'ABBASE IBN FIRNAS','PERSON','{}','Abbas ibn Firnas was 9th-century Al-Andalus''s pioneer in controlled hang-glider flight','{}','{}','{"frequency": 1, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('4195d053-33c0-43f4-a7f2-144a3c78889f'::uuid,'WINGS','MECHANISM','{}','Imitative wings were constructed to attempt human flight, starting with Daedalus''s mythical construction and continuing until the 17th century; they were often attached to high towers but rarely successful','{}','{}','{"frequency": 1, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6642c7b6-de40-44fd-a89b-3a312f3be1de'::uuid,'D AEDELUS','PERSON','{}','Daedalus is a mythical figure attributed with constructing imitative wings which allowed him to fly from Crete','{}','{}','{"frequency": 1, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('768533ad-a04a-410b-946b-90457a833b65'::uuid,'TARANTUM','GEO','{}','Tarantum was the region in ancient Greece where Archytas of Tarentum worked and potentially pioneered flying machines','{}','{}','{"frequency": 1, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('90591554-a6d8-4579-b724-65432865c421'::uuid,'FLYING PIGEON','DEVICE','{}','Archytas, a Greek philosopher, mathematician, astronomer, statesman, and strategist, developed the first known flying machine, called the Flying Pigeon which could fly about 200 meters.','{}','{}','{"frequency": 1, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6be23d30-4533-4702-9f5b-00c121f3b366'::uuid,'WOODEN BIRD','MECHANISM','{}','A large paper structure supported with wooden elements that was constructed in the 5th century AD; it may have been used for flight experiments','{}','{}','{"frequency": 1, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('edce2c0f-9f32-4a12-be5e-9cfd4768f790'::uuid,'CHINESE FLIGHT LANTERN','DEVICE','{}','The Chinese flight lantern, a prototype of a hot-air balloon with a fabric envelope filled with hot air, used by General Zhuge Liang to instill fear in enemy troops through the 3rd century BC.','{}','{}','{"frequency": 1, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6aac5d3a-6382-475e-8740-8b84056eb40e'::uuid,'WAX AND FEATHERS','MATERIAL','{}','Materials used to construct imitative wings in early flight experiments were often wax and feathers, symbolizing human efforts to mimic nature for the purposes of flight.','{}','{}','{"frequency": 1, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6b8eb539-b806-40f6-9f1d-bc45c124152c'::uuid,'HOT AIR BALLOONS','DEVICE','{}','Known in China by the 3rd century BC','{}','{}','{"frequency": 1, "text_unit_ids": ["ce6b5bf047905c10664374fb49d23d3216e192e2a564c6bafca1f58cbb43577b7a825598664c39e99d438a006e69f57882a5588711fddc205867ae05aa428ea2"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('808c38c5-1dea-4900-aecb-0b5da31062cb'::uuid,'RECTANGULAR LAMPS','SYSTEM','{}','Permanent feature of festivals during the Yuan Dynasty (13th century), may have spread along the Great Silk Road to Central Asia and the Middle East by the Mongol period','{}','{}','{"frequency": 2, "text_unit_ids": ["ce6b5bf047905c10664374fb49d23d3216e192e2a564c6bafca1f58cbb43577b7a825598664c39e99d438a006e69f57882a5588711fddc205867ae05aa428ea2", "ce6b5bf047905c10664374fb49d23d3216e192e2a564c6bafca1f58cbb43577b7a825598664c39e99d438a006e69f57882a5588711fddc205867ae05aa428ea2"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f6a030ee-a19a-4407-8a1a-f6a4251d3173'::uuid,'FLOATING LANTERNS','COMPONENT','{}','Similar in Tibetan and Indian festivities, with a rectangular lamp inside thin paper by the 13th century','{}','{}','{"frequency": 2, "text_unit_ids": ["ce6b5bf047905c10664374fb49d23d3216e192e2a564c6bafca1f58cbb43577b7a825598664c39e99d438a006e69f57882a5588711fddc205867ae05aa428ea2", "ce6b5bf047905c10664374fb49d23d3216e192e2a564c6bafca1f58cbb43577b7a825598664c39e99d438a006e69f57882a5588711fddc205867ae05aa428ea2"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('558085dd-5d47-4f8a-9396-896d274f1004'::uuid,'MANNED KITE FLIGHT','SYSTEM','{}','First documented event where Gao Yang sent Yuan Huangtou on a kite from his capital Ye in 559, which landed alive but was executed soon after','{}','{}','{"frequency": 2, "text_unit_ids": ["ce6b5bf047905c10664374fb49d23d3216e192e2a564c6bafca1f58cbb43577b7a825598664c39e99d438a006e69f57882a5588711fddc205867ae05aa428ea2", "ce6b5bf047905c10664374fb49d23d3216e192e2a564c6bafca1f58cbb43577b7a825598664c39e99d438a006e69f57882a5588711fddc205867ae05aa428ea2"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f8d60f31-380e-4d95-8f25-5902cd64c97d'::uuid,'ABBAS IBN FIRNAS''S UMBRELLA-LIKE DEVICE','DEVICE','{}','Fabric stretched over wooden struts, jumped from the Great Mosque minaret in Córdoba in 852 with minor injuries upon landing by Emir Abd ar-Rahman II''s patronage','{}','{}','{"frequency": 2, "text_unit_ids": ["ce6b5bf047905c10664374fb49d23d3216e192e2a564c6bafca1f58cbb43577b7a825598664c39e99d438a006e69f57882a5588711fddc205867ae05aa428ea2", "ce6b5bf047905c10664374fb49d23d3216e192e2a564c6bafca1f58cbb43577b7a825598664c39e99d438a006e69f57882a5588711fddc205867ae05aa428ea2"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('819ba575-76c7-4986-82da-d251caa16018'::uuid,'KUBLAI KHAN','PERSON','{}','Ruler of the Yuan Dynasty, who oversaw the development of rectangular lamps during his reign','{}','{}','{"frequency": 1, "text_unit_ids": ["ce6b5bf047905c10664374fb49d23d3216e192e2a564c6bafca1f58cbb43577b7a825598664c39e99d438a006e69f57882a5588711fddc205867ae05aa428ea2"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('aa2d587d-4185-40a4-a903-84210ca2b513'::uuid,'GAO HUAN','PERSON','{}','General and later emperor after Gao Yang, mentioned for launching Yuan Huangtou in a kite flight','{}','{}','{"frequency": 1, "text_unit_ids": ["ce6b5bf047905c10664374fb49d23d3216e192e2a564c6bafca1f58cbb43577b7a825598664c39e99d438a006e69f57882a5588711fddc205867ae05aa428ea2"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c081368a-3e24-40be-b5f9-3c5b135551f7'::uuid,'EMIR ABD AR-RAHMAN II','PERSON','{}','Patron of Abbas ibn Firnas during the Umayyad Caliphate','{}','{}','{"frequency": 1, "text_unit_ids": ["ce6b5bf047905c10664374fb49d23d3216e192e2a564c6bafca1f58cbb43577b7a825598664c39e99d438a006e69f57882a5588711fddc205867ae05aa428ea2"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ad48c558-e8a9-4a61-b1e3-0b87856bd694'::uuid,'ABBAS IBN FIRNAS','PERSON','{}','Arab scholar and inventor who experimented with flight devices in Muslim Spain','{}','{}','{"frequency": 1, "text_unit_ids": ["ce6b5bf047905c10664374fb49d23d3216e192e2a564c6bafca1f58cbb43577b7a825598664c39e99d438a006e69f57882a5588711fddc205867ae05aa428ea2"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ff790065-3f43-4948-95ef-8524c92d6ea6'::uuid,'MARCO POLO','PERSON','{}','Italian explorer who noted the ability of kites to lift a person, which was evident several centuries before his time','{}','{}','{"frequency": 1, "text_unit_ids": ["ce6b5bf047905c10664374fb49d23d3216e192e2a564c6bafca1f58cbb43577b7a825598664c39e99d438a006e69f57882a5588711fddc205867ae05aa428ea2"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('21bd10ee-9aa5-4a4e-81af-b403d5c14c9c'::uuid,'HEZÂRFEN AHMED ÇELEBI''S WINGED APPARATUS','DEVICE','{}','A device enabling Hezârfen to fly across the Bosphorus from the Galata Tower in 1632','{}','{}','{"frequency": 1, "text_unit_ids": ["46b667214423448900a64449a21a8d78137e40dbbcde1ff7361b13892626a596937541e8a1dff8c28756c1af322bcfde1298239045005d93a04cd46043247c20"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('127e7d40-36f1-4194-b8b6-547748dc6765'::uuid,'MAN-POWERED GLIDER','DEVICE','{}','The MAN-POWERED GLIDER is a device that enables people to attempt human flight through their own physical effort. This concept traces back to early experiments such as the one conducted by Ibn Firnas, who, around the 9th or 10th century, invented a flying machine resembling wings. Built with visionary intent for controlled flight, Ibn Firnas'' device inspired later inventors, including Leonardo da Vinci, who conceptualized hang gliders. Together, these pioneering efforts laid the groundwork for future developments in human-powered airplanes and gliders, albeit not initially successful, they contributed significantly to the advancement of aviation technology.','{}','{}','{"frequency": 2, "text_unit_ids": ["46b667214423448900a64449a21a8d78137e40dbbcde1ff7361b13892626a596937541e8a1dff8c28756c1af322bcfde1298239045005d93a04cd46043247c20", "46b667214423448900a64449a21a8d78137e40dbbcde1ff7361b13892626a596937541e8a1dff8c28756c1af322bcfde1298239045005d93a04cd46043247c20"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5064d1f4-1712-4793-90f7-ad07d4498dfd'::uuid,'EUROPEAN RENAISSANCE','MODEL','{}','A cultural and intellectual revival during the late Middle Ages to early modern period that saw a renewed interest in classical culture, encouraging innovation in fields like aviation as evidenced by Leonardo''s work with hang gliders<|','{}','{}','{"frequency": 1, "text_unit_ids": ["46b667214423448900a64449a21a8d78137e40dbbcde1ff7361b13892626a596937541e8a1dff8c28756c1af322bcfde1298239045005d93a04cd46043247c20"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9661ccd5-97c1-4703-ab55-9867b36ae662'::uuid,'GUNPOWDER','MATERIAL','{}','Material used to fill the cavities of the rocket for propulsion','{}','{}','{"frequency": 1, "text_unit_ids": ["46b667214423448900a64449a21a8d78137e40dbbcde1ff7361b13892626a596937541e8a1dff8c28756c1af322bcfde1298239045005d93a04cd46043247c20"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('0e57730a-362b-4a1e-a0ad-2da385c563ab'::uuid,'CAGE','COMPONENT','{}','Component of the rocket designed by Lagari Hasan Çelebi','{}','{}','{"frequency": 1, "text_unit_ids": ["46b667214423448900a64449a21a8d78137e40dbbcde1ff7361b13892626a596937541e8a1dff8c28756c1af322bcfde1298239045005d93a04cd46043247c20"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('65c61ad2-1ad7-4a76-9b61-4b16a716fb85'::uuid,'CONICAL TOP','PART','{}','Part of the design of the rocket built by Lagari Hasan Çelebi','{}','{}','{"frequency": 1, "text_unit_ids": ["46b667214423448900a64449a21a8d78137e40dbbcde1ff7361b13892626a596937541e8a1dff8c28756c1af322bcfde1298239045005d93a04cd46043247c20"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
