	 ('fbd62739-e5a6-4293-8196-a0613e3c6829'::uuid,'IPOD FIRNAS'' FLYING MACHINE','DEVICE','{}','Ibn Firnas'' device, a man-powered glider developed as one of the first attempts at controlled flight in 9th or 10th century','{}','{}','{"frequency": 1, "text_unit_ids": ["46b667214423448900a64449a21a8d78137e40dbbcde1ff7361b13892626a596937541e8a1dff8c28756c1af322bcfde1298239045005d93a04cd46043247c20"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('af6335f9-4c37-494d-a531-a6c251d8e2d5'::uuid,'LEONARDO DA VINCI''S HANG GLIDER DESIGN','MODEL','{}','Theoretical drawings and calculations that led to the implementation of a functional device by others like Faust Vrančić','{}','{}','{"frequency": 1, "text_unit_ids": ["46b667214423448900a64449a21a8d78137e40dbbcde1ff7361b13892626a596937541e8a1dff8c28756c1af322bcfde1298239045005d93a04cd46043247c20"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e323fe4a-cb3f-48a1-b11a-da139d28a517'::uuid,'LAGARIE HASAN ÇELEBI','PERSON','{}','The person who conducted the first known example of a manned rocket flight during Sultan Murad IV''s celebrations','{}','{}','{"frequency": 1, "text_unit_ids": ["624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('1e37603c-3daa-4fe7-8402-07c5ec777d81'::uuid,'FRANCESCO DE LANA-TERZI','PERSON','{}','Person who proposed a lighter-than-air apparatus made of spheres with a vacuum created for flight, published before 1670','{}','{}','{"frequency": 3, "text_unit_ids": ["624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5", "624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5", "624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('891ad321-bca9-42fe-a350-9e9790910cc7'::uuid,'LIGHTER-THAN-AIR APPARATUS','DEVICE','{}','A flying device designed by Francesco de Lana-Terzi using spheres from which air could be evacuated to decrease its density and allow it to ascend.>','{}','{}','{"frequency": 3, "text_unit_ids": ["624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5", "624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5", "624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('4c0fe7ca-7a4e-47f7-91c9-6251ad8bc4d8'::uuid,'GLIDERS','DEVICE','{}','Airborne vehicles designed for sustained unpowered flight, often used for research into aerodynamics and early attempts at piloting air travel.','{}','{}','{"frequency": 3, "text_unit_ids": ["624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5", "624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5", "624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3c83e551-332e-4911-ae9b-0e499f23e584'::uuid,'WING WARP','MECHANISM','{}','Technique where the shape of wing surfaces is changed during flight, originally developed by the Wright brothers.>','{}','{}','{"frequency": 3, "text_unit_ids": ["624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5", "624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5", "624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b39265ef-f985-417b-9e12-290151900d85'::uuid,'LA FRANCE (AIRSHIP)','DEVICE','{}','"Air Ship" developed by Charles Renard and Arthur Krebs, first fully controlled free flight airship launched in 1884.>','{}','{}','{"frequency": 3, "text_unit_ids": ["624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5", "624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5", "624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('89f63ca6-9371-440e-b88a-0e9712ab7084'::uuid,'STEAM ENGINE','MECHANISM','{}','Used to power Giffard''s airship, 1852.>','{}','{}','{"frequency": 3, "text_unit_ids": ["624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5", "624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5", "624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e59157a1-3d5f-4327-8299-143a20a99277'::uuid,'SOUNDING BALLOONS','DEVICE','{}','Balloon technology used to popularize altitude exploration and air travel during the late 18th century.>','{}','{}','{"frequency": 3, "text_unit_ids": ["624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5", "624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5", "624b0f2e5156161ffdb09c558f32b39ad0bf347e1dcc51d0cc803eb1592f75125b51005c9a82dfcfa9afb96df74b8311d90272937604af08308a19e41b14f3c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('25a06cc8-90fe-4f4b-b47d-8865cc5a9552'::uuid,'ORNITHOPTER','DEVICE','{}','Devices designed by Leonardo da Vinci meant to mimic bird wings under human muscular power, none realized but influenced aerodynamic thought','{}','{}','{"frequency": 2, "text_unit_ids": ["a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad", "a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('57a7ecfd-2b5a-453e-b7df-8ca5bea3b5e5'::uuid,'LA FRANCE','SYSTEM','{}','The French military electric-powered airship developed in 1884 by Charles Renard and Arthur Krebs, covering 8 km in 23 minutes with an 8.5 hp engine','{}','{}','{"frequency": 1, "text_unit_ids": ["335e085fd6d0950373e690c3dfa99dacf6ded0df7007db03f94def10a1aeb7d55a54302596740d65bce43516315326647e94e473b0df3e8a1e385c4dcd8ff1b1"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('64ad9737-9360-4eae-8e28-99a7e62d4d73'::uuid,'INTERNAL COMBUSTION ENGINE','MECHANISM','{}','Engine mechanism that enabled regular controlled flights after the early airships were short-lived and fragile','{}','{}','{"frequency": 2, "text_unit_ids": ["335e085fd6d0950373e690c3dfa99dacf6ded0df7007db03f94def10a1aeb7d55a54302596740d65bce43516315326647e94e473b0df3e8a1e385c4dcd8ff1b1", "335e085fd6d0950373e690c3dfa99dacf6ded0df7007db03f94def10a1aeb7d55a54302596740d65bce43516315326647e94e473b0df3e8a1e385c4dcd8ff1b1"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('4a160bfc-f68e-4f49-bbbb-20ad467c0113'::uuid,'CONTROLLABLE PARACHUTE','DEVICE','{}','Device designed by Sir George Cayley that had two large oars or wings to create lift for controlled parachute descents','{}','{}','{"frequency": 2, "text_unit_ids": ["335e085fd6d0950373e690c3dfa99dacf6ded0df7007db03f94def10a1aeb7d55a54302596740d65bce43516315326647e94e473b0df3e8a1e385c4dcd8ff1b1", "335e085fd6d0950373e690c3dfa99dacf6ded0df7007db03f94def10a1aeb7d55a54302596740d65bce43516315326647e94e473b0df3e8a1e385c4dcd8ff1b1"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('369c33e7-4f94-4b8f-a5e1-bc5c47322c63'::uuid,'GLIDER DESIGNED BY GEORGE CAYLEY','SYSTEM','{}','The GLIDER DESIGNED BY GEORGE CAYLEY is a significant historical aircraft produced in 1799. This design incorporated several innovative features that would influence the development of aviation, including a tail for control and a positioned pilot below the center of mass to enhance stability. As per records, this glider successfully flew in 1804, marking an important milestone in early aerial experimentation. This particular iteration by Cayley laid foundational principles for subsequent gliders and highlighted the importance of aerodynamic design elements such as tail positioning and pilot placement for stable flight.','{}','{}','{"frequency": 2, "text_unit_ids": ["335e085fd6d0950373e690c3dfa99dacf6ded0df7007db03f94def10a1aeb7d55a54302596740d65bce43516315326647e94e473b0df3e8a1e385c4dcd8ff1b1", "335e085fd6d0950373e690c3dfa99dacf6ded0df7007db03f94def10a1aeb7d55a54302596740d65bce43516315326647e94e473b0df3e8a1e385c4dcd8ff1b1"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('03a132fb-ed1a-4cd4-a755-be05dde1133f'::uuid,'EERIEMAN SWEDENBORG','PERSON','{}','Swedish theologian who published "Sketches of a Machine for Flying in the Air" in 1716','{}','{}','{"frequency": 1, "text_unit_ids": ["335e085fd6d0950373e690c3dfa99dacf6ded0df7007db03f94def10a1aeb7d55a54302596740d65bce43516315326647e94e473b0df3e8a1e385c4dcd8ff1b1"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('234733f4-df12-45f5-af38-95fea0e3501f'::uuid,'TIRUZIA','GEO','{}','Capital city in Firuzabad where Aurelians were initially held as hostages during the hostage exchange scenario','{}','{}','{"frequency": 1, "text_unit_ids": ["335e085fd6d0950373e690c3dfa99dacf6ded0df7007db03f94def10a1aeb7d55a54302596740d65bce43516315326647e94e473b0df3e8a1e385c4dcd8ff1b1"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c0d4f1aa-1ed6-4c49-9b8f-55d3ced58bad'::uuid,'KROHAARA','GEO','{}','Capital city of Quintara, which hosted the swap and subsequent flights after the hostage release agreement.','{}','{}','{"frequency": 1, "text_unit_ids": ["335e085fd6d0950373e690c3dfa99dacf6ded0df7007db03f94def10a1aeb7d55a54302596740d65bce43516315326647e94e473b0df3e8a1e385c4dcd8ff1b1"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e2932507-d998-4e48-b145-e8a077cbb3e6'::uuid,'AURELIANS HOSPITALITY OFFICIALS','PERSON','{}','Senior Aurelian officials who welcomed hostages at Krohaara upon their release and facilitated their journey back home.','{}','{}','{"frequency": 1, "text_unit_ids": ["335e085fd6d0950373e690c3dfa99dacf6ded0df7007db03f94def10a1aeb7d55a54302596740d65bce43516315326647e94e473b0df3e8a1e385c4dcd8ff1b1"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('db1cb422-958a-4880-a5f0-ee1bd6c430fb'::uuid,'CENTER OF MASS','COMPONENT','{}','The center of mass was used as a mechanism to stabilize the flight of early models','{}','{}','{"frequency": 1, "text_unit_ids": ["faa334cc3a5b50c3cebcf1df46beb7be9ad777690802933a651dec6cbd0da34c9fef6dd95627eca4b6a746fc7c67bc72b217d1c4e60e92895dbfef4b8412f573"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
