	 ('bd6ccba5-d1e8-4772-8f4b-3cbbc08a1365'::uuid,'ZHUGE LIANG','PERSON','{}','Chinese general who lived from 180–234 AD, attributed with inventing the flying lantern','{}','{}','{"frequency": 1, "text_unit_ids": ["93598286bf41252a5653b865693926a10004c8895f439d179e7df23951875f9be08961897007b5955c71dd93076ae3119f0c8ca810440b7e216291c012b3265d"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a0f36047-a246-44fe-b1cd-9c9a4c5c63c5'::uuid,'BOSPHORUS','MATERIAL','{}','The Bosphorus is a strait connecting the Black Sea and the Marmara Sea','{}','{}','{"frequency": 1, "text_unit_ids": ["5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d304929e-8375-4d8e-8735-58bddbb32ead'::uuid,'FIXED WING','MECHANISM','{}','A fixed wing mechanism that remains in a fixed position during flight, facilitating sustained powered lift through aerodynamics','{}','{}','{"frequency": 1, "text_unit_ids": ["5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('de673617-61ce-416f-90ac-fbe3eb58b850'::uuid,'MUSCULAR POWER','MECHANISM','{}','Refers to the muscular effort applied by the pilot without mechanical apparatuses. It was used as an energy source before fixed-winged aircraft had motors driven by non-human factors.','{}','{}','{"frequency": 2, "text_unit_ids": ["5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5", "5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('59e89c45-7d76-4411-896e-2745862abf93'::uuid,'MOVABLE WINGS','MECHANISM','{}','Wings that can flap or move during flight to generate motion, inspired by birds and used before fixed-wing designs were developed.','{}','{}','{"frequency": 2, "text_unit_ids": ["5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5", "5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('1056652b-dead-4ea4-ab18-a2e358bfe960'::uuid,'M. V. LOMONOSOV','PERSON','{}','A Russian scientist who documented practical designs for aircraft, especially the heavier-than-air aircraft.','{}','{}','{"frequency": 2, "text_unit_ids": ["5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5", "5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d5a4d21a-1b8e-44aa-94ae-f2131f9125a8'::uuid,'HOT-SMOKE','MECHANISM','{}','A means by which hot smoke is used to rise in the air and create lift for heavier-than-air aircraft.','{}','{}','{"frequency": 2, "text_unit_ids": ["5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5", "5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('8d181118-0542-4263-bb2c-f9348aa34011'::uuid,'JACQUES-ÉTIENTE MONTGOLFIER','PERSON','{}','One of the French brothers who designed and launched the first hot-air balloon.','{}','{}','{"frequency": 2, "text_unit_ids": ["5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5", "5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e60f06b5-506f-4d60-aee2-7c883b42ad58'::uuid,'MEANDER','MECHANISM','{}','A complex system or path that winds around in many curves; often used to describe balloon flight.','{}','{}','{"frequency": 1, "text_unit_ids": ["5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('8b2403d5-d916-43bb-b98d-47f7532d004c'::uuid,'JEAN-FRANCOIS PILÂTRE DE ROZIER','PERSON','{}','A French physicist who was the first to ascend in a hot-air balloon along with Marquis d''Arlandes.','{}','{}','{"frequency": 2, "text_unit_ids": ["5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5", "5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
