	 ('a47d0b13-2f19-4849-ae1a-adb2ac3af1d0'::uuid,'ENGLISH CHANNEL','GEO','{}','A sea area separating southern England and northern France, crossed by Jean Blanchard in a balloon in 1785.','{}','{}','{"frequency": 2, "text_unit_ids": ["5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5", "5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
