	 ('48d18292-d962-4c8f-ab62-919e8d64a537'::uuid,'COUTELLE','PERSON','{}','French physicist who used balloons for military reconnaissance, marking the first use of aircraft in warfare.','{}','{}','{"frequency": 2, "text_unit_ids": ["5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5", "5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d842d55f-eccb-44e1-b83c-24faf0614533'::uuid,'ANDRÉ-JACQUES GARNERIN','PERSON','{}','Frenchman who made the first free-fall parachute jump from a balloon in 1797.','{}','{}','{"frequency": 2, "text_unit_ids": ["5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5", "5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('caa946e8-9b49-432f-9a5b-2c4495776852'::uuid,'AERIAL BOMBING','MECHANISM','{}','Deploying bombs from an aircraft to target locations ground-based artillery couldn''t reach.','{}','{}','{"frequency": 2, "text_unit_ids": ["5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5", "5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9515f21d-45cb-4a19-8fad-86781d4028b5'::uuid,'JACQUES GARNERIN','PERSON','{}','Jacques Garnerin is well-known for his jump from a balloon at an altitude of about 800 m','{}','{}','{"frequency": 1, "text_unit_ids": ["b93603f69bb902d6bc4a15e32e34bac0942d14f58f5b7fd54e0187ddc73790c3986b6f906396ba733338823b8e99640c1794d84bcc0a8862b2e18fb964601739"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('45666601-c339-40a7-aa0f-e98841045df4'::uuid,'AEROSTAT','DEVICE','{}','Originally used to describe any type of lighter than air aircraft that can be made to stay in the air, now often associated with tethered balloons but also historically encompasses dirigibles and helicopters','{}','{}','{"frequency": 2, "text_unit_ids": ["b93603f69bb902d6bc4a15e32e34bac0942d14f58f5b7fd54e0187ddc73790c3986b6f906396ba733338823b8e99640c1794d84bcc0a8862b2e18fb964601739", "b93603f69bb902d6bc4a15e32e34bac0942d14f58f5b7fd54e0187ddc73790c3986b6f906396ba733338823b8e99640c1794d84bcc0a8862b2e18fb964601739"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
