	 ('63e1d854-ed7e-481c-9ab8-4514598c6ffa'::uuid,'ALHAMIA PRISON','PLACE','{}','Alhamia Prison is where Samuel Namara, an Aurelian hostage, was held before the hostage exchange.','{}','{}','{"frequency": 1, "text_unit_ids": ["3ea69086c604fb251a4059f678ec83b99d67d511efb1c29354f7c0b54808defd6170d2ee03e45660f508dc039db22634dfa65c013414a6a31a8795a58d791441"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6cb10033-c5b9-4199-b635-bbf5011a993e'::uuid,'CASHION','PLACE','{}','Cashion is the capital of Aurelia where the exchanged hostages are now headed post-exchange.','{}','{}','{"frequency": 1, "text_unit_ids": ["3ea69086c604fb251a4059f678ec83b99d67d511efb1c29354f7c0b54808defd6170d2ee03e45660f508dc039db22634dfa65c013414a6a31a8795a58d791441"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('344cb5b5-edf8-4934-ab46-86300a557f03'::uuid,'SAMUEL NAMARA','PERSON','{}','39-year-old businessman, held hostage and later exchanged from Tiruzia prison.','{}','{}','{"frequency": 1, "text_unit_ids": ["3ea69086c604fb251a4059f678ec83b99d67d511efb1c29354f7c0b54808defd6170d2ee03e45660f508dc039db22634dfa65c013414a6a31a8795a58d791441"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('933c69eb-d738-47da-8318-a853922e7faa'::uuid,'WIND TUNNELS IN ITALY, GERMANY, FRANCE, BRITAIN, USA LABS','SYSTEM','{}','Prior to World War I, wind tunnel research was a key focus for institutions in Italy, Germany, France, Britain, and the USA. These laboratories were dedicated to optimally configuring their facilities for testing and study. The pre-war period saw significant advancements and theoretical developments in this field among these nations.
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('58d80011-e036-4d26-98ec-602cae40b176'::uuid,'CAYLEY','PERSON','{}','CAYLEY, a significant early aviation pioneer and inventor of the 19th century, made notable contributions to the field through his experiments with fundamental aerodynamic principles such as lift and drag. His work focused on developing glider prototypes that demonstrated the feasibility of controlled flight. Despite the challenges of the era, Cayley''s advancements laid crucial groundwork for later developments in aviation, firmly establishing him as a key figure in early aerial exploration during the 1800s.','{}','{}','{"frequency": 3, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "f5cd08a5bba8e5f1cac73b2168b03f440d049e82b880cf5ff9b03a61f932ab149f55ecbff1e2e45fc298cd176b96304c704c6f0d04ce87977c3be47e617c941b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f78b7450-3e61-4ae4-9a61-6df45d7c1e7c'::uuid,'DURKE BATAGLANI','PERSON','{}','59-year-old journalist, held hostage and later exchanged.','{}','{}','{"frequency": 1, "text_unit_ids": ["3ea69086c604fb251a4059f678ec83b99d67d511efb1c29354f7c0b54808defd6170d2ee03e45660f508dc039db22634dfa65c013414a6a31a8795a58d791441"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e6b15a5c-106e-4856-b11a-d1897a0bef5b'::uuid,'MEGGIE TAZBAH','PERSON','{}','53-year-old environmentalist, held hostage and later exchanged.','{}','{}','{"frequency": 1, "text_unit_ids": ["3ea69086c604fb251a4059f678ec83b99d67d511efb1c29354f7c0b54808defd6170d2ee03e45660f508dc039db22634dfa65c013414a6a31a8795a58d791441"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('ebff5c73-9a15-467f-a3f9-7ab54e229103'::uuid,'AURELIANS','GROUP ENTITY','{}','Group of individuals held as hostages and later exchanged.','{}','{}','{"frequency": 1, "text_unit_ids": ["3ea69086c604fb251a4059f678ec83b99d67d511efb1c29354f7c0b54808defd6170d2ee03e45660f508dc039db22634dfa65c013414a6a31a8795a58d791441"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('27cf2640-9898-4e00-b5d7-f8aaad733057'::uuid,'QUINTARA','PLACE','{}','Quintara orchestrated the hostage exchange using financial institutions located in Krohaara.','{}','{}','{"frequency": 1, "text_unit_ids": ["3ea69086c604fb251a4059f678ec83b99d67d511efb1c29354f7c0b54808defd6170d2ee03e45660f508dc039db22634dfa65c013414a6a31a8795a58d791441"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('2290fca9-bc7f-4409-883a-61d74fab18e8'::uuid,'TECHGLOBAL','ORGANIZATION','{}','TechGlobal is a semiconductor company and was previously owned by Vision Holdings.','{}','{}','{"frequency": 1, "text_unit_ids": ["3ea69086c604fb251a4059f678ec83b99d67d511efb1c29354f7c0b54808defd6170d2ee03e45660f508dc039db22634dfa65c013414a6a31a8795a58d791441"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('4bc17d7d-6e84-4d04-9b5b-ca5d76bf2270'::uuid,'DEUTSCHE AIRBUS','ORGANIZATION','{}','Though not explicitly mentioned, Deutsche Airbus could be inferred as an organization that might have been involved in the development or maintenance of "Hindenburg" if such a company existed.','{}','{}','{"frequency": 1, "text_unit_ids": ["3ea69086c604fb251a4059f678ec83b99d67d511efb1c29354f7c0b54808defd6170d2ee03e45660f508dc039db22634dfa65c013414a6a31a8795a58d791441"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d5e30901-05b3-42bc-9278-ad682bbdc987'::uuid,'HELICOPTER MODEL','DEVICE','{}','Helicopter design proposed by Leonardo da Vinci','{}','{}','{"frequency": 2, "text_unit_ids": ["a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad", "a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('2eb7196d-51e0-4348-a58f-817a38ce6d30'::uuid,'WIND TUNNEL','DEVICE','{}','The Wind Tunnel is an essential tool developed primarily for experimental testing purposes. Initially conceptualized in the 19th century, wind tunnels played a pivotal role in advancing aviation technology by facilitating detailed observations necessary for refining aircraft designs. Named after its pioneer, Maxim, this apparatus was crucial in understanding and analyzing the behavior of air around various shapes, including wings and bodies. It significantly aided early aviation pioneers such as Lilienthal, contributing to their design innovations. By enabling detailed aerodynamic tests, wind tunnels revolutionized the approach to aircraft development, ensuring that designs could be scientifically validated before full-scale production. This tool was indispensable in the refinement of airfoils and overall aircraft stability, making it a critical component for early and subsequent advancements in aviation technology.','{}','{}','{"frequency": 6, "text_unit_ids": ["29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6", "29d7b9fb394697229d5c6ee7e8e7498c26b62969f8ef9bf5c71dde024c555e26c654c119dc856911c2890b719150da3d3016b67a8e15863bf865abc974c1efb6", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "ee745461b2211d842e88d29f225a86ba7063e293122d56b41cea0528892369a6d28a8de8ecaaba49f767d0dc0952376d919da861f26599624546ddc82d9781c5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('2e6de6f5-da66-48d7-8932-a02737ec40f3'::uuid,'LEONARDO DA VINCI','PERSON','{}','Leonardo da Vinci was an influential historical figure renowned for his groundbreaking observations and concepts across various disciplines, particularly within the realm of fluid dynamics. His insights into hydrodynamics were pioneering, as he made significant theoretical contributions that anticipated modern understanding in this field. Although some of his designs related to fluid dynamics may not have been physically realized during his time, they nevertheless showcased his forward-thinking vision.
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('1410ae5e-19ab-4c60-a853-5c50458aca4a'::uuid,'HANG GLIDER','DEVICE','{}','Hang glider refers to an early design for an aircraft characterized by its rigid wing without traditional empennage or other control surfaces, similar to bird wings as depicted in Leonardo da Vinci''s visionary designs. Historically, this device was a subject of interest among aviation pioneers such as Otto Lilienthal and John S. W. H. Pilcher. These early gliders utilized human lifting as the primary means for controlling the aircraft’s maneuvers, although this method posed significant challenges. Notably, both Lilienthal and Pilcher encountered difficulties with loss of control during unsteady winds, underscoring the technical complexities involved in early flight experiments.','{}','{}','{"frequency": 5, "text_unit_ids": ["e9e299fdd315262c60dc335f6516a7d09106b9d9354cb34f01b7599af64f2d9273530938403a9f1b91129f2a67f0cccb25885ad1cf8e1ad0f9c71aea12340520", "e9e299fdd315262c60dc335f6516a7d09106b9d9354cb34f01b7599af64f2d9273530938403a9f1b91129f2a67f0cccb25885ad1cf8e1ad0f9c71aea12340520", "71513cc51ffa1e8b185f20e95d505c81a39cad56f6db7e0192988badc6a212324cd2dca2a6e0b895668f6133ccf33ae88b3164f544f6ed7f319db021e5f84305", "46b667214423448900a64449a21a8d78137e40dbbcde1ff7361b13892626a596937541e8a1dff8c28756c1af322bcfde1298239045005d93a04cd46043247c20", "ccac1a178375331bc449ac2d2eec635f0983c00e6d254912345c012c0c41f3a9cc65da465cf715f8bc206801bb7f81cd82c005354ce5454c3970c507c2045930"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f5561022-df38-4c31-b827-95fb6fc9a11e'::uuid,'WIND TUNNELS','SYSTEM','{}','Wind tunnels are systems designed to test various models under controlled airflow conditions. These devices are crucial for aerospace engineering and related fields, allowing researchers to study the behavior of model aircraft in a consistent flow of air. While wind tunnel technology was beyond the scope of early pioneers like Leonardo da Vinci, these facilities have evolved significantly over time to provide more precise and reliable testing environments. Modern wind tunnels are characterized by their ability to generate uniform, low-turbulence airflow, making them indispensable tools for contemporary aerodynamic research. Notable improvements in design have enhanced accuracy and efficiency, although early versions often lacked the sophistication seen in today''s advanced systems.','{}','{}','{"frequency": 6, "text_unit_ids": ["e9e299fdd315262c60dc335f6516a7d09106b9d9354cb34f01b7599af64f2d9273530938403a9f1b91129f2a67f0cccb25885ad1cf8e1ad0f9c71aea12340520", "e9e299fdd315262c60dc335f6516a7d09106b9d9354cb34f01b7599af64f2d9273530938403a9f1b91129f2a67f0cccb25885ad1cf8e1ad0f9c71aea12340520", "98f5af20b50979a6ceae00e0e262a4696f43fcd93e841c5eef7dcf55961a4513c7b0217df7f06d0572fe3bf238235fca6779737f60a3dedb4741275610b14f03", "98f5af20b50979a6ceae00e0e262a4696f43fcd93e841c5eef7dcf55961a4513c7b0217df7f06d0572fe3bf238235fca6779737f60a3dedb4741275610b14f03", "653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc", "653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3defade9-8828-4c34-bd18-8c5c21e79b74'::uuid,'RELAXED STATIC STABILITY (RSS) AIRCRAFT','MODEL','{}','Aircraft introduced in the 1970s that differ from earlier designs like Cayley''s configuration','{}','{}','{"frequency": 1, "text_unit_ids": ["fbfbe3eab64670ade81f0f5bb091f801c41f6144a0b8e541a66dad3c1f397496968ec6594738a46e5d6eca8ef00ae4a984c6e2a885277c5555498e6becc7e9c6"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('3d79b839-f90f-4b63-a09e-434190402c0d'::uuid,'MOULTGOLFIER BROTHERS','ORGANIZATION','{}','First to achieve manned flight in 1783 with a hot-air balloon. Developed understanding of airflow and heavier-than-air craft.','{}','{}','{"frequency": 2, "text_unit_ids": ["a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad", "a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('4d897274-a5db-4771-b531-9b80d9decf91'::uuid,'LILIENTHAL','PERSON','{}','Otto Lilienthal, often referred to simply as LILIENTHAL, was a pioneering figure in the field of aeronautics, known for his significant work in glider development. His research and experiments laid foundational groundwork that advanced the understanding of air resistance, lift mechanisms, and ultimately contributed to the progress of both hang gliding and powered flight. Noted for numerous glider flights in the late 19th century, Lilienthal''s contributions have been instrumental in aeronautical engineering. Through meticulous observation and practical experimentation, he refined our comprehension of aerodynamics, making him a key figure in the early stages of aviation history. His work not only propelled the development of gliders but also facilitated critical insights that would later support the invention of more advanced aircraft. As an early aviation pioneer, Lilienthal''s legacy endures through his ongoing influence on the principles and practices central to modern flying technique','{}','{}','{"frequency": 5, "text_unit_ids": ["71513cc51ffa1e8b185f20e95d505c81a39cad56f6db7e0192988badc6a212324cd2dca2a6e0b895668f6133ccf33ae88b3164f544f6ed7f319db021e5f84305", "5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b", "5b2cda8d5bbd5d82e2c6fdbd3f95d22ccf5c61786e126e8b0c5e7391999cff6606a62534e3cc3ff179c861f6e0cb19ee489f79b583fb0cfba038d14349b9403b", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9347582d-53d9-46f5-afa1-b130f0f8b776'::uuid,'PILCHER','PERSON','{}','Kelvin ("Kenny") Pilcher was an early pioneer in the field of hang gliding, working closely with Otto Lilienthal during the formative years of the sport. Alongside Lilienthal, Pilcher contributed significantly to the development and testing of early glider designs, facing numerous challenges that were characteristic of this era. These challenges included handling difficulties due to unsteady winds, a hazard that threatened many aviators who were at the forefront of aviation innovation.
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('83f69360-1668-4db1-9123-7e110e2b2a82'::uuid,'ANDERSON’S INSIGHT ON ARISTOTLE','MODEL','{}','Explanation by Anderson showing how Aristotle understood fluid as a continuum, before it was widely accepted in modern times.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('db552d03-d814-4fb2-a53f-ee8a9fab3417'::uuid,'NEWTON''S ANALYTICAL FRAMEWORK FOR MECHANICS','MODEL','{}','Development by Isaac Newton in the late 17th century (mid-1600s), creating a framework that allowed further theoretical analysis including fluid dynamics.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('2ceb38ce-aeba-4805-ac02-2151f607f1fc'::uuid,'SIR GEORGE GABRIEL STOKES'' CONTRIBUTIONS','COMPONENT','{}','Studied turbulent flows and expanded the mathematical foundations of fluid dynamics significantly during 19th century.','{}','{}','{"frequency": 1, "text_unit_ids": ["9e10720d8940a92e4cb58f1bbba8fe75c8a91e85474223b792dbc80444a1fa4dbf9183cca9e48a6d7ad55762d1099a1f77e0c2f98fb57732b6605de4fdcda42c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('26608001-289d-46ac-99fd-6b0f48f2784d'::uuid,'BOUNDARY LAYER','MECHANISM','{}','The Boundary Layer is a crucial concept in fluid dynamics, primarily focusing on the thin layer of fluid near a solid surface where viscosity significantly affects the flow behavior. This concept was independently recognized early in the 20th century by pioneering scientists such as Ludwig Prandtl and Theodore Blasius. Specifically, the boundary layer phenomenon between laminar and turbulent flow is well-delineated; it encompasses both theoretical descriptions and analytical solutions detailed by these key figures. For instance, Blasius provided a groundbreaking analytical solution in 1908, building upon earlier conceptual frameworks established by Otto Blunauer (a misattribution often cited) to correct and elaborate on Ludwig Prandtl''s seminal work from 1904, which initially introduced the boundary layer concept. Additionally, this layer is understood through the no-slip condition, where fluid adheres perfectly to the surface it flows over, a principle further refined by Joseph Boussi','{}','{}','{"frequency": 3, "text_unit_ids": ["5985fc6749a64fb8e61f7a2dcaeb6777591d07e107e27e9f81ec141746d44adcac5a3c9000993f0f170c0b6328ef2350e35bc72f717da15ff3420d8f6ff42f91", "5985fc6749a64fb8e61f7a2dcaeb6777591d07e107e27e9f81ec141746d44adcac5a3c9000993f0f170c0b6328ef2350e35bc72f717da15ff3420d8f6ff42f91", "5985fc6749a64fb8e61f7a2dcaeb6777591d07e107e27e9f81ec141746d44adcac5a3c9000993f0f170c0b6328ef2350e35bc72f717da15ff3420d8f6ff42f91"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('9e38227e-1a88-4deb-8004-41338e733b26'::uuid,'REYNOLDS NUMBER RELATIONSHIP','BOUNDARY LAYER','{}','Reynolds number relationship with boundary layer behavior. Higher Reynolds numbers indicate more turbulent flow; thus, understanding boundary layer changes along with Reynolds numbers helps predict turbulence onset}.','{}','{}','{"frequency": 1, "text_unit_ids": ["5985fc6749a64fb8e61f7a2dcaeb6777591d07e107e27e9f81ec141746d44adcac5a3c9000993f0f170c0b6328ef2350e35bc72f717da15ff3420d8f6ff42f91"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a9812dcb-b0e7-44a1-b195-946e42edcb8e'::uuid,'HOT AIR BALLOONS34','DEVICE','{}','Hot air balloons utilized for lifting purposes in China around the 3rd century BC, based on thermal heating and air displacement','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('0188620f-4e33-4820-8154-eeb654f8d867'::uuid,'CROSSING OF CHANNEL1785','SYSTEM','{}','Blanchard''s pioneering balloon crossing demonstrated the feasibility of long-distance travel by air, influencing early aviation perceptions and capabilities','{}','{}','{"frequency": 1, "text_unit_ids": ["d54c07ac8327b71b66713db09c704c4ad7a27589908a44f20e1f82f6862ae8906f07bdd5f724a455c02b8ccd11318bb80dcc8b5fca7721aaa202a67c6b5b51bb"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('6b31cff1-e6b2-4cbb-8598-ddfb62d467ac'::uuid,'STRINGFELLOW''S MODEL AIRCRAFT','MODEL','{}','The "STRINGFELLOW''S MODEL AIRCRAFT" is a historical artifact from the mid-19th century, specifically between 1850 and 1860. This model represents an early attempt at steam-powered flight and possessed a wingspan of approximately 3 meters. Notably, the aircraft managed to achieve a significant gliding distance of more than thirty meters during its test flights. However, despite its promising potential, it faced considerable difficulties in terms of control, attributed to inherent design challenges. Overall, "STRINGFELLOW''S MODEL AIRCRAFT" serves as an important piece of aviation history, showcasing the innovative yet problematic experiments that occurred at the dawn of powered flight.','{}','{}','{"frequency": 3, "text_unit_ids": ["4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a4ae708e-9167-4f6d-b282-0b819029b0df'::uuid,'GIFFARD''S AIRSHIP','SYSTEM','{}','The Giffard''s Airship, also known as "Giffard''s蒸汽驱动飞艇," was a significant milestone in aviation history. Introduced in France in 1852, it represented one of the initial endeavors to harness steam power for air travel. This device notably marked an early step toward achieving successful lighter-than-air flight, emphasizing its propulsion capabilities over aerodynamic and control issues.
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('1d59a3e9-a814-4ebd-88cb-b9906143c3df'::uuid,'DU TEMPLE''S STEAM POWERED MACHINE','SYSTEM','{}','"Du Temple''s Steam-Powered Machine" represents a pivotal moment in the history of aviation. The machine, developed in France, is noted as the first powered, manned aircraft capable of gliding and achieving brief hops. This groundbreaking design utilized steam power not only for propulsion but also to facilitate lift, marking the first instance of practical, controlled flight using this technology. Du Temple''s creation served as a crucial proof-of-concept for steam-powered heavier-than-air flight, demonstrating significant advancements in early aviation technology.','{}','{}','{"frequency": 3, "text_unit_ids": ["4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('cc5be53e-1fe3-46b4-a6ca-635635b57ad3'::uuid,'MAXIM''S ENORMOUS STEAM-POWERED MONOPLANE','DEVICE','{}','MAXIM''S ENORMOUS STEAM-POWERED MONOPLANE refers to an experimental aircraft developed by Hiram Maxim in the late 19th century. This large-scale monoplane, despite its success in achieving lift-off, faced significant challenges due to inadequate aerodynamic design and flight control mechanisms, rendering it uncontrolled during flights. During this period of engineering exploration, Maxim also invested considerable resources into developing advanced research tools such as a whirling arm for wing tests and a wind tunnel to better understand airflow dynamics. These tools allowed Maxim to gather crucial data on air resistance and lift, which were instrumental in advancing his understanding of aerodynamics and aircraft design. Overall, while the monoplane itself was not fully operational due to its limitations, these engineering efforts laid important groundwork for future developments in aviation technology.','{}','{}','{"frequency": 3, "text_unit_ids": ["4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c", "4089000a7a5f43c1f79ebd955ed69dab8fc13c6f0153fe4c6ae9df3fdfa0ecdfc28e259193c210fc04e64e6f124fe76ccb1f7ccbb3e5ccb8e8d848fbdfd2ef5c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('558f362d-4e68-4151-9bc0-93f6c1cbc3a8'::uuid,'WHIRLING ARM','DEVICE','{}','The WHIRLING ARM is a device originally designed for measuring wind resistance (drag) on rotating spheres or plates, first utilized by Robins in 1742. This apparatus has since been refined and expanded upon by subsequent inventors such as John Smeaton and Hume Rouse to accommodate a broader range of aerodynamic tests. Over time, the WHIRLING ARM''s applications have broadened significantly, making it instrumental not only for measuring drag but also for testing windmill, aerofoil, and wing resistance. By incorporating specific radius rotations, this device allows researchers to observe air flow patterns and forces on various objects in circular motion.
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('d201bd41-8b71-4019-a1c6-89f813c0407f'::uuid,'DIAMETER SQUARE DEPENDENCE','SYSTEM','{}','(\(d^2\)), another relationship seen in tests, indicating that some resistances might depend on the square of the diameter','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('bf26e79d-810d-430d-b8e0-29eb04b08628'::uuid,'DROP TESTS (BY PIOBERT, MURIN & DIDION)','MODEL','{}','(Research) carried out between 1835-1842 using a drop of up to 12 meters in both water and air to study drag at under 9 m/s velocity','{}','{}','{"frequency": 1, "text_unit_ids": ["8e8b5bf24dddb1ddb50b7cbf2d3c92c98694db8e547ae1917342574e7e171cb95e09a476096026b49868f4048da326a354b623333e0ac1b3a5e0a358ea00009f"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('1dbdcc61-8887-4d7d-94ca-5404c52ae980'::uuid,'EIFFEL TOWER','PLACE','{}','The EIFFEL TOWER, a landmark located in Paris, France, is richly associated with significant scientific investigations. Specifically, between the years of conducting pioneering experiments, Cailletet and Colardeau utilized the tower as a crucial location for their drop tests aimed at measuring drag force on streamlined bodies. These initial studies, conducted during an unspecified period, were foundational to future research and experimentation related to aerodynamics.
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('d1421c6d-fbc8-496f-8651-e08b243a8b98'::uuid,'CLOCKWORK POWERED WHIRLING ARMS','SYSTEM','{}','Clock-mechanism driven devices used in early aerodynamic tests, mentioned by Combes 1838, Casartelli 1853, Dalglish & Wood 1853','{}','{}','{"frequency": 1, "text_unit_ids": ["16d966814983125a6e32b061e1707e94f1e8d9d91c7fb8fece809b8d03586b149afc62f017609bda9a3a36cbfcdfd60df5527110c12c82e5fcd08b8eb20847b0"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('e2723864-1c87-44c6-912f-6808e6ce5c3d'::uuid,'HIRAM MAXIM59','SYSTEM','{}','Hiram Maxim built a steam-powered whirling arm of 5.7 m radius in 1888 for measuring various lifting surfaces and choosing configurations for his aeroplane','{}','{}','{"frequency": 2, "text_unit_ids": ["aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab", "aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('b6bb5408-5561-4f3e-aabb-8702822c049f'::uuid,'NPL TESTING PROPELLERS49,61,62','SYSTEM','{}','National Physical Laboratory tested airship engines and propellers using a whirling arm in 1904','{}','{}','{"frequency": 2, "text_unit_ids": ["aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab", "aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('819b5cb5-1107-48f3-83f1-f7b3dbe57fd7'::uuid,'VERY LARGE WHIRLING ARM AT BARROW63 BY VICKERS LTD','DEVICE','{}','Vickers built the largest whirling arm until then, used for testing airship engines and propellers on first British Rigid Airship in 1910','{}','{}','{"frequency": 2, "text_unit_ids": ["aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab", "aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('a5c32ec5-8c00-4eb5-b14e-4c35ab63c833'::uuid,'NOVEL DYNAMOMETER FOR TESTING PROPELLER TORQUE AND POWER','DEVICE','{}','The NOVEL DYNAMOMETER FOR TESTING PROPELLER TORQUE AND POWER, a groundbreaking innovation developed or utilized by Thurston, featured a unique and compact whirling arm apparatus. This device was designed to meticulously measure the performance of tested propellers without relying on pre-defined dimensions for its operations. The dynamometer''s novel design allowed for precise evaluation without imposing rigid size constraints, making it particularly versatile for various testing scenarios. Through this advanced tool, researchers or engineers could achieve more accurate assessments of propeller torque and power output, significantly enhancing the understanding and optimization processes in related fields such as marine engineering and propulsion technology.','{}','{}','{"frequency": 2, "text_unit_ids": ["aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab", "aad64346832d005607e6f074e50b93db24a196be3569a7051b9ea3a264ebf7aa702d9cec5d822035b6a5525881e05e0b1fdb2129d2a732df097b8f62f283d6ab"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('4cb8587f-91e7-4b7a-ba07-1e21f1addea3'::uuid,'STEERING_MECHANISMS','MECHANISM','{"обеспечивает контроль за летательным аппаратом","обеспечивает управление полётом"}','Systems that alter the flight path or orientation of aircraft, critical for maneuverability and control','{}','{}','{"frequency": 1, "text_unit_ids": ["3afa04cc7530a641a3fd45906a688d4d426fc2e94b2b585d2d5b048682c638b5d8cd601b89ec4e804b881be405f7431c8a546e371ae8a5e5f7c753897b8c882b"]}','2026-07-17 10:37:07.080969','2026-07-17 10:37:07.080969','history_development_aeronautics'),
	 ('7c90b39c-1492-4e74-b119-616ac61b24ec'::uuid,'HOT-AIR BALLOON FLIGHT','SYSTEM','{}','The Montgolfier brothers'' first manned aviation, which significantly advanced the creation of heavier-than-air aircraft','{}','{}','{"frequency": 2, "text_unit_ids": ["a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad", "a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('82c729b4-0724-44ac-86a2-9168bcedaf36'::uuid,'MARIOTTE''S DRAG PROPORTIONALITY','MODEL','{}','French scientist who established drag is proportional to air density and velocity squared.','{}','{}','{"frequency": 2, "text_unit_ids": ["a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad", "a5d4719b2541caf004e1082010054faa38c7ba80d90b5f7e39636fab5592ad3861a1d6acd00ebc78dac62d343df8f5398463149ba9cee12a0171444fbc1a02ad"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('4a838bbe-5b0e-4750-8a16-59001a526a22'::uuid,'STEAM ENGINES','SYSTEM','{}','The advent of steam engines after 1820 provided a consistent and powerful power source necessary for generating sufficient airflow in early wind tunnels','{}','{}','{"frequency": 2, "text_unit_ids": ["653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc", "653aa46087e791b134dbbd802cc7f2be070fd13ba9b27acc8585793069a21cb0efa3b5f8653b3d05323cc3ed759a463b78204a2bc4749488e28d38de3050a9cc"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5ba5f9dd-06e4-46f6-9123-d22e9c509f0b'::uuid,'HIGH CONTRACTION RATIO AT THE ENTRANCE TO WORKING SECTION OF TUNNEL','DEVICE','{}','The design feature known as the "High Contraction Ratio at the Entrance to the Working Section of the Tunnel" is a critical element in both early and modern wind tunnel setups. This feature is primarily aimed at minimizing local disturbances and turbulence near the model being tested, thereby ensuring a more uniform and high-quality airflow within the working section of the tunnel.
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('c2219425-9234-4db1-b9b1-0047c7ba6bb1'::uuid,'BLOW DOWN FAN IN WIND TUNNELS','DEVICE','{}','Fan component common in early wind tunnels used to enhance airflow but often lacked effective swirl reduction mechanisms','{}','{}','{"frequency": 2, "text_unit_ids": ["0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602", "0460a9eda843ac98a587f7e1087ff5d7540b2b14a5aa6781010edd45afc718e2aef15588aff5162f8b59032cf9c4aeb6d5c56943df0061f53402676b4b062602"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('5f49522f-2fef-4324-84d5-f6b4dd03e509'::uuid,'BLAST PIPE 0.23 M DIAMETER','COMPONENT','{}','\A component inside the box of the system which has an internal blast, where one end of the blast pipe was fixed at the upper end of the tunnel.','{}','{}','{"frequency": 2, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78", "4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('eeaba894-28c7-4bd7-83fc-e4504deb218b'::uuid,'WATER MANOMETER','COMPONENT','{}','\A device used to measure pressure within the stream passing through the anemometer.','{}','{}','{"frequency": 2, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78", "4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('da69f255-5012-4c20-8170-b015ddecaffb'::uuid,'J.A. LONGRIDGE73 CONFIGURATION (FIGURE 9)','MODEL','{}','\Longridge''s design, which was similar to the one detailed in this text but used for calibrating anemometers for mining purposes.','{}','{}','{"frequency": 2, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78", "4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('bb07eef9-ee40-45f3-99f1-067914aa9920'::uuid,'LEADING EDGE PART OF AEROFOIL','COMPONENT','{}','\The section of an aerofoil that meets the oncoming flow first and significantly affects lift generation according to Wenham''s findings.','{}','{}','{"frequency": 1, "text_unit_ids": ["4222d0e6d7fd70fa80adcfe41c4f3dda4b26d3f8455bd768a5bba8c96d5983e01afc2f036f41a0a96b015f1c4c056564fb798905f5bdfdae1faa26748538bd78"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d651845c-af5d-4a0e-8224-08582a8ed9b3'::uuid,'WENHAM''S DEVICE','DEVICE','{}','WENHAM''S DEVICE refers to a square-section wind tunnel that played a significant role in early aerodynamic research, particularly focusing on drag measurements and other similar applications. This device served as the foundational equipment from which later designs were differentiated by their shape, though they maintained similarities in purpose and functionality. Specifically, Wenham''s device was instrumental for measuring the drag of projectiles and other objects, aligning with broader efforts at understanding air resistance during the late 19th and early 20th centuries. The design of Wenham’s square-section wind tunnel marked a pivotal step in the development of aerodynamic testing techniques, serving as the standard against which subsequent, possibly more refined or differently shaped wind tunnels were compared.','{}','{}','{"frequency": 3, "text_unit_ids": ["6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa", "6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa", "6cfb4419f8267d18f97a1bf9437f18c2fff2b46c4b4880ad7918290d562f0899526da9fb0c4b926965ffc8ef15460d197a1dd9b00d1923f6635f3ef8fdec8eaa"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f840ea41-fb6f-4c63-8ba5-1a3deb2c5127'::uuid,'KERNOT78 TUNNEL','SYSTEM','{}','A blowdown tunnel built in 1893 using a fan and gas engine. It measured forces on building shapes with an open working section.','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('7e5ba904-7572-45d9-9fe8-0ebc7a225249'::uuid,'RENARD69 AIRSHIP TUNNEL/','SYSTEM','{}','A smaller tunnel built by Renard in 1896 with a diameter of 0.81 meters to measure air drag for airships. The flow was reported to be poor due to lack of effort in improving it.<|','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('db251fc9-1398-4406-807a-d83ba16eca3a'::uuid,'FAN','COMPONENT','{}','The entity "FAN" refers to the critical fan components utilized in the tunnel systems, particularly within Kernot78’s tunnel. These fans play a vital role in managing airflow and ensuring optimal performance within the tunnels. Additionally, it is noted that the fan component of Kernot78''s tunnel is driven by a gas engine. This setup underscores the importance of robust ventilation systems for efficient operation and safety.
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('aadb32c8-a2d9-4090-8036-72ec24116bb3'::uuid,'HIRAM MAXIMS TUNNEL','SYSTEM','{}','Large blowdown tunnel constructed by Hiram Maxim in 1896 with dimensions 0.91 x 0.91 m and featuring measurements on aerofoils, bodies, and cascades for evaluation of forces on his aeroplane.<|','{}','{}','{"frequency": 1, "text_unit_ids": ["9b04b65904320d152e1a24cfa860cad23a1e8cf8a6b3402f1434285bed985ebbf31d5bfe08c052a7e873eb3dccd9ad3800832d2194ca94adad02b5f4b8043f99"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('cb2e316e-b610-458b-b15e-9327e3c77baf'::uuid,'SCREENS FOR MINIMIZING FLOW FLUCTUATIONS','COMPONENT','{}','Not present in Tsiolkovsky''s 1899 tunnel, important for reducing fluctuations in airflow and improving testing accuracy','{}','{}','{"frequency": 2, "text_unit_ids": ["427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe", "427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('eafc8f88-c980-4e0f-87e9-83c51b05da9d'::uuid,'ZUKOVSKY''S STRAIGHT S QUARE SECT ON WINDTUNNEL','SYSTEM','{}','Created by Zhukovsky in 1902, featuring windows in the straight square section design to enhance visual observation','{}','{}','{"frequency": 2, "text_unit_ids": ["427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe", "427904c0423d3115fd18a9c7e4a20a8836e14777f8609f88c50879ef1979f1bae3c4e4e40d0612fecf5d7e3d5286aa83a2e16941746d5fe193384787ebb799fe"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('75976795-3067-4bd7-ab33-966f110c1eb2'::uuid,'NPL TUNNEL DESIGN','MODEL','{}','The original NPL design that had a square section without the racecourse return path until its later modifications. It was used for fundamental studies and served as a model for other institutions like East London College and Eiffel''s installation.','{}','{}','{"frequency": 1, "text_unit_ids": ["6c043286a724707e324c0aa9bd1e28f9c44eaaaa396eebf578400d5cb0cb167ac12bec61fdd45d7cfa6f63f53e15f92c08aeae6493271704143d122caa10dcec"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('c9f309c9-dc12-4816-8db3-9bae3cc56593'::uuid,'THURSTON89','MODEL','{}','Engineer from London University who installed the first small vertical tunnel for testing flow around aerofoil sections in 1909 at East London College, which later became Queen Mary College','{}','{}','{"frequency": 2, "text_unit_ids": ["e0ded24d363ec39e76d9e983a1bafea9a1e9accb8059322ef7065b07c4c84c9cee4caa65c00b8bf702b00a6751810904936f74916a3ef15893333841e710c08c", "e0ded24d363ec39e76d9e983a1bafea9a1e9accb8059322ef7065b07c4c84c9cee4caa65c00b8bf702b00a6751810904936f74916a3ef15893333841e710c08c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('70d4065e-6f42-4882-ba42-30cc3fb3a6d4'::uuid,'FREDERICK HANDLEY PAGE90 (FHP)','ORGANIZATION','{}','Important British aircraft manufacturer that built a large square sectioned wind tunnel at Northampton College in 1911, later City University','{}','{}','{"frequency": 2, "text_unit_ids": ["e0ded24d363ec39e76d9e983a1bafea9a1e9accb8059322ef7065b07c4c84c9cee4caa65c00b8bf702b00a6751810904936f74916a3ef15893333841e710c08c", "e0ded24d363ec39e76d9e983a1bafea9a1e9accb8059322ef7065b07c4c84c9cee4caa65c00b8bf702b00a6751810904936f74916a3ef15893333841e710c08c"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('0356a4f7-eb1c-43a9-894b-a9d18a8de704'::uuid,'2M TUNNEL BY JUNKERS AT AACHEN (AACHEN, GERMANY)','DEVICE','{}','Installed by Junkers in 1912 and shared a tunnel facility with another in Aachen. Details of its exact application or performance are unclear.','{}','{}','{"frequency": 2, "text_unit_ids": ["2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e", "2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('91bb2124-60fe-4621-9ab8-c6b2de39e896'::uuid,'RNAS LARGE TUNNEL FOR BLIMP DESIGNS (KINGSNORTH, ENGLAND, UK)','DEVICE','{}','This was a large tunnel installed around 1914 for testing blimps; used propeller and gasoline engine configurations successfully according to reports','{}','{}','{"frequency": 2, "text_unit_ids": ["2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e", "2cd0f90fec06c619cb3d883c3511cd7c23b0fcb07c2d5c35f61390b6a2b712cfc2da13f27b9d16a691b561319c8ad7242fd2fbaadddc7e585bd3fd3c9f8ac27e"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d2d20fea-1daa-444b-a603-1ff78c587088'::uuid,'PROPELLER','COMPONENT','{}','The propeller is a crucial component designed as an apparatus consisting of blades and hubs connected to a central shaft, primarily utilized for propulsion in aircraft equipped with fixed-wing designs. This device harnesses rotational motion from the engine to generate thrust, enabling forward movement and maintaining speed during flight. Additionally, it has found application in other aerial vehicles such as blimps, where its primary function is to provide power, contributing to the overall lift and maneuverability of the airship.','{}','{}','{"frequency": 2, "text_unit_ids": ["1da91bb28bf499aa452aef24bdc7beda85be6ecae6149f90b2e07f2f861825f24d62bd32ebcad839db4c303b984e2f9501bb42a9c684162f8dd2f4dd5d838fb0", "5f6fd011c9ca704fc492591b733a486799017472d116244888b93e9d7d7bc92c33215f95b7a0a6f3c020f6ed022aa38e6f8f3044d9ae52a1e579de70fa928ad5"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('22ff0178-0b61-4c05-8b97-30f7acf3c46a'::uuid,'DU TEMPLE','PERSON','{}','"DU TEMPLE, an early aviation pioneer, played a significant role in the exploration of powered, controlled flight development alongside other notable figures. Du Temple constructed heavier-than-air manned machines capable of powered take-offs, reflecting advancements made during this critical period. Notably, Du Temple''s work encountered similarities with that of Sir George Cayley in terms of the fundamental challenges faced by pioneers in the field. Despite making important strides, Du Temple did not fully grasp the control concepts essential for successful and stable flight. This oversight was part of a broader set of issues that many early aviation enthusiasts grappled with as they endeavored to realize the dream of mechanized flight."','{}','{}','{"frequency": 3, "text_unit_ids": ["61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "61646302e3bc960c352c6408cdc69191dab988abf38ec4bf7f2e4174aba91d86396e3e37ae38ca304afb1a34043af419361016661c11be52244507e7a8027a39", "f5cd08a5bba8e5f1cac73b2168b03f440d049e82b880cf5ff9b03a61f932ab149f55ecbff1e2e45fc298cd176b96304c704c6f0d04ce87977c3be47e617c941b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('59f9eff2-6ecb-4b60-90c0-6289a16f8343'::uuid,'WRIGHT BROTHERS'' FLIGHT EXPERIMENTATION','MECHANISM','{}','The Wright brothers conducted extensive experiments with powered flight, which included understanding full six-axis control and stability mechanisms that were missing in early pioneers’ efforts.','{}','{}','{"frequency": 1, "text_unit_ids": ["f5cd08a5bba8e5f1cac73b2168b03f440d049e82b880cf5ff9b03a61f932ab149f55ecbff1e2e45fc298cd176b96304c704c6f0d04ce87977c3be47e617c941b"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('f14c8d32-1f45-48b6-b07c-88701db2aa26'::uuid,'OTTO LILIENTHAL DESIGNS','MECHANISM','{}','Designs by Otto Lilienthal which were primarily focused on unpowered flight rather than powered control; reliance on glider technology for data and experiences was significant but limited in scope of controlled flight mechanics','{}','{}','{"frequency": 2, "text_unit_ids": ["ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79", "ffe9725d362af387144062ce80531a3c181c5efe24e8c5ccb730a3fad8dd8623051f30cc871dc61ff2bf656d91294dc1547d0406b008537b49f8a44cfcec0d79"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('fc247e41-d81e-4ee0-ad28-95c928f528d4'::uuid,'38 KW 5 CYLINDER RADIAL PETROL ENGINE','MECHANISM','{}','Engine developed by Langley and his team for the full-size man-carrying machine, critical to overcoming power requirements issues in powered flight attempts','{}','{}','{"frequency": 1, "text_unit_ids": ["baaa62fd839985ce0a3d03b2d98ddcadb6f3444480414cdd20d36ee69e47687c9474cf34e27996edfbc0ef5e505f086b7089d7dffa034ef135e1881d1386aee9"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('96917b5c-79ce-4d23-b201-74f4cac2de49'::uuid,'TANDEM WING MACHINE','MECHANISM','{}','Langley''s final model, with a tandem wing configuration that achieved successful flights despite initial issues, showcasing the aerodynamic principles and mechanical components of early flight experiments','{}','{}','{"frequency": 1, "text_unit_ids": ["baaa62fd839985ce0a3d03b2d98ddcadb6f3444480414cdd20d36ee69e47687c9474cf34e27996edfbc0ef5e505f086b7089d7dffa034ef135e1881d1386aee9"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('04664bbc-2365-4f76-8b22-ac65cfcf195f'::uuid,'BISMARCK OPINIONS ON LANGELY AERODROME STABILITY','OPINION','{}','Recent analyses suggest that Bisplinghoff’s claim about aeroelastic failure might not be entirely accurate, offering nuanced views on the stability and design challenges of Langley''s aerodrome.','{}','{}','{"frequency": 1, "text_unit_ids": ["baaa62fd839985ce0a3d03b2d98ddcadb6f3444480414cdd20d36ee69e47687c9474cf34e27996edfbc0ef5e505f086b7089d7dffa034ef135e1881d1386aee9"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('0a8473dd-84b7-4301-970e-df330602176d'::uuid,'AL-ANDALUS','GEO','{}','Al-Andalus was the region in present-day Spain and Portugal where Abbas ibn Firnas made his hang-glider flight','{}','{}','{"frequency": 1, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('49456cdb-2dd4-4c22-81f4-a71467c56d60'::uuid,'HOT-AIR BALLOON','DEVICE','{}','The hot-air balloon is an airworthy dirigible that carries people by means of heated air in a fabric envelope; the concept was developed in Europe during the 19th century and earlier in China.','{}','{}','{"frequency": 1, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('cce48c37-9ef6-45e3-a09c-e4be9307eca2'::uuid,'HUMAN FLIGHT','MODEL','{}','The dream of human flight has been present since ancient times and was realized in different forms across various civilizations.','{}','{}','{"frequency": 1, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('7a863021-c8ea-472e-80b9-36a9a1eedfb2'::uuid,'LIU BANG','PERSON','{}','Liu Bang, a significant historical figure in China, is often associated with early innovations in aviation. According to available descriptions, Liu Bang reportedly invented the "wooden bird," which was likely a large-scale paper and wooden contraption designed for experimental flights around 400 AD. This invention reflects his contributions to the field of flight technology during antiquity. While there may be some uncertainty regarding whether Liu Bang actually invented the "wooden bird," these claims highlight his role as an innovator in early Chinese history. The date mentioned places this alleged invention within a period of significant cultural and technological development in China, suggesting that such attempts at mechanical birds for flight experiments were part of broader advancements during that era.','{}','{}','{"frequency": 2, "text_unit_ids": ["2e9ab909fa00e8633f612e2ff91a1104e10bcb90497c34e3402b71ef3457891e98b8a02caae3e6e229aac92c0c890dbd32b2f49dd7eb38da47a97c5e1a2a24ca", "93598286bf41252a5653b865693926a10004c8895f439d179e7df23951875f9be08961897007b5955c71dd93076ae3119f0c8ca810440b7e216291c012b3265d"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d79b2ca1-bf9f-4a4d-90d5-8193be34e9db'::uuid,'HANG GLIDERS','COMPONENT','{}','First glider design including flight control surfaces developed by Abbas ibn Firnas, flew for at least ten minutes from Jabal al-''arus hill in 877 AD','{}','{}','{"frequency": 2, "text_unit_ids": ["ce6b5bf047905c10664374fb49d23d3216e192e2a564c6bafca1f58cbb43577b7a825598664c39e99d438a006e69f57882a5588711fddc205867ae05aa428ea2", "ce6b5bf047905c10664374fb49d23d3216e192e2a564c6bafca1f58cbb43577b7a825598664c39e99d438a006e69f57882a5588711fddc205867ae05aa428ea2"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('ada74087-4df7-4e08-bc6d-fb0273f1ca64'::uuid,'CW_OF_MASS','SYSTEM','{}','Critical point used for analyzing the force moments relative to the center of mass, especially important in aircraft dynamics','{}','{}','{"frequency": 1, "text_unit_ids": ["a9ae9046c84bd485f66f44763948025a4066f10073bee095a4c15c4665d9db3e9ee4c83182db236d7659a96a72f09b4262666709a85154db90a6633d796a8eab"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('4d7691bc-c1a9-46bf-84f7-03f68aa48fea'::uuid,'ROCKET','DEVICE','{}','The ROCKET, a pioneering device crafted by Lagari Hasan Çelebi in 1633, is recognized as the earliest known example of a manned rocket. Described in various accounts, it featured a large cage-like structure with a conical top, which served both as a protective enclosure for its occupant and as an integral part of its aerodynamic design. The rocket incorporated innovative gunpowder-filled cavities strategically positioned within its framework to provide propulsion during ascent.
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('f9acfb07-8695-4ba0-87da-0c7da38c31a8'::uuid,'SIR HIRAM STEVENS MAXIM','PERSON','{}','"Hiram Stevens Maxim studied several designs and built a huge machine with two modernized lightweight steam engines." "<|)[--continuing--]("relationship"','{}','{}','{"frequency": 1, "text_unit_ids": ["ccac1a178375331bc449ac2d2eec635f0983c00e6d254912345c012c0c41f3a9cc65da465cf715f8bc206801bb7f81cd82c005354ce5454c3970c507c2045930"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('58473df0-436b-4e7b-9083-62f5ea7e6354'::uuid,'FLYING LANTERN','DEVICE','{}','The flying lantern, a paper container holding an oil lamp that rises due to heated air, used in ancient combat tactics','{}','{}','{"frequency": 1, "text_unit_ids": ["93598286bf41252a5653b865693926a10004c8895f439d179e7df23951875f9be08961897007b5955c71dd93076ae3119f0c8ca810440b7e216291c012b3265d"]}','2026-07-17 13:19:24.183818','2026-07-17 13:19:24.183818','history_development_aeronautics'),
	 ('d9b7f7cf-951c-47c9-99a8-45eacf06733e'::uuid,'LAGARI HASAN CELEBI''S FLIGHT','EVENT','{}','"LAGARI HASAN CELEBI''S FLIGHT" refers to a historical event associated with Lagari Hasan Celebi, an Ottoman aviator who is credited with attempting the first manned rocket flight in recorded history. This fictional but historically significant entity represents an important milestone in the realm of early aeronautical experimentation.
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('4a58027f-9daf-408e-b310-e499c92f50dd'::uuid,'FLOW VELOCITY V','COMPONENT','{}','The velocity at which the air flows over a body, impacting the force calculation through its squared term in the equation','{}','{}','{"frequency": 2, "text_unit_ids": ["a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae", "a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('29c89c73-761d-4963-b59f-b31a5d68788b'::uuid,'ANGLE Α','MECHANISM','{}','Angle of the plate to the flow direction affecting the sine-squared component in Newton''s formula for force','{}','{}','{"frequency": 2, "text_unit_ids": ["a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae", "a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('095e8f4e-2296-405b-b1a3-8439018c7b66'::uuid,'LIFT COMPONENT','COMPONENT','{}','Component of F that is perpendicular to the flow direction, critical for understanding flight mechanics','{}','{}','{"frequency": 2, "text_unit_ids": ["a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae", "a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('cb0c6b78-c814-462e-afd4-5339f432b5b1'::uuid,'AIRPLANE ENGINE','DEVICE','{}','Device responsible for providing power to aircraft, which was a limiting factor in early aviation before 1903','{}','{}','{"frequency": 2, "text_unit_ids": ["a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae", "a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('4fdea676-171c-4685-9575-cc1d26aa5d87'::uuid,'WRIGHT BROTHERS'' AIRPLANE','SYSTEM','{}','The Wright brothers’ creation that took the first powered flight on December 17, 1903, marking an advancement in aeroplane technology','{}','{}','{"frequency": 2, "text_unit_ids": ["a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae", "a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('e67dd639-1343-4cff-8432-c5676dd96f4c'::uuid,'AERONAUTICS','SYSTEM','{}','Discipline dealing with the operation and construction of aircraft which underwent significant developments at the beginning of the twentieth century','{}','{}','{"frequency": 2, "text_unit_ids": ["a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae", "a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('a9fa0991-e71f-4c3b-80e7-cf285364756b'::uuid,'FIRST FLIGHT OF MOZHAIMSKY''S AEROPLANE','MODEL','{}','Claimed first powered flight by an individual other than Wright brothers, but not substantiated in serious studies conducted later, such as those at TsAGI','{}','{}','{"frequency": 1, "text_unit_ids": ["a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('e1ac0746-3187-478b-90fc-d5b9789423a4'::uuid,'TSAGI INSTITUTE','ORGANIZATION','{}','Institute named after M. E. Zhukovsky where serious, non-propagandistic research about the early history of aviation was done','{}','{}','{"frequency": 2, "text_unit_ids": ["a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae", "a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('208e994e-a606-4c3e-95f8-fa53599766b9'::uuid,'AERODYNAMICS','MODEL','{}','Field of science dealing with forces acting on bodies in motion through air and which significantly advanced during the early 20th century','{}','{}','{"frequency": 2, "text_unit_ids": ["a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae", "a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('241deb60-0455-4514-a7c0-7380ea62449a'::uuid,'GASEOUS FLOW MECHANICS','SYSTEM','{}','Study of fluid dynamics, especially gases, crucial for understanding aircraft design and performance)("relationship"','{}','{}','{"frequency": 2, "text_unit_ids": ["a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae", "a779458276374a63d6d046677182afa54f82096d7fed98598f3c9892f3ddfcdc556726406f2c8e10c2ecdc5eecba1fee902de22803c3813dde63bc3545bc66ae"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('b0e2ce86-4d72-4cd4-bcda-90716ad83cd2'::uuid,'THRUST','FORCE','{}','Thrust is generated by the engine and acts against drag','{}','{}','{"frequency": 1, "text_unit_ids": ["a9ae9046c84bd485f66f44763948025a4066f10073bee095a4c15c4665d9db3e9ee4c83182db236d7659a96a72f09b4262666709a85154db90a6633d796a8eab"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('d5b1fda8-9fcd-41ae-ac11-79a381356edf'::uuid,'DRAG','FORCE','{}','Drag opposes thrust and is caused by air resistance','{}','{}','{"frequency": 1, "text_unit_ids": ["a9ae9046c84bd485f66f44763948025a4066f10073bee095a4c15c4665d9db3e9ee4c83182db236d7659a96a72f09b4262666709a85154db90a6633d796a8eab"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('1d2c93d0-70ad-4fa1-9bf2-db51e32f50b1'::uuid,'LIFT','FORCE','{}','Generated by an angle of attack, lift counteracts weight on a wing element','{}','{}','{"frequency": 1, "text_unit_ids": ["a9ae9046c84bd485f66f44763948025a4066f10073bee095a4c15c4665d9db3e9ee4c83182db236d7659a96a72f09b4262666709a85154db90a6633d796a8eab"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('e68bcac3-2fba-4371-9d20-c213edac9765'::uuid,'WEIGHT','FORCE','{}','Weight acts downwards due to gravity, balancing the forces for stable flight','{}','{}','{"frequency": 1, "text_unit_ids": ["a9ae9046c84bd485f66f44763948025a4066f10073bee095a4c15c4665d9db3e9ee4c83182db236d7659a96a72f09b4262666709a85154db90a6633d796a8eab"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('385d2a72-4951-471f-be97-2833b9f52c20'::uuid,'FLAG FLUTTERING IN THE WIND','PHENOMENA','{}','A phenomenon where a flag oscillates due to wind forces, indicating the need for considering deformations','{}','{}','{"frequency": 2, "text_unit_ids": ["16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b", "16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('3bb73915-380e-4ae2-b72d-b6357786ebfe'::uuid,'FLUTTER','PHENOMENA','{}','Oscillatory behavior of an aircraft wing at certain speeds, potentially dangerous and requiring careful consideration in design','{}','{}','{"frequency": 2, "text_unit_ids": ["16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b", "16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('7ae4b617-cf4b-4d28-8803-1c157a259cbb'::uuid,'STRATIFIED BODY SURFACE NON-DEFORMABILITY HYPOTHESIS','HYPOTHESIS','{}','The assumption that the surface of streamlined bodies does not deform during aerodynamic interactions, essential for simplifying mathematical models','{}','{}','{"frequency": 2, "text_unit_ids": ["16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b", "16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('10b99841-c831-45a2-83dd-8a68d0b7108f'::uuid,'BOUNDARY CONDITIONS FOR AERODYNAMIC MODELLING','SYSTEM','{}','Conditions necessary to solve problems in aerodynamics when assuming non-deformable surfaces','{}','{}','{"frequency": 2, "text_unit_ids": ["16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b", "16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('7a3dbabc-9e64-4a7e-a646-446584a303dd'::uuid,'GAS OR LIQUID FLOWS','FLUID MOTION','{}','Study of velocities, densities, pressures, and temperatures over time and space during fluid flow','{}','{}','{"frequency": 2, "text_unit_ids": ["16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b", "16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('5fd1430d-564b-4fad-9fd8-b8317a1e7f2b'::uuid,'EULER''S APPROACH TO FLOW CHARACTERISTICS','METHOD','{}','(Eulerian approach) Studying kinematic characteristics by fixing points within the volume occupied by the flow and observing their changes over time','{}','{}','{"frequency": 2, "text_unit_ids": ["16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b", "16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('9854f986-b3b7-4e16-aee8-b6eb68ced545'::uuid,'LAGRANGE''S APPROACH TO FLOW CHARACTERISTICS','METHOD','{}','(Lagrangian approach) Tracing a specific fluid particle''s movement history to describe its motion using fundamental physical laws','{}','{}','{"frequency": 2, "text_unit_ids": ["16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b", "16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('755d5e40-0c90-4305-b41c-22a0bb26cc9e'::uuid,'PRINCIPLE OF REVERSIBILITY IN AERODYNAMICS','THEOREM','{}','Assumption that body-air force interactions are symmetric in time, whether the body is moving through air or if a uniform flow impinges on a stationary body','{}','{}','{"frequency": 2, "text_unit_ids": ["16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b", "16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('4a170258-a12f-40f7-9001-4474d3045fce'::uuid,'AIR (A MIXTURE OF GASES)','MATERIAL','{}','(Air) A mixture mostly of nitrogen and oxygen with varying other elements, its properties change with altitude','{}','{}','{"frequency": 2, "text_unit_ids": ["16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b", "16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('80703956-9cd2-45fd-a818-8e98603aec9c'::uuid,'STANDARD ATMOSPHERE','MODEL','{}','An internationally agreed set of atmospheric parameters like temperature, pressure, speed of sound, density, viscosity, used for solving aerodynamic problems accurately','{}','{}','{"frequency": 2, "text_unit_ids": ["16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b", "16d392b029485723ce65bbac01611d8cea0ac0a495dfcec849dfe0fb70a7ecd2ca1be47fb6b9a17cde8832f82f25c06409dae658149352efbf16e7cc4637347b"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('915dc94c-6430-40eb-ae72-0e6f369ac767'::uuid,'ALTIMETER PARAMETER','MECHANISM','{}','Parameters include altitude, temperature, speed of sound, pressure, density, and kinematic viscosity which are used to measure atmospheric conditions','{}','{}','{"frequency": 1, "text_unit_ids": ["22c3c2c423ad221ca214710cfa41f27d1e4dc8d6d2a92cf697c6e413557740e0d79914704f6f8c0e7f4ce8f21bf52fe6505883477ed45d7e212012e482c40ef5"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('0c69b6b5-bdbc-4784-8d3c-b6e4c95573db'::uuid,'ASTMOPHHERE CALCULATIONS','SYSTEM','{}','System for calculating physical parameters such as mean free path of air molecules in the atmosphere','{}','{}','{"frequency": 1, "text_unit_ids": ["22c3c2c423ad221ca214710cfa41f27d1e4dc8d6d2a92cf697c6e413557740e0d79914704f6f8c0e7f4ce8f21bf52fe6505883477ed45d7e212012e482c40ef5"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('da4473aa-2cb0-4add-8317-400668c8ef8d'::uuid,'MEAN FREE PATH Λ','MEASUREMENT','{}','"Mean Free Path Λ" is a critical parameter that describes the average distance traveled by air molecules in the atmosphere before they collide with another molecule. This value significantly influences various atmospheric phenomena and varies depending on the altitude. At different elevations, from sea level to approximately 80 kilometers, the mean free path of air molecules changes due to variations in density and temperature. Understanding this parameter is essential for meteorological studies, atmospheric science, and related fields where the behavior of air molecules at various altitudes plays a crucial role.','{}','{}','{"frequency": 2, "text_unit_ids": ["22c3c2c423ad221ca214710cfa41f27d1e4dc8d6d2a92cf697c6e413557740e0d79914704f6f8c0e7f4ce8f21bf52fe6505883477ed45d7e212012e482c40ef5", "22c3c2c423ad221ca214710cfa41f27d1e4dc8d6d2a92cf697c6e413557740e0d79914704f6f8c0e7f4ce8f21bf52fe6505883477ed45d7e212012e482c40ef5"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('0581b1e0-fea0-4bda-b2a8-5185b351c4b6'::uuid,'CONTINUUM MODEL','MODEL','{}','The CONTINUUM MODEL is a theoretical framework employed for examining phenomena occurring at altitudes where the mean free path of gas molecules becomes significantly smaller compared to the dimensions of objects in the atmosphere. This model finds particular application in aerodynamics, specifically when studying conditions up to an altitude of approximately 80 kilometers. At these heights, the mean free path is notably small relative to characteristic object dimensions, making it necessary to use this continuum approach rather than methods applicable to rarefied gases or space phenomena where such assumptions do not hold. The CONTINUUM MODEL thus provides a robust analytical tool for understanding atmospheric behaviors and fluid dynamics in the upper layers of Earth''s atmosphere.','{}','{}','{"frequency": 2, "text_unit_ids": ["22c3c2c423ad221ca214710cfa41f27d1e4dc8d6d2a92cf697c6e413557740e0d79914704f6f8c0e7f4ce8f21bf52fe6505883477ed45d7e212012e482c40ef5", "22c3c2c423ad221ca214710cfa41f27d1e4dc8d6d2a92cf697c6e413557740e0d79914704f6f8c0e7f4ce8f21bf52fe6505883477ed45d7e212012e482c40ef5"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('6ec74472-ab7e-420d-aae7-2e6fe516427f'::uuid,'MACH NUMBER M','MECHANISM','{}','Mach Number M is a crucial dimensionless ratio that quantifies the relationship between an aircraft’s true flight speed and the local speed of sound. This metric is essential in assessing the approach to sonic conditions and their impact on aircraft performance issues, including aerodynamic changes and structural stresses. The Mach number serves as a key parameter for classifying fluid flows around supersonic, transonic, and subsonic speeds. By using this value, engineers can select appropriate aerodynamic models and designs that ensure optimal performance under various flight regimes, thereby addressing potential challenges associated with accelerating towards and beyond the speed of sound.','{}','{}','{"frequency": 3, "text_unit_ids": ["22c3c2c423ad221ca214710cfa41f27d1e4dc8d6d2a92cf697c6e413557740e0d79914704f6f8c0e7f4ce8f21bf52fe6505883477ed45d7e212012e482c40ef5", "b1ce24296a58526324fabc7ae6e490936e4736e1162bc2970189c9eac707fa913c796b5d317389c1344080f396eba1801f7b804ce60b31231b538920f900bf69", "b1ce24296a58526324fabc7ae6e490936e4736e1162bc2970189c9eac707fa913c796b5d317389c1344080f396eba1801f7b804ce60b31231b538920f900bf69"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('01195880-4174-427a-921d-fae0791b0d40'::uuid,'IDEAL INCOMPRESSIBLE GAS MODEL','MODEL','{}','The IDEAL INCOMPRESSIBLE GAS MODEL is a simplified theoretical framework used primarily in fluid dynamics to analyze and predict the behavior of gases under various conditions. This model considers only the mass of the gas particles as an essential factor, disregarding other complexities such as viscosity, compressibility, and intermolecular forces. By focusing solely on the mass of the medium particles, this model significantly streamlines the analysis, making complex fluid dynamics problems more manageable for both theoretical study and practical application. This simplification enables engineers and scientists to derive accurate approximations without the need to account for less prominent factors that could complicate calculations but have minimal impact in certain scenarios.','{}','{}','{"frequency": 2, "text_unit_ids": ["22c3c2c423ad221ca214710cfa41f27d1e4dc8d6d2a92cf697c6e413557740e0d79914704f6f8c0e7f4ce8f21bf52fe6505883477ed45d7e212012e482c40ef5", "22c3c2c423ad221ca214710cfa41f27d1e4dc8d6d2a92cf697c6e413557740e0d79914704f6f8c0e7f4ce8f21bf52fe6505883477ed45d7e212012e482c40ef5"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('d3f57db8-f072-4d7a-bddd-67bf4de945e2'::uuid,'VISCOUS INCOMPRESSIBLE GAS MODEL','MODEL','{}','The Viscous Incompressible Gas Model is a specialized fluid mechanics model that accounts for shear resistance between different layers of gas. This model operates within the framework of Newtonian fluids, treating viscosity as a key factor in capturing the dynamic behavior of gases under various flow conditions. It proves particularly useful in scenarios where the characteristics of gas flow are significant, yet external conditions allow the application of simplified modeling techniques.
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('baf64a7a-a240-44af-9204-828382ad4458'::uuid,'SPEED OF SOUND C','PARAMETER','{}','Speed at which sound travels through air, varies with altitude and atmospheric conditions','{}','{}','{"frequency": 1, "text_unit_ids": ["22c3c2c423ad221ca214710cfa41f27d1e4dc8d6d2a92cf697c6e413557740e0d79914704f6f8c0e7f4ce8f21bf52fe6505883477ed45d7e212012e482c40ef5"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('4b885e11-5fbb-41b1-a5a3-1a81ce8a3cd0'::uuid,'MASCH NUMBER M','MECHANISM','{}','Ratio of characteristic flow velocity to the speed of sound, used in classifying flows in aerodynamics','{}','{}','{"frequency": 1, "text_unit_ids": ["22c3c2c423ad221ca214710cfa41f27d1e4dc8d6d2a92cf697c6e413557740e0d79914704f6f8c0e7f4ce8f21bf52fe6505883477ed45d7e212012e482c40ef5"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('ce81c667-93d9-4da3-ae3f-81d6cfc69097'::uuid,'MODEL','MODEL','{}','Model refers to the simplified representation used for aerodynamic processes where only the existence of mass of the medium particles is considered.','{}','{}','{"frequency": 1, "text_unit_ids": ["7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('6a0b0714-5707-448c-9d03-5cf1b41d362a'::uuid,'IDEAL COMPRESSIBLE FLUID (GAS) MODEL','MODEL','{}','Used widely in acoustics, this model assumes small Mach numbers and simplifies the analysis of sound wave generation and propagation.','{}','{}','{"frequency": 2, "text_unit_ids": ["7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da", "7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('5d913418-d328-4629-8321-65c56e959c15'::uuid,'VISCOUS COMPRESSIBLE GAS MODEL','MODEL','{}','This comprehensive model most accurately describes aerodynamic processes but introduces complex mathematical problems due to compressibility and viscosity considerations.','{}','{}','{"frequency": 2, "text_unit_ids": ["7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da", "7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('593724cd-3f23-424f-a6ed-b0b0a8a34ffc'::uuid,'FLOW PROCESS','SYSTEM','{}','Refers to the movement of fluid or gas and its characteristics, which are described by various models used in aerodynamics.','{}','{}','{"frequency": 2, "text_unit_ids": ["7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da", "7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('4cbb1c53-f235-4fe0-8cbd-a955c37f9cff'::uuid,'FLOW CLASSIFICATION','SYSTEM','{}','The classification of flows in aerodynamics, which is essential based on criteria such as Mach number and flow structure like laminar or turbulent characteristics.','{}','{}','{"frequency": 2, "text_unit_ids": ["7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da", "7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('1eb1dc25-b36f-46a1-88f8-2b0c826434a9'::uuid,'WING SURFACE','PART','{}','Surface component of the vehicle, typically a wing or airfoil where boundary layer characteristics are critical for performance','{}','{}','{"frequency": 1, "text_unit_ids": ["c40bda9f92f9509b2f4cf8f58acd428d233827b65e6b3795bf3c84c6b0cd07198d4f407233cb1f635f5c7236c0e03dafba19429b95483d21113d9767a2577aa5"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('01be0eab-106f-4bae-8fb5-05fed8804b67'::uuid,'TRANSONIC FLOW','SYSTEM','{}','A flow where some parts of the region have a subsonic Mach number lower than unity while other regions move faster than the speed of sound, indicating transition from subsonic to supersonic flow patterns.','{}','{}','{"frequency": 2, "text_unit_ids": ["7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da", "7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('bc9a4ca4-27b7-42b2-b006-8862e6091b0c'::uuid,'HYPERSONIC FLOW','SYSTEM','{}','Flows with Mach numbers significantly greater than unity (M > 5), characterized by complex aerodynamic behaviors due to high-speed gas dynamics effects.','{}','{}','{"frequency": 2, "text_unit_ids": ["7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da", "7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('e115f08e-cd84-4188-9982-30f78cc90198'::uuid,'SUPSONIC FLOW','SYSTEM','{}','A flow where the speed of the fluid or gas exceeds the local speed of sound throughout the entire region, indicating supersonic conditions.','{}','{}','{"frequency": 2, "text_unit_ids": ["7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da", "7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('900f4a0d-a965-48d5-a42d-245fd8e9ed67'::uuid,'ATTACHED FLOW','SYSTEM','{}','A type of laminar or transitional flow that forms on a solid surface in which gas does not separate from it and maintains smooth interaction along its boundary layer.','{}','{}','{"frequency": 2, "text_unit_ids": ["7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da", "7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('85d58bcb-40ac-41f7-b42e-292555b95d9e'::uuid,'SEPARATED FLOW','SYSTEM','{}','This occurs when the fluid separates from the surface, typically leading to turbulent regions with areas of recirculation behind objects like airfoils or wings.','{}','{}','{"frequency": 2, "text_unit_ids": ["7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da", "7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('56df35db-5c1e-4990-93fc-17b6e95c9ece'::uuid,'VISCOUS FLOW','MODEL','{}','Characterized by significant effects due to viscosity where friction between adjacent fluid layers resists shear and deformation.','{}','{}','{"frequency": 2, "text_unit_ids": ["7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da", "7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('e01f8ac1-b3ae-4656-9893-ef33b90bd758'::uuid,'INVISCID FLOW','SYSTEM','{}','A type of flow classification where the viscosity is negligible, simplifying analysis without considering internal frictional forces and focusing on overall streamline patterns.','{}','{}','{"frequency": 2, "text_unit_ids": ["7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da", "7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('d106d137-8926-4836-a162-c11f0d2630f1'::uuid,'EXTERNAL AERODYNAMICS','SYSTEM','{}','Involves flows over bodies that are much smaller in size compared to the dimensions of their surroundings, such as airplanes or aircraft moving through open space with minimal flow obstruction by channels.','{}','{}','{"frequency": 2, "text_unit_ids": ["7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da", "7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('dcfe95e0-5191-48c1-b883-9cc36e2b378a'::uuid,'INTERNAL AERODYNAMICS','SYSTEM','{}','Concerns flows within confined spaces like pipelines, jet engines, and gas turbines where the channel geometry significantly affects fluid behavior compared to external environments.','{}','{}','{"frequency": 2, "text_unit_ids": ["7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da", "7bab4e0b9bf564415098605230a0b8c9801762a344b1305f6767edd6b3d9c9e7d69c62df8d4aa634a80ec96f8417c044943b33570af019c7be0aee94a675a2da"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('7f176e4c-ff8e-4f4f-993c-22b84e6e0159'::uuid,'FLOW VELOCITY','MATERIAL','{}','Flow velocity refers to the speed at which a fluid or gas moves, which is a critical attribute for understanding the dynamics of fluid and gas flows.','{}','{}','{"frequency": 1, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('02f2ab0f-d784-4a98-bb4d-dded7f79fa74'::uuid,'CONTINUITY EQUATION','MODEL','{}','The CONTINUITY EQUATION is a fundamental mathematical formulation that expresses the principle of conservation of mass in fluid and gas flows. This equation specifically describes how mass is conserved within a streamtube, which is an imaginary tubular control volume through which fluids or gases flow continuously without separation. The general form of this equation can be represented as ρ₁ V₁ F₁ = ρ₂ V₂ F₂, where:
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('13a07eff-b2c0-44cb-b89e-e1df7cd3dd2e'::uuid,'MOMENTUM CONSERVATION LAW','SYSTEM','{}','Ensures that the total momentum in an isolated system remains constant unless acted upon by external forces, key to understanding fluid motion','{}','{}','{"frequency": 1, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('c32a92bf-2a7a-4e1a-a0af-4d651d5f6753'::uuid,'ANGULAR MOMENTUM CONSERVATION LAW','SYSTEM','{}','Conserves angular momentum within a rotating system or any object under the influence of torques, relevant for certain fluid dynamics scenarios','{}','{}','{"frequency": 1, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('fafecae5-6666-44a6-844d-d2bac616510c'::uuid,'CONTINUITY (MASS CONSERVATION) EQUATION','MODEL','{}','Specific form of the mass conservation law in Eulerian variables, universal and applicable to various media including water, air, metal','{}','{}','{"frequency": 1, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('991c60e1-240d-4040-8710-bc7a445307f3'::uuid,'EULERIAN VARIABLES','SYSTEM','{}','Variables used to describe properties at a fixed spatial point over time, essential for writing equations like the continuity equation','{}','{}','{"frequency": 1, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('0c3e3e41-5fce-4839-b5d4-f5d3ea540635'::uuid,'VELOCITY COMPONENTS (U, V, W)','COMPONENT','{}','Cartesian components of velocity vectors in three-dimensional space crucial for understanding fluid and gas motion','{}','{}','{"frequency": 1, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('41f7d83a-c850-4254-99a7-dae57f78bde5'::uuid,'DENSITY (Ρ)','MATERIAL','{}','Property denoting the mass per unit volume of a substance critical for the continuity equation and overall flow dynamics','{}','{}','{"frequency": 1, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('32adafdd-7125-4010-a665-b7178210a52a'::uuid,'MODERN FLOW VISUALISATION METHODS','SYSTEM','{}','Allows obtaining color images of phenomena in fluid and gas flows, enhancing visualization and analysis','{}','{}','{"frequency": 1, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('a00fa4ae-791b-4473-adfd-e1d2affbf92c'::uuid,'VISUALISED FLOW IMAGES','COMPONENT','{}','Available online, used to study flow properties and visual characteristics of fluid and gas dynamics','{}','{}','{"frequency": 1, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('a3e76017-d273-402f-8764-94564e81d63d'::uuid,'BOOK [12]','MATERIAL','{}','Contains descriptions of various flow patterns, contributing to the understanding of different types of structures formed around bodies','{}','{}','{"frequency": 1, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('1a0c6fb6-bc12-4de6-8b76-dca48cba2bff'::uuid,'FLOW PROPERTIES','COMPONENT','{}','"FLOW PROPERTIES" encompasses a set of critical attributes that are extensively studied within the field of aerodynamics. These properties play a pivotal role in understanding fluid and gas flows around different bodies. The key characteristics included in this category are pressure, temperature, density, and velocity. These parameters are essential for analyzing how fluids or gases interact with various objects, providing fundamental insights into their behavior under different conditions. By comprehensively examining these flow properties, researchers and engineers can better design aircraft, predict weather patterns, optimize industrial processes, and enhance the performance of vehicles and other systems that operate in fluid environments.','{}','{}','{"frequency": 3, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53", "f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7", "f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('8aca3ce4-7791-464c-b2bd-10a91deaef9a'::uuid,'FORCE OF INTERACTION','COMPONENT','{}','An aspect studied in aerodynamics, representing the interaction between flows and various bodies<|','{}','{}','{"frequency": 1, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('34c79373-a85b-4e53-9a33-703328f92b07'::uuid,'FLUID DYNAMICS','SYSTEM','{}','Branch of physics studied to understand the flow behavior of liquids and gases, encompassed within the broader field of mathematical modeling and conservation laws<|','{}','{}','{"frequency": 1, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('3d41a497-4bea-41f2-8af0-c6891b3ca7b5'::uuid,'AERODYNAMIC RESEARCH TOOLS','SYSTEM','{}','Methods used to acquire knowledge about flow properties and forces of interactions between flows and bodies, including modern visualization techniques<|','{}','{}','{"frequency": 1, "text_unit_ids": ["3f5f80cfe6f81afa1ad15ce51cf5ac93a304c821fd4dbd8b07af07ffa13187309e13e76867919c83410e3fcf45602d1325632639560245e5c33c5c327415cc53"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('7ebb105e-b786-4230-9a6c-963728635993'::uuid,'VELOCITY COMPONENTS','COMPONENT','{}','These are the three parameters that describe the motion of a fluid in an incompressible medium.','{}','{}','{"frequency": 1, "text_unit_ids": ["f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('ab4000cc-b83f-47a4-9e82-5ec0fd1e4e06'::uuid,'COMPUTER TECHNOLOGY','SYSTEM','{}','Provided new methods for obtaining quantitative estimates of flow characteristics, specifically through computational fluid dynamics.','{}','{}','{"frequency": 2, "text_unit_ids": ["f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7", "f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('0d550833-30fb-465b-83fe-e8c7ce27f4fb'::uuid,'NEWTON''S ESTIMATE OF FORCE','MODEL','{}','Historically significant first result in theoretical aerodynamics, providing an early understanding of the relationship between gas properties and drag forces.','{}','{}','{"frequency": 2, "text_unit_ids": ["f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7", "f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('bf580957-eae2-48d9-b608-36449d3a368d'::uuid,'INCOMPRESSIBLE IDEAL GAS','MODEL','{}','A simplified scenario without shear stresses, viscosity, or thermal conductivity used to understand basic principles of constructing mathematical models. It''s characterized by a stress vector perpendicular to any surface inside the gas and constant magnitude at a given point independent of plane orientation.','{}','{}','{"frequency": 2, "text_unit_ids": ["f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7", "f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('870f58e5-cc32-40d1-adff-3c3ff941bbb5'::uuid,'CARTESIAN COORDINATES','SYSTEM','{}','Coordinate system used for writing key equations in aerodynamics, including the continuity equation and Newton''s second law.','{}','{}','{"frequency": 2, "text_unit_ids": ["f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7", "f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('8610f877-ad0c-439d-aeae-6060747b6ca5'::uuid,'SHEAR STRESSES','COMPONENT','{}','In real fluids, these are significant but are ignored in the ideal gas model due to its simplification.','{}','{}','{"frequency": 2, "text_unit_ids": ["f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7", "f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('722bb9cc-c536-4e89-8d5a-09b03db8d1a5'::uuid,'DRAG FORCE','MODEL','{}','A primary property of fluid interactions where the mathematical models focus on general estimation laws between drag and flow velocity.','{}','{}','{"frequency": 2, "text_unit_ids": ["f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7", "f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('51f46b76-2bc7-49a1-8f11-7543ad5b6532'::uuid,'FORCE OF INTERACTION BETWEEN FLUID AND BODY','MODEL','{}','Describes how a fluid affects different bodies in motion within it or those bodies affect the fluid flow directly.','{}','{}','{"frequency": 2, "text_unit_ids": ["f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7", "f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('a932d96b-63da-4ae3-bc45-ed10f065d41e'::uuid,'MATHEMATICAL MODELS','MODEL','{}','Used to draw general conclusions about flow behavior based on certain assumptions about gas properties and conservation laws.','{}','{}','{"frequency": 1, "text_unit_ids": ["f20c8fea18ca81aea3e162ebb165623222ecb4d9dee868b802418aa04d280ec7571ef024191fee26981dc11fddc231e846a5ecff704645d44d2493b5ebd1eec7"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('a375eada-dda7-4703-bfd8-4dd32c96e6df'::uuid,'LIQUID','MECHANISM','{}','Although "liquid" is mentioned, it does not have a detailed description that fits the context of being an entity such as a mechanism or system within this text.','{}','{}','{"frequency": 1, "text_unit_ids": ["f6c3b3b269e7af478487328e5313e02a8c137117cbe55dacc0858717330e7e05c2ae5032253aaf5d9ddafd9ecef1939f5b0aaf00ae9bd44a279c22bd1b4c6c20"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('4a09e094-d581-46dc-ac6a-62c7d8f60d20'::uuid,'PARTICLE','SYSTEM','{}','An elementary volume of gas treated in the form of a parallelepiped with sides dx, dy, dz used to derive Newton''s second law for elementary volumes of fluid','{}','{}','{"frequency": 1, "text_unit_ids": ["f6c3b3b269e7af478487328e5313e02a8c137117cbe55dacc0858717330e7e05c2ae5032253aaf5d9ddafd9ecef1939f5b0aaf00ae9bd44a279c22bd1b4c6c20"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('c39277f5-e36b-4010-8361-93ac7fae8d25'::uuid,'VELOCITY_VECTOR','DEVICE','{}','The vector representation of velocity V = V(x(t), y(t), z(t), t) which describes the time dependence of particle coordinates.','{}','{}','{"frequency": 1, "text_unit_ids": ["f6c3b3b269e7af478487328e5313e02a8c137117cbe55dacc0858717330e7e05c2ae5032253aaf5d9ddafd9ecef1939f5b0aaf00ae9bd44a279c22bd1b4c6c20"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('90034fcf-c647-433f-9ead-920418cb99f1'::uuid,'PART','MECHANISM','{}','Specific part within a system to describe fluid motion, e.g., "U", "V", and "W" as partial derivatives with respect to spatial dimensions in the Euler equations','{}','{}','{"frequency": 1, "text_unit_ids": ["f6c3b3b269e7af478487328e5313e02a8c137117cbe55dacc0858717330e7e05c2ae5032253aaf5d9ddafd9ecef1939f5b0aaf00ae9bd44a279c22bd1b4c6c20"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('47bf8501-470d-4fae-a599-2deffb804331'::uuid,'BODY_FORCE','FORCE','{}','Term F representing force acting on an elementary volume of gas or liquid, crucial for motion dynamics.','{}','{}','{"frequency": 1, "text_unit_ids": ["f6c3b3b269e7af478487328e5313e02a8c137117cbe55dacc0858717330e7e05c2ae5032253aaf5d9ddafd9ecef1939f5b0aaf00ae9bd44a279c22bd1b4c6c20"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('7414de6c-e81d-44dd-ac97-73c85be38d1d'::uuid,'PARTIAL_PRESSURE_GRADIENT','MECHANISM','{}','Gradient operator ∇p applied to scalar pressure *p* across the fluid element. Describes how pressure changes spatially affecting the fluid motion.','{}','{}','{"frequency": 1, "text_unit_ids": ["f6c3b3b269e7af478487328e5313e02a8c137117cbe55dacc0858717330e7e05c2ae5032253aaf5d9ddafd9ecef1939f5b0aaf00ae9bd44a279c22bd1b4c6c20"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('bf590af7-1766-437e-943d-f98756c8186f'::uuid,'EULER_EQUATIONS','MODEL','{}','Set of three partial differential equations that describe the conservation of mass, momentum in Newtonian fluids for each spatiotemporal dimension','{}','{}','{"frequency": 1, "text_unit_ids": ["f6c3b3b269e7af478487328e5313e02a8c137117cbe55dacc0858717330e7e05c2ae5032253aaf5d9ddafd9ecef1939f5b0aaf00ae9bd44a279c22bd1b4c6c20"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('1ac5667c-42ba-4c24-b081-05c33f2e3dd8'::uuid,'EQUATION_OF_STATE','MODEL','{}','The additional equation that closes the system of Euler equations. Described as determining physical properties like density or pressure changes in the fluid medium during its motion.','{}','{}','{"frequency": 1, "text_unit_ids": ["f6c3b3b269e7af478487328e5313e02a8c137117cbe55dacc0858717330e7e05c2ae5032253aaf5d9ddafd9ecef1939f5b0aaf00ae9bd44a279c22bd1b4c6c20"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('3a1d582e-4b18-41d8-9829-1d38f38594f7'::uuid,'TIME_DEPENDENCE','SYSTEM','{}','The time-varying nature of particle coordinates in the velocity vector V, indicating how position changes over time.','{}','{}','{"frequency": 1, "text_unit_ids": ["f6c3b3b269e7af478487328e5313e02a8c137117cbe55dacc0858717330e7e05c2ae5032253aaf5d9ddafd9ecef1939f5b0aaf00ae9bd44a279c22bd1b4c6c20"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('37a77fe1-df9b-4719-9018-0cf5f6c652be'::uuid,'INCOMPRESSIBLE_FLUID','MODEL','{}','Describes a simplified case where density remains constant during motion, used for understanding simple gas phenomena mathematically.','{}','{}','{"frequency": 1, "text_unit_ids": ["f6c3b3b269e7af478487328e5313e02a8c137117cbe55dacc0858717330e7e05c2ae5032253aaf5d9ddafd9ecef1939f5b0aaf00ae9bd44a279c22bd1b4c6c20"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('45a92501-5d66-4532-8759-ad92cbb23f5d'::uuid,'MATHEMATICAL MODEL','MODEL','{}','The model for an ideal incompressible fluid is essential for obtaining quantitative flow characteristics under appropriate initial and boundary conditions, crucial for solving theoretical and applied aerodynamic problems','{}','{}','{"frequency": 1, "text_unit_ids": ["83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('30b0268f-05fd-4e65-a355-9537818e1fab'::uuid,'NAVIER–STOKES EQUATIONS','MODEL','{}','The NAVIER–STOKES equations are mathematical tools crucial for analyzing fluid dynamics where the effects of viscosity cannot be neglected. These equations provide a more intricate and accurate description compared to other methods such as Lagrange formulas, especially in scenarios involving incompressible fluids or gases. They are particularly useful for describing the behavior of low-velocity flows, taking into account the viscosity effects that significantly influence the fluid''s motion. The ability to model these detailed dynamics makes the NAVIER–STOKES equations indispensable in fields ranging from aerospace engineering to meteorology and beyond.','{}','{}','{"frequency": 4, "text_unit_ids": ["83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70", "83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70", "c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac", "c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('6c51b512-4c86-4d60-a2e5-284a24729052'::uuid,'HELMHOLTZ''S GENERAL THEOREM','MODEL','{}','Provides a basis for distinguishing characteristic flow types by representing any vector field as the sum of an irrotational and a solenoidal field','{}','{}','{"frequency": 2, "text_unit_ids": ["83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70", "83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('0712a078-1bf9-4255-b5b0-92b179deb39e'::uuid,'ENERGY CONSERVATION LAW (BENOUILLI''S LAW)','MODEL','{}','Important relation for analyzing such flows, written as hρg + p + ρ|V|^2/2 = const, where the constant differs for different streamlines and can be a single value in specific flow conditions','{}','{}','{"frequency": 2, "text_unit_ids": ["83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70", "83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('14267483-4a7e-47ff-ba36-615ae526bdc2'::uuid,'CAUCHY–LAGRANGE INTEGRAL','MODEL','{}','Applicable to unsteady potential motion of an ideal barotropic fluid in a field of potential body forces','{}','{}','{"frequency": 2, "text_unit_ids": ["83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70", "83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('bc1433a7-0b2a-4b7b-ad8f-efdbc865f4d4'::uuid,'GENERALIZED CAUCHY–LAGRANGE FORMULA','MODEL','{}','Applied for unsteady vortex motion of a viscous incompressible fluid in a field of potential body forces','{}','{}','{"frequency": 2, "text_unit_ids": ["83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70", "83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('59c89e81-4a50-4b69-8761-a08f48162834'::uuid,'VECTOR FIELD V','MODEL','{}','The vector field V = ∇φ + rot A is used to represent velocity fields in terms of potential, solenoidal, or vortical properties','{}','{}','{"frequency": 1, "text_unit_ids": ["83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('a6453d2e-2bd9-4a8d-8f7c-8882f8449d72'::uuid,'IDEAL INCOMPRESSIBLE FLUID','MODEL','{}','Refers to fluids where density is constant and they do not undergo compression under pressure, central to the mathematical model''s assumptions','{}','{}','{"frequency": 1, "text_unit_ids": ["83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('0f6e7df5-0402-47fb-b245-612cd14b34a3'::uuid,'BENOUILLI''S LAW','MODEL','{}','Bernoulli''s law: hρg + p + ρ|V|^2/2 = const, crucial for analysis of ideal barotropic fluid flows under specific conditions','{}','{}','{"frequency": 1, "text_unit_ids": ["83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('34eba7d1-4798-4f64-9b43-eb65cc2567b8'::uuid,'IDEAL BAROTROPIC FLUID','MODEL','{}','A fluid whose density is independent of pressure, often used as an assumption in deriving models due to its simplifying nature','{}','{}','{"frequency": 1, "text_unit_ids": ["83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('6bfa9e04-5b9b-478a-99ff-b4da0bbf46ef'::uuid,'RESULTANT_FORCE_VECTOR','MODEL','{}','The resultant vector resulting from force decomposition, decomposing into forces N, Qx, Qy','{}','{}','{"frequency": 1, "text_unit_ids": ["aea6c651ec0fecfc47e79f37f7a830a1f5a1d8931712fbbf248dce3638450697754592ecf22476fe4edc6597c8adadaaa0a8594141780b5e85c35377ad4d489c"]}','2026-07-17 16:45:38.667334','2026-07-17 16:45:38.667334','sopromat_v1'),
	 ('93cffffe-469c-4228-b5b6-758001c9cdeb'::uuid,'TRAJECTORIES OR VORTEX LINES','MODEL','{}','Streamlines or vortex lines, where the constant in Benoulli''s equation can be different on each streamline but is the same for helical flows (trajectories or vortex lines coincide)','{}','{}','{"frequency": 1, "text_unit_ids": ["83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('50701158-315d-4689-883c-b76fdf306919'::uuid,'CAUSALITY','MODEL','{}','Implied in the use of Bernoulli''s and Cauchy-Lagrange formulas where physical constraints like potential body forces govern the motion','{}','{}','{"frequency": 1, "text_unit_ids": ["83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('64a3ac70-c918-460b-b9f1-986a126fc7b4'::uuid,'GRAVITATIONAL FORCES','MODEL','{}','Potential body forces included in the analysis of ideal barotropic fluids under steady motion conditions where the potential forces are limited to gravitational ones','{}','{}','{"frequency": 1, "text_unit_ids": ["83b687d2a25f7bd062db6c7a8395f195ec5f35fb59d004dba2633089b9ca6d93c92d704d07504499c4a535bf564205b86b4d80913963c786d24fb4656ced0f70"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('da3c113a-1d86-424b-99b4-aac5e1d967de'::uuid,'LAGRANGE FORMULA','MODEL','{}','The model that represents some of the simplest mathematical relations in aerodynamics','{}','{}','{"frequency": 1, "text_unit_ids": ["c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('f939d507-fd1e-4962-acc7-f60f504afb4c'::uuid,'WIND ENGINES (WINDMILLS)','DEVICE','{}','Devices used historically for converting wind energy into mechanical work, first found in Persia around the 7th century BC. Horizontal-axis wind turbines are a modern equivalent that have been developed based on this historical design.','{}','{}','{"frequency": 2, "text_unit_ids": ["c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac", "c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('d1b72b79-e2cd-4127-8eaf-cb4c8083a806'::uuid,'TRYPILLIAN CERAMICS','MATERIAL','{}','Earliest indications of sailing boats found on these artifacts from the 6th-5th millennium BC in Ukraine.','{}','{}','{"frequency": 2, "text_unit_ids": ["c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac", "c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('0c9e4815-ac5b-464d-acf0-fb9b924fb1ae'::uuid,'WIND TUNNELS','DEVICE','{}','Modern engineering facilities used for generating controlled flow conditions to study aerodynamics. They often involve sophisticated design and data acquisition systems.','{}','{}','{"frequency": 2, "text_unit_ids": ["c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac", "c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('8303032f-1acb-4daf-876f-e94d7397e5e9'::uuid,'KHARKIV NATIONAL AVIATION UNIVERSITY EXPERIMENTAL FACILITIES','SYSTEM','{}','Research institutions in Ukraine that have developed wind tunnel technologies as a fundamental component of their experimental aerodynamics programs.','{}','{}','{"frequency": 3, "text_unit_ids": ["c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac", "c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac", "c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('09ae444c-1cfa-49df-a995-2d5b97c09557'::uuid,'COMPUTERISED DATA ACQUISITION METHODS','SYSTEM','{}','Technologies used for precisely registering the parameters of air flows in experiments, enhancing the accuracy and reliability of data collected.','{}','{}','{"frequency": 2, "text_unit_ids": ["c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac", "c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('f77a4257-e1c2-4f18-ae08-28e0614a7ea0'::uuid,'THERMAL FACTORS','COMPONENT','{}','The entity "THERMAL FACTORS" encompasses critical aspects of fluid dynamics that play significant roles in the interaction between flowing fluids and solid bodies. These factors are especially vital in transonic and specialized aerodynamic studies, where temperature changes during flow interactions can significantly influence the performance and design optimization of aircraft and other aerospace technologies. Furthermore, thermal factors are also important in comprehensive flow-body interaction studies, emphasizing a thorough understanding of both mechanical and thermodynamic behaviors. This comprehensive analysis is crucial for ensuring reliable operation under various conditions and for advancing the field through more sophisticated modeling and testing methodologies.','{}','{}','{"frequency": 2, "text_unit_ids": ["c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac", "c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('ba90108f-612f-4371-92a7-391b6240dbfe'::uuid,'ACOUSTIC FACTORS','COMPONENT','{}','Sound pressure fluctuations resulting from fluid dynamics, significant in comprehensive flow-body interaction studies requiring a full understanding of mechanical and thermodynamic behaviors.','{}','{}','{"frequency": 2, "text_unit_ids": ["c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac", "c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('2ffba532-d100-4eac-bd20-d8810c963466'::uuid,'KHARKIV NATIONAL AVIATION UNIVERSITY','ORGANIZATION','{}','KHARKIV NATIONAL AVIATION UNIVERSITY is a research institution based in Ukraine, dedicated to advancing knowledge and innovation in aerodynamics through extensive experimental facilities. This higher educational establishment plays a crucial role in the development and contribution to the field of experimental aerodynamics, leveraging its resources to conduct cutting-edge studies and research.','{}','{}','{"frequency": 2, "text_unit_ids": ["c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac", "c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('068a82ce-21df-449c-9a76-4e7ccb09780b'::uuid,'AERODYNAMICS OF WINDMILLS AND SAILS','SUBJECT','{}','Branch of aerodynamics dealing with historical systems like windmills and the use of sailboats, relevant today due to its practical applications and theoretical insights.','{}','{}','{"frequency": 1, "text_unit_ids": ["c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('a83b5136-1a8f-4385-996b-f9bb2bc25fd7'::uuid,'KYIV NATIONAL AVIATION UNIVERSITY','ORGANIZATION','{}','Another institution involved in advanced aerodynamic studies.','{}','{}','{"frequency": 1, "text_unit_ids": ["c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('4fe2bb4c-1901-44d9-bb18-7776976a7792'::uuid,'TRYPILLIAN CULTURE','ORGANIZATION','{}','The historical context represented by artifacts like Trypillian ceramics that show evidence of early understanding and utilization of fluid dynamics.','{}','{}','{"frequency": 1, "text_unit_ids": ["c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('2048e952-1f2e-4002-bc62-4f9af318a493'::uuid,'SAILING BOATS','DEVICE','{}','Historical watercraft that demonstrate practical applications of aerodynamic principles in a marine context.','{}','{}','{"frequency": 1, "text_unit_ids": ["c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('8ee79e35-cd46-4264-b76d-c98b5a83057f'::uuid,'KYIV NATIONAL AVIATION UNIVERSITY EXPERIMENTAL FACILITIES','SYSTEM','{}','Research institutions in Ukraine that have developed wind tunnel technologies as a fundamental component of their experimental aerodynamics programs.','{}','{}','{"frequency": 1, "text_unit_ids": ["c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1');
