	 ('33f8c634-40af-4878-adda-307628f4aa4b'::uuid,'TRYPILLIAN CERAMICS (WITH INDICATIONS OF SAILING)','MATERIAL','{}','Artifacts indicating the existence of early watercraft and the understanding of fluid dynamics by ancient civilizations.','{}','{}','{"frequency": 1, "text_unit_ids": ["c39119a42bf54d5f3a6c528527afa0659b9429b38912e2720b5ab4f6ac9e9979a2f0357e21700957de3eeda5bfae120fd0986c0cbb00355505e8e2ddc1e849ac"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('b7f898fa-22a1-4803-b3b0-efe0df2dbd03'::uuid,'FLOW','SYSTEM','{}','Flow refers to the movement or state of fluid with specific characteristics, crucial for studies in aerodynamics','{}','{}','{"frequency": 1, "text_unit_ids": ["4d79766d7c102666e5cbdcf972aa2ca84c504f89f7c9e735d66b3b9901f21bb74741741169d93c5909e55918a8ed41113434da52d7537b0cef2a603e49c9dc6e"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
