	 ('2da22f4e-399d-4e0a-9b67-f74600b714b4'::uuid,'ANTONOV AVIATION SCIENTIFIC-TECH COMPLEX WIND TUNNEL FACILITY','COMPONENT','{}','Facility within Antonov complex utilized for conducting wind tunnel tests and experiments','{}','{}','{"frequency": 1, "text_unit_ids": ["4d79766d7c102666e5cbdcf972aa2ca84c504f89f7c9e735d66b3b9901f21bb74741741169d93c5909e55918a8ed41113434da52d7537b0cef2a603e49c9dc6e"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('36ef02ee-2314-43dd-a19c-0c27207e8ca2'::uuid,'MODEL EXPERIMENTS','SYSTEM','{}','Experiments conducted on scaled-down models to represent real objects in controlled settings, used to simulate full-scale behavior','{}','{}','{"frequency": 3, "text_unit_ids": ["4d79766d7c102666e5cbdcf972aa2ca84c504f89f7c9e735d66b3b9901f21bb74741741169d93c5909e55918a8ed41113434da52d7537b0cef2a603e49c9dc6e", "4d79766d7c102666e5cbdcf972aa2ca84c504f89f7c9e735d66b3b9901f21bb74741741169d93c5909e55918a8ed41113434da52d7537b0cef2a603e49c9dc6e", "4d79766d7c102666e5cbdcf972aa2ca84c504f89f7c9e735d66b3b9901f21bb74741741169d93c5909e55918a8ed41113434da52d7537b0cef2a603e49c9dc6e"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('0686c533-5c0d-42cc-97c7-fa3ce2b3b5d2'::uuid,'SCALED-DOWN MODELS','MODEL','{}','Models used in model experiments to represent and test real objects under controlled conditions','{}','{}','{"frequency": 2, "text_unit_ids": ["4d79766d7c102666e5cbdcf972aa2ca84c504f89f7c9e735d66b3b9901f21bb74741741169d93c5909e55918a8ed41113434da52d7537b0cef2a603e49c9dc6e", "4d79766d7c102666e5cbdcf972aa2ca84c504f89f7c9e735d66b3b9901f21bb74741741169d93c5909e55918a8ed41113434da52d7537b0cef2a603e49c9dc6e"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('d9462338-f641-4f5b-aede-1a78987c9d49'::uuid,'NEWTON''S IMPACT THEORY OF AERODINAMIC DRAG','MECHANISM','{}','This theory proposed in the 17th century dominated science until the 20th century and served as a foundation for modern rarefied gas aerodynamics','{}','{}','{"frequency": 2, "text_unit_ids": ["179038fe517a80b11687045f8990ed7f43f61ddac3ac215566be7a632476947416100235bd283fbe165b968ddf404e87c54967e59bf89b7b6d8260c5e4cb485f", "179038fe517a80b11687045f8990ed7f43f61ddac3ac215566be7a632476947416100235bd283fbe165b968ddf404e87c54967e59bf89b7b6d8260c5e4cb485f"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1');
INSERT INTO agi_evolution.knowledge_nodes (id,"name",node_type,properties,description,embedding,parameters,metadata,created_at,updated_at,theme_id) VALUES
	 ('7d1f2521-c376-4dd3-97d3-8f627ddc047a'::uuid,'INTERNAL FRICTION FORCES','COMPONENT','{}','(Conceptual term) The force between moving particles that affects the resistance to flow or shear in fluids; directly influences properties like viscosity.','{}','{}','{"frequency": 1, "text_unit_ids": ["bf26f5a3b6530571e586bf2e521de1606936d166f7ecd17a2fda3301e6731802baf11ea7e937d0ec458325da1ec98c55af85370ad15325184313eb3e41a92807"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('f6d4dd93-02b6-4f9f-a822-a5e272a51684'::uuid,'LEONHARD EULER','PART','{}','A mathematician who formulated general equations of fluid and gas motion, applied conservation laws to these motions, investigated resistance forces in fluids, and provided practical recommendations for shipbuilding and hydraulic machines','{}','{}','{"frequency": 2, "text_unit_ids": ["179038fe517a80b11687045f8990ed7f43f61ddac3ac215566be7a632476947416100235bd283fbe165b968ddf404e87c54967e59bf89b7b6d8260c5e4cb485f", "179038fe517a80b11687045f8990ed7f43f61ddac3ac215566be7a632476947416100235bd283fbe165b968ddf404e87c54967e59bf89b7b6d8260c5e4cb485f"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('9d7811a6-fb7c-44b0-8ab4-87aca47e9f36'::uuid,'DANIEL BERNOULLI','PART','{}','Bernoulli quantitatively related changes in kinetic energy with fluid pressure and explored various pressure force issues concerning bodies moving through a fluid.','{}','{}','{"frequency": 2, "text_unit_ids": ["179038fe517a80b11687045f8990ed7f43f61ddac3ac215566be7a632476947416100235bd283fbe165b968ddf404e87c54967e59bf89b7b6d8260c5e4cb485f", "179038fe517a80b11687045f8990ed7f43f61ddac3ac215566be7a632476947416100235bd283fbe165b968ddf404e87c54967e59bf89b7b6d8260c5e4cb485f"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('245096b9-a30f-404a-980f-0dfbac666258'::uuid,'N.E. ZHUKOVSKY','MODEL','{}','"Father of Russian aviation," Zhukovsky solved the problem of wing lift scientifically, developed the concept of vortexes, and established Russia''s first aerodynamic laboratories including TsAGI','{}','{}','{"frequency": 2, "text_unit_ids": ["179038fe517a80b11687045f8990ed7f43f61ddac3ac215566be7a632476947416100235bd283fbe165b968ddf404e87c54967e59bf89b7b6d8260c5e4cb485f", "179038fe517a80b11687045f8990ed7f43f61ddac3ac215566be7a632476947416100235bd283fbe165b968ddf404e87c54967e59bf89b7b6d8260c5e4cb485f"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('57d965f4-ffea-4326-9ded-b6700cd8947b'::uuid,'TSAGI (CENTRAL AEROHYDRODYNAMIC INSTITUTE)','SYSTEM','{}','Founded under N.E. Zhukovsky''s leadership in 1918 for research into aviation aerodynamics','{}','{}','{"frequency": 2, "text_unit_ids": ["179038fe517a80b11687045f8990ed7f43f61ddac3ac215566be7a632476947416100235bd283fbe165b968ddf404e87c54967e59bf89b7b6d8260c5e4cb485f", "179038fe517a80b11687045f8990ed7f43f61ddac3ac215566be7a632476947416100235bd283fbe165b968ddf404e87c54967e59bf89b7b6d8260c5e4cb485f"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('e4479427-d2b2-432d-80c3-a67e810a9838'::uuid,'FACILITIES AND LABORATORIES','SYSTEM','{}','Physical places where research and experiments related to aerodynamics can be conducted','{}','{}','{"frequency": 1, "text_unit_ids": ["179038fe517a80b11687045f8990ed7f43f61ddac3ac215566be7a632476947416100235bd283fbe165b968ddf404e87c54967e59bf89b7b6d8260c5e4cb485f"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('aa04b46e-58f8-4dfa-8c36-7299b54b020b'::uuid,'AEROHYDRODYNAMIC INSTITUTE (TSAGI)','ORGANIZATION','{}','Founded by N.E. Zhukovsky, it focuses on aerodynamics and flight dynamics research','{}','{}','{"frequency": 1, "text_unit_ids": ["7b1ef518d9d451766f80b634c2d13ecaf9e58d741b20333962ca9373f633c69f3846571db070b444adf5f537b399ec1a4c834561966469f5c4779d75e90d948d"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('eab55604-4ec2-4497-8b0b-18db1dbd2646'::uuid,'S.A. CHAPLYGIN','PERSON','{}','A student of N.E. Zhukovsky, contributed to wing drag theory, finite-span wing theory, and advanced aerodynamic methodologies','{}','{}','{"frequency": 2, "text_unit_ids": ["7b1ef518d9d451766f80b634c2d13ecaf9e58d741b20333962ca9373f633c69f3846571db070b444adf5f537b399ec1a4c834561966469f5c4779d75e90d948d", "7b1ef518d9d451766f80b634c2d13ecaf9e58d741b20333962ca9373f633c69f3846571db070b444adf5f537b399ec1a4c834561966469f5c4779d75e90d948d"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('6da8b8d7-9ddf-4e75-b9c0-864df398f449'::uuid,'FLIGHT DYNAMICS','SYSTEM','{}','The science concerning the motion of aircraft under given forces and moments, aiming at optimizing flight parameters such as range, endurance, and cost-efficiency','{}','{}','{"frequency": 2, "text_unit_ids": ["7b1ef518d9d451766f80b634c2d13ecaf9e58d741b20333962ca9373f633c69f3846571db070b444adf5f537b399ec1a4c834561966469f5c4779d75e90d948d", "7b1ef518d9d451766f80b634c2d13ecaf9e58d741b20333962ca9373f633c69f3846571db070b444adf5f537b399ec1a4c834561966469f5c4779d75e90d948d"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1'),
	 ('91819ba3-0e5a-4c8c-b902-347a7ac3175a'::uuid,'V.P. VETCHINKIN','PERSON','{}','A student of N.E. Zhukovsky, involved in further advancements in flight dynamics research','{}','{}','{"frequency": 2, "text_unit_ids": ["7b1ef518d9d451766f80b634c2d13ecaf9e58d741b20333962ca9373f633c69f3846571db070b444adf5f537b399ec1a4c834561966469f5c4779d75e90d948d", "7b1ef518d9d451766f80b634c2d13ecaf9e58d741b20333962ca9373f633c69f3846571db070b444adf5f537b399ec1a4c834561966469f5c4779d75e90d948d"]}','2026-07-17 16:18:55.489892','2026-07-17 16:18:55.489892','aerodynamics_v1');
