	 ('58fb65b4-a103-4ac6-b95c-c4983df2f942'::uuid,'R_C = 2Γ T_M / [ Λ (T_M − T) ]','MODEL','{}','Expression used to calculate the critical nucleus radius given the system state and phase transition material properties','{}','{}','{"frequency": 2, "text_unit_ids": ["d2032ae9dddd98b060a009a328f21502528c28113460e17f3cb1218b3536aefa712a61e6b8149a0979cd51a8b20c63a51e821e71df8f19c34d6f0a736a46dac6", "d2032ae9dddd98b060a009a328f21502528c28113460e17f3cb1218b3536aefa712a61e6b8149a0979cd51a8b20c63a51e821e71df8f19c34d6f0a736a46dac6"]}','2026-07-17 17:14:05.801343','2026-07-17 17:14:05.801343','solid_state_physics_v1'),
